-- Poems batch 38
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('d1ff3436-20ac-4495-8d40-e24c315e50f5','秋','李山甫','唐','唐诗','tang','','[]','傍雨衣風冷漸勻，更憑青女事精神。',64,'全唐诗/poet.tang.35000.json','["傍雨衣風冷漸勻，更憑青女事精神。", "來時將得幾多雁，到處愁他無限人。", "能被綠楊深懊惱，謾偎黃菊送殷勤。", "鄒家不用偏吹律，到底榮枯也自均。"]'),
('de1ebe27-4eee-420b-8816-03337f734d46','松','李山甫','唐','唐诗','tang','','[]','地聳蒼龍勢抱雲，天教青共衆材分。',64,'全唐诗/poet.tang.35000.json','["地聳蒼龍勢抱雲，天教青共衆材分。", "孤標百尺雲中見，長嘯一聲風裏聞。", "桃李傍他真是佞，藤蘿攀爾亦非羣。", "平生相愛應相識，誰道修篁勝此君。"]'),
('fecd579f-9528-48be-86f6-6cc4f6fa4672','讀漢史','李山甫','唐','唐诗','tang','','[]','四百年間反覆尋，漢家興替好沾襟。',64,'全唐诗/poet.tang.35000.json','["四百年間反覆尋，漢家興替好沾襟。", "每逢姦詐須挼手，真遇英雄始醒心。", "王莽弄來曾半破，曹公將去便平沈。", "當時虛受君恩者，謾向青編作鬼林。"]'),
('847539b6-7ea7-4aec-a7ff-7a32da3e8c6b','上元懷古二首 一','李山甫','唐','唐诗','tang','','[]','南朝天子愛風流，盡守江山不到頭。',64,'全唐诗/poet.tang.35000.json','["南朝天子愛風流，盡守江山不到頭。", "總是戰爭收拾得，却因歌舞破除休。", "堯行道德終無敵，秦把金湯可自由。", "試問繁華何處有，雨苔煙草古城秋。"]'),
('58070aff-c81d-4222-9ad2-8f8b6de6f0c9','上元懷古二首 二','李山甫','唐','唐诗','tang','','[]','爭帝圖王德盡衰，驟興馳霸亦何爲。',64,'全唐诗/poet.tang.35000.json','["爭帝圖王德盡衰，驟興馳霸亦何爲。", "君臣都是一塲笑，家國共成千載悲。", "排岸遠檣森似槊，落波殘照赫如旗。", "今朝城上難迴首，不見樓船索戰時。"]'),
('72f577cd-8974-4e77-810b-731a0c7d5e2c','隋堤柳','李山甫','唐','唐诗','tang','','[]','曾傍龍舟拂翠華，至今凝恨倚天涯。',64,'全唐诗/poet.tang.35000.json','["曾傍龍舟拂翠華，至今凝恨倚天涯。", "但經春色還秋色，不覺楊家是李家。", "背日古陰從北朽，逐波疎影向南斜。", "年年只有晴風便，遙爲雷塘送雪花。"]'),
('6acd98af-efc6-49c4-b9b7-c8a010db993a','蒲關西道中作','李山甫','唐','唐诗','tang','','["\u9ec4\u6cb3"]','國東王氣凝蒲關，樓臺帖出晴空間。',64,'全唐诗/poet.tang.35000.json','["國東王氣凝蒲關，樓臺帖出晴空間。", "紫煙橫捧大舜廟，黃河直打中條山。", "地鎖咽喉千古壯，風傳歌吹萬家閑。", "來來去去身依舊，未及潘年鬢已斑。"]'),
('37714d4c-e101-40aa-bb53-e611b9453851','道李秀才入軍','李山甫','唐','唐诗','tang','','[]','弱柳貞松一地栽，不因霜霰自難媒。',64,'全唐诗/poet.tang.35000.json','["弱柳貞松一地栽，不因霜霰自難媒。", "書生只是平時物，男子爭無亂世才。", "鐵馬已隨紅斾去，同人猶著白衣來。", "到頭功業須如此，莫爲初心首重回。"]'),
('6c1cdc78-f9ca-4e01-9c8e-3c1c074d277a','送蘄州裴員外','李山甫','唐','唐诗','tang','','[]','正作南宮第一人，蹔隨霓斾愴離羣。',64,'全唐诗/poet.tang.35000.json','["正作南宮第一人，蹔隨霓斾愴離羣。", "曉從闕下辭天子，春向江頭待使君。", "五馬尚迷青瑣路，雙魚猶惹翠蘭芬。", "明朝無路尋歸處，禁樹參差隔紫雲。"]'),
('6e56b3d4-d709-41ea-a8b6-a1d28fb296ba','代孔明哭先主','李山甫','唐','唐诗','tang','','[]','憶昔南陽顧草廬，便乘雷電捧乘輿。',64,'全唐诗/poet.tang.35000.json','["憶昔南陽顧草廬，便乘雷電捧乘輿。", "酌量諸夏須平取，期刻羣雄待遍鋤。", "南面未能成帝業，西陵那忍送宮車。", "九疑山下頻惆悵，曾許微臣水共魚。"]'),
('31d938bf-b466-4524-a1f2-9ce252ccc5cd','送職方王郎中吏部劉員外自太原鄭相公幕繼奉徵書歸省署','李山甫','唐','唐诗','tang','','[]','雙鳳銜書次第飛，玉皇催促列仙歸。',64,'全唐诗/poet.tang.35000.json','["雙鳳銜書次第飛，玉皇催促列仙歸。", "雲開日月臨青瑣，風卷煙霞上紫微。", "蓮影一時空儉府，蘭香同處撲堯衣。", "此生長掃朱門者，每向人間夢粉闈。"]'),
('e3da4e09-5915-4ef6-b234-4aab0e619ced','寒食二首 一','李山甫','唐','唐诗','tang','','[]','柳帶東風一向斜，春陰澹澹蔽人家。',64,'全唐诗/poet.tang.35000.json','["柳帶東風一向斜，春陰澹澹蔽人家。", "有時三點兩點雨，到處十枝五枝花。", "萬井樓臺疑繡畫，九原珠翠似煙霞。", "年年今日誰相問，獨臥長安泣歲華。"]'),
('bc04b5a5-f7ea-4040-8872-19f2d1912c11','寒食二首 二','李山甫','唐','唐诗','tang','','[]','風煙放蕩花披猖，鞦韆女兒飛短牆。',64,'全唐诗/poet.tang.35000.json','["風煙放蕩花披猖，鞦韆女兒飛短牆。", "繡袍馳馬拾遺翠，錦袖鬬雞喧廣塲。", "天地氣和融霽色，池臺日暖燒春光。", "自憐塵土無他事，空脫荷衣泥醉鄉。"]'),
('98c46436-ea84-44e4-8521-825a69e01082','又代孔明哭先主','李山甫','唐','唐诗','tang','','[]','鯨鬣翻騰四海波，始將天意用干戈。',64,'全唐诗/poet.tang.35000.json','["鯨鬣翻騰四海波，始將天意用干戈。", "盡驅神鬼隨鞭策，全罩英雄入網羅。", "提劒尚殘吳郡國，垂衣猶欠魏山河。", "鼎湖無路追仙駕，空使羣臣泣血多。"]'),
('e3ae9671-6997-446b-96dc-3fd66939e152','貧女','李山甫','唐','唐诗','tang','','[]','平生不識繡衣裳，閑把荆釵亦自傷。',64,'全唐诗/poet.tang.35000.json','["平生不識繡衣裳，閑把荆釵亦自傷。", "鏡裏只應諳素貌，人間多自信紅妝。", "當年未嫁還憂老，終日求媒即道狂。", "兩意定知無說處，暗垂珠淚濕蠶筐。"]'),
('481de596-c60e-45d1-99d8-b715f46d5bb7','寓懷','李山甫','唐','唐诗','tang','','[]','萬古交馳一片塵，思量名利孰如身。',64,'全唐诗/poet.tang.35000.json','["萬古交馳一片塵，思量名利孰如身。", "長疑好事皆虛事，却恐閑人是貴人。", "老逐少來終不放，辱隨榮後直須勻。", "勸君不用誇頭角，夢裏輸贏總未真。"]'),
('7835f216-6e86-43e8-b122-eac142063bad','蜀中寓懷','李山甫','唐','唐诗','tang','','[]','千里煙霞錦水頭，五丁開得也風流。',64,'全唐诗/poet.tang.35000.json','["千里煙霞錦水頭，五丁開得也風流。", "春裝寶闕重重樹，日照仙州萬萬樓。", "蛙似公孫雖不守，龍如諸葛亦須休。", "此中無限英雄鬼，應對江山各自羞。"]'),
('77f434c1-8374-45ef-a4b7-aa8ab210694b','下第臥疾盧員外召遊曲江','李山甫','唐','唐诗','tang','','[]','眼前何事不傷神，忍向江頭更弄春。',64,'全唐诗/poet.tang.35000.json','["眼前何事不傷神，忍向江頭更弄春。", "桂樹既能欺賤子，杏花爭肯採閑人。", "麻衣未掉渾身雪，皁蓋難遮滿面塵。", "珍重列星相借問，嵇康慵病也天真。"]'),
('838782aa-7340-4de5-bec0-46ecc67ecd34','司天臺','李山甫','唐','唐诗','tang','','[]','拂雲朱檻捧昭回，靜對銅渾水鏡開。',64,'全唐诗/poet.tang.35000.json','["拂雲朱檻捧昭回，靜對銅渾水鏡開。", "太史只知頻奏瑞，蒼生無計可防災。", "景公進德星曾退，漢帝推誠日爲迴。", "何事曠官全不語，好天良月鎖高臺。"]'),
('c07f4a1e-aea8-45dc-b043-ac4ac52910dd','落花','李山甫','唐','唐诗','tang','','[]','落拓東風不藉春，吹開吹謝兩何因。',64,'全唐诗/poet.tang.35000.json','["落拓東風不藉春，吹開吹謝兩何因。", "當時曾見笑筵主，今日自爲行路塵。", "顏色却還天上女，馨香留與世間人。", "明年寒食重相見，零淚無端又滿巾。"]'),
('e50c8203-889f-4852-883e-eceb9fd2486c','赴舉別所知','李山甫','唐','唐诗','tang','','[]','腰劒囊書出戶遲，壯心奇命兩相疑。',64,'全唐诗/poet.tang.35000.json','["腰劒囊書出戶遲，壯心奇命兩相疑。", "麻衣盡舉一雙手，桂樹只生三兩枝。", "黃祖不憐鸚鵡客，誌公偏賞麒麟兒。", "叔牙憂我應相痛，回首天涯寄所思。"]'),
('a116199a-f983-41cb-be0b-5ffaaf022cd8','賀邢州盧員外','李山甫','唐','唐诗','tang','','[]','紫泥飛詔下金鑾，列象分明世仰觀。',64,'全唐诗/poet.tang.35000.json','["紫泥飛詔下金鑾，列象分明世仰觀。", "北省諫書藏舊草，南宮郎署握新蘭。", "春歸鳳沼恩波暖，曉入鴛行瑞氣寒。", "偏是此生棲息者，滿衣零淚一時乾。"]'),
('1691957b-b9b7-442f-b76f-481dbf4b834e','方干隱居','李山甫','唐','唐诗','tang','','[]','咬咬嘎嘎水禽聲，露洗松陰滿院清。',64,'全唐诗/poet.tang.35000.json','["咬咬嘎嘎水禽聲，露洗松陰滿院清。", "溪畔印沙多鶴跡，檻前題竹有僧名。", "問人遠岫千重意，對客閑雲一片情。", "早晚塵埃得休去，且將書劒事先生。"]'),
('a1b663d1-ec19-4999-be77-f34181f81a1f','早春微雨','李山甫','唐','唐诗','tang','','[]','怪來鶯蝶似凝愁，不覺看花蹔濕頭。',64,'全唐诗/poet.tang.35000.json','["怪來鶯蝶似凝愁，不覺看花蹔濕頭。", "疎影未藏千里樹，遠陰微翳萬家樓。", "青羅舞袖紛紛轉，紅臉啼珠旋旋收。", "歲旱且須教濟物，爲霖何事愛風流。"]'),
('30b7423f-6a09-4427-9301-5cf14720119b','謁翰林劉學士不遇','李山甫','唐','唐诗','tang','','[]','夢繞清華宴地深，洞宮橫鎖曉沈沈。',64,'全唐诗/poet.tang.35000.json','["夢繞清華宴地深，洞宮橫鎖曉沈沈。", "鵬飛碧海終難見，鶴入青霄豈易尋。", "六尺羇魂迷定止，兩行愁血謝知音。", "平生只耻凌風翼，隨得鳴珂上禁林。"]'),
('3ed68218-7826-46a3-a432-418b00e4d15a','答劉書記見贈','李山甫','唐','唐诗','tang','','[]','吟近秋光思不窮，酷探騷雅愧無功。',64,'全唐诗/poet.tang.35000.json','["吟近秋光思不窮，酷探騷雅愧無功。", "茫然心苦千篇拙，瞑坐神凝萬象空。", "月上開襟當北戶，竹邊回首揖西風。", "知音頻有新詩贈，白雪紛紛落郢中。"]'),
('55069a74-8930-425c-8633-06cd5646da04','賀友人及第','李山甫','唐','唐诗','tang','','[]','得水蛟龍失水魚，此心相對兩何如。',64,'全唐诗/poet.tang.35000.json','["得水蛟龍失水魚，此心相對兩何如。", "敢辭今日須行卷，猶喜他年待薦書。", "松桂也應情未改，萍蓬爭奈迹還疎。", "春風不見尋花伴，遙向青雲泥子虛。"]'),
('dad3bf10-ae4d-4d73-b0d0-e859b928491a','雨後過華嶽廟','李山甫','唐','唐诗','tang','','["\u534e\u5c71"]','華山黑影霄崔嵬，金天□□門未開。',64,'全唐诗/poet.tang.35000.json','["華山黑影霄崔嵬，金天□□門未開。", "雨淋鬼火滅不滅，風送神香來不來。", "牆外素錢飄似雪，殿前陰栢吼如雷。", "知君暗宰人間事，休把蒼生夢裏裁。"]'),
('786e21cb-3d73-44a2-adf4-fb90bfa30160','贈彈琴李處士','李山甫','唐','唐诗','tang','','[]','情知此事少知音，自是先生枉用心。',64,'全唐诗/poet.tang.35000.json','["情知此事少知音，自是先生枉用心。", "世上幾時曾好古，人前何必更沾襟。", "致身不似笙竽巧，悅耳寧如鄭衛淫。", "三尺焦桐七條線，子期師曠兩沈沈。"]'),
('bc6627b1-698f-44d2-9145-8f57af01a649','劉員外寄移菊','李山甫','唐','唐诗','tang','','[]','秋來緣樹復緣牆，怕共平蕪一例荒。',64,'全唐诗/poet.tang.35000.json','["秋來緣樹復緣牆，怕共平蕪一例荒。", "顏色不能隨地變，風流唯解逐人香。", "煙含細葉交加碧，露拆寒英次第黃。", "深謝栽培與知賞，但慙終歲待重陽。"]'),
('e3f10660-9859-42bd-8c8e-b77308682c04','南山','李山甫','唐','唐诗','tang','','[]','鈍碧頑青幾萬秋，直無天地始應休。',64,'全唐诗/poet.tang.35000.json','["鈍碧頑青幾萬秋，直無天地始應休。", "莫嫌塵土佯遮面，能向樓臺強出頭。", "霽色陡添千尺翠，夕陽閑放一堆愁。", "假繞不是神仙骨，終抱琴書向此遊。"]'),
('8c6ef35c-9fb8-4aa9-81d3-ecca44e1e1b9','山中覽劉書記新詩','李山甫','唐','唐诗','tang','','[]','記室新詩相寄我，藹然清絕更無過。',64,'全唐诗/poet.tang.35000.json','["記室新詩相寄我，藹然清絕更無過。", "溪風滿袖吹騷雅，巖瀑無時滴薜蘿。", "雲外山高寒色重，雪中松苦夜聲多。", "靜酬嘉唱對幽景，蒼鶴羸棲古木柯。"]'),
('5b184397-9da2-44e7-be9b-b73373769e30','早秋山中作','李山甫','唐','唐诗','tang','','[]','榮枯無路入千峯，肥遯誰諧此志同。',64,'全唐诗/poet.tang.35000.json','["榮枯無路入千峯，肥遯誰諧此志同。", "司寇亦曾遭魯黜，步兵何事哭途窮。", "檜松瘦健滴秋露，戶牖虛明生晚風。", "山思更清人影絕，隴雲飛入草堂中。"]'),
('5ae50bb5-5d5a-4a3d-a5b3-f9f9b5321b75','賦得寒月寄齊已','李山甫','唐','唐诗','tang','','[]','松下清風吹我襟，上方鐘磬夜沉沉。',64,'全唐诗/poet.tang.35000.json','["松下清風吹我襟，上方鐘磬夜沉沉。", "已知廬嶽塵埃絕，更憶寒山雪月深。", "高謝萬緣消祖意，朗吟千首亦師心。", "豈知名出徧諸夏，石上棲禪竹影侵。"]'),
('2a81130f-f5d8-42cb-aa0e-aed0adec9531','曲江二首 一','李山甫','唐','唐诗','tang','','[]','南山低對紫雲樓，翠影紅陰瑞氣浮。',64,'全唐诗/poet.tang.35000.json','["南山低對紫雲樓，翠影紅陰瑞氣浮。", "一種是春長富貴，大都爲水也風流。", "爭攀柳帶千千手，間插花枝萬萬頭。", "獨向江邊最惆悵，滿衣塵土避王侯。"]'),
('08e40e7f-b8cd-4b1a-81e5-468896d7c830','曲江二首 二','李山甫','唐','唐诗','tang','','[]','江色沈天萬草齊，暖煙晴靄自相迷。',64,'全唐诗/poet.tang.35000.json','["江色沈天萬草齊，暖煙晴靄自相迷。", "蜂憐杏蕋細香落，鶯墜柳條濃翠低。", "千隊國娥輕似雪，一羣公子醉如泥。", "斜陽怪得長安動，陌上分飛萬馬蹄。"]'),
('c06f015b-4e31-403c-943c-741b9e61fd16','遷居清谿和劉書記見示','李山甫','唐','唐诗','tang','','[]','擔錫歸來竹繞谿，過津曾笑魯儒迷。',96,'全唐诗/poet.tang.35000.json','["擔錫歸來竹繞谿，過津曾笑魯儒迷。", "端居味道塵勞息，扣寂眠雲心境齊。", "還似村家無寵祿，時將隣叟話幽棲。", "山衣毳爛唯添野，石井源清不貯泥。", "祖意豈從年臘得，松枝肯爲雪霜低。", "晚天吟望秋光重，雨陣橫空蔽斷霓。"]'),
('d1cbca71-a4ac-432c-9a35-72ce1d9e781f','陰地關崇徽公主手跡','李山甫','唐','唐诗','tang','','[]','一拓纖痕更不收，翠微蒼蘚幾經秋。',64,'全唐诗/poet.tang.35000.json','["一拓纖痕更不收，翠微蒼蘚幾經秋。", "誰陳帝子和番策，我是男兒爲國羞。", "寒雨洗來香已盡，澹煙籠著恨長留。", "可憐汾水知人意，旁與吞聲未忍休。"]'),
('bae339d2-44f7-45d5-8a12-e26198f3a9c1','題李員外廳','李山甫','唐','唐诗','tang','','[]','石砌蛩吟響，草堂人語稀。',84,'全唐诗/poet.tang.35000.json','["石砌蛩吟響，草堂人語稀。", "道孤思絕唱，年長漸知非。", "名利終成患，煙霞亦可依。", "高丘松蓋古，閑地藥苗肥。", "猨鳥啼嘉景，牛羊傍晚暉。", "幽棲還自得，清嘯坐忘機。", "愛彼人深處，白雲相伴歸。"]'),
('7e1ca04a-ec8d-4414-8fd3-5f5caf642d02','山中寄梁判官','李山甫','唐','唐诗','tang','','[]','歸臥東林計偶諧，柴門深向翠微開。',64,'全唐诗/poet.tang.35000.json','["歸臥東林計偶諧，柴門深向翠微開。", "更無塵事心頭起，還有詩情象外來。", "康樂公應頻結社，寒山子亦患多才。", "星郎雅是道中侶，六藝拘牽在隗臺。"]'),
('9a285c45-d028-48d9-b1b8-d3a130c36d91','禪林寺作寄劉書記','李山甫','唐','唐诗','tang','','[]','坐近松風骨自寒，茅齋直拶白雲邊。',64,'全唐诗/poet.tang.35000.json','["坐近松風骨自寒，茅齋直拶白雲邊。", "玄關不閉何人到，此事誰論在佛先。", "天竺老師留一句，曹溪行者答全篇。", "今朝林下忘言說，強把新詩寄謫仙。"]'),
('7923ead0-313e-4dec-b8d2-885d0f57afb1','山中病後作','李山甫','唐','唐诗','tang','','[]','臥病厭厭三伏盡，商飆初自水邊來。',64,'全唐诗/poet.tang.35000.json','["臥病厭厭三伏盡，商飆初自水邊來。", "高峯枯槁骨偏峭，野樹扶疎葉未摧。", "時序追牽從鬢改，蟬聲酸急是誰催。", "雲門不閉全無事，心外沈然一聚灰。"]'),
('3f4d7d31-3aba-4742-8b39-b2c3d406fd3a','寄衛別駕','李山甫','唐','唐诗','tang','','[]','曉屐歸來嶽寺深，嘗思道侶會東林。',64,'全唐诗/poet.tang.35000.json','["曉屐歸來嶽寺深，嘗思道侶會東林。", "昏沈天竺看經眼，蕭索淨名老病心。", "雲蓋數重橫隴首，苔花千點遍松陰。", "知君超達悟空旨，三徑閑行抱素琴。"]'),
('504c444d-2e7a-4508-9a08-ac8976f31f76','遣懷','李山甫','唐','唐诗','tang','','[]','長松埋澗底，鬱鬱未出原。',72,'全唐诗/poet.tang.35000.json','["長松埋澗底，鬱鬱未出原。", "孤雲飛隴首，高潔不可攀。", "古道貴拙直，時事不足言。", "莫飲盜泉水，無爲天下先。", "智者與愚者，盡歸北邙山。", "唯有東流水，年光不蹔閑。"]'),
('744f543e-2b43-4caf-a1d5-dfd97c31cdaa','酬劉書記一二知己見寄','李山甫','唐','唐诗','tang','','[]','見說金臺客，相逢秪論詩。',72,'全唐诗/poet.tang.35000.json','["見說金臺客，相逢秪論詩。", "坐來殘暑退，吟許野僧知。", "自喜幽棲僻，唯慙道義虧。", "身閑偏好古，句冷不求奇。", "晦跡全無累，安貧自得宜。", "同人終念我，蓮社有歸期。"]'),
('00746ae5-6e74-4285-954e-536bc25747ae','山中依韻答劉書記見贈','李山甫','唐','唐诗','tang','','[]','幽居少人事，三徑草不開。',192,'全唐诗/poet.tang.35000.json','["幽居少人事，三徑草不開。", "隱几虛室靜，閑雲入坐來。", "至道非內外，詎言才不才。", "寶月當秋空，高潔無纖埃。", "心滅百慮減，詩成萬象回。", "亦有吾廬在，寂寞舊山隈。", "從容未歸去，滿地生青苔。", "謝公寄我詩，清奇不可陪。", "白雲飛不盡，碧雲欲成堆。", "驚風出地戶，虩虩似震雷。", "吟哦山嶽動，令人心膽摧。", "思君覽章句，還復如望梅。", "慷慨追古意，曠望登高臺。", "何當陶淵明，遠師勸傾盃。", "流年將老來，華髪自相催。", "野寺連屏障，左右相裴回。"]'),
('81c42920-e893-4820-a655-cb1622d80487','山中答劉書記寓懷','李山甫','唐','唐诗','tang','','[]','貴門多冠冕，日與榮辱並。',120,'全唐诗/poet.tang.35000.json','["貴門多冠冕，日與榮辱並。", "山中有獨夫，笑傲出衰盛。", "正直任天真，鬼神亦相敬。", "之子賁丘園，戶牖松蘿暎。", "骨將槁木齊，心同止水淨。", "筆頭指金波，座上橫玉柄。", "芙蓉出秋渚，繡段流清詠。", "高古不稱時，沈默豈相競。", "窮搜萬籟息，危坐千峯靜。", "林僧繼嘉唱，風前亦爲幸。"]'),
('cf93b309-99d2-4903-831a-948b41237045','項羽廟','李山甫','唐','唐诗','tang','','[]','爲虜爲王盡偶然，有何羞見漢江船。',32,'全唐诗/poet.tang.35000.json','["爲虜爲王盡偶然，有何羞見漢江船。", "停分天下猶嫌少，可要行人贈紙錢。"]'),
('21e45348-a3b1-4cf3-ab85-b4bd1ed9afed','春日商山道中作','李山甫','唐','唐诗','tang','','[]','一逕春光裏，揚鞭入翠微。',48,'全唐诗/poet.tang.35000.json','["一逕春光裏，揚鞭入翠微。", "風來花落帽，雲過雨沾衣。", "谷鳥銜枝去，巴人負笈歸。", "殘陽更惆悵，前路客亭稀。"]'),
('badbc3a4-f625-4d5f-a4d9-e5294f3ea568','古石硯','李山甫','唐','唐诗','tang','','[]','追琢他山石，方圓一勺深。',48,'全唐诗/poet.tang.35000.json','["追琢他山石，方圓一勺深。", "抱真唯守墨，求用每虛心。", "波浪因文起，塵埃爲廢侵。", "憑君更研究，何啻直千金。"]'),
('8f9fde68-8cba-4237-a2f7-6f1a5895fa17','惜花','李山甫','唐','唐诗','tang','','[]','未會春風意，開君又落君。',48,'全唐诗/poet.tang.35000.json','["未會春風意，開君又落君。", "一年今爛熳，幾日便繽紛。", "別豔那堪賞，餘香不忍聞。", "尊前恨無語，應解作朝雲。"]'),
('409a9707-4097-4323-8693-49ee24a47bd0','別楊秀才','李山甫','唐','唐诗','tang','','[]','因亂與君別，相逢悲且驚。',48,'全唐诗/poet.tang.35000.json','["因亂與君別，相逢悲且驚。", "開襟魂自慰，拭淚眼空明。", "故國已無業，舊交多不生。", "如何又分袂，難話別離情。"]'),
('f2429d5e-f507-4138-b954-911a00a831a1','自歎拙','李山甫','唐','唐诗','tang','','[]','自憐心計拙，欲語更悲辛。',48,'全唐诗/poet.tang.35000.json','["自憐心計拙，欲語更悲辛。", "世亂僮欺主，年衰鬼弄人。", "鏡中顏欲老，江上業長貧。", "不是劉公樂，何由變此身。"]'),
('4a224e8b-7580-49b4-9906-caef628be9c0','亂後途中','李山甫','唐','唐诗','tang','','[]','亂離尋故園，朝市不如村。',48,'全唐诗/poet.tang.35000.json','["亂離尋故園，朝市不如村。", "慟哭翻無淚，顛狂覺少魂。", "諸侯貪割據，羣盜恣幷吞。", "爲問登壇者，何年答漢恩。"]'),
('031feb59-e047-4527-bf66-810a5008bc19','燕','李山甫','唐','唐诗','tang','','[]','每歲同辛苦，看人似有情。',48,'全唐诗/poet.tang.35000.json','["每歲同辛苦，看人似有情。", "亂飛春得意，幽語夜聞聲。", "整羽莊姜恨，迴身漢后輕。", "豪家足金彈，不用污雕楹。"]'),
('a1d40d1e-a200-4cc8-b119-5189cca2dfae','題慈雲寺僧院','李山甫','唐','唐诗','tang','','[]','帝城深處寺，棲殿壓秋江。',48,'全唐诗/poet.tang.35000.json','["帝城深處寺，棲殿壓秋江。", "紅葉去寒樹，碧峯來曉窗。", "煙霞生淨土，苔蘚上高幢。", "欲問吾師語，心猨不肯降。"]'),
('c846db54-7fed-417a-b0d9-b35c304b3933','聞子規','李山甫','唐','唐诗','tang','','[]','冤禽名杜宇，此事更難知。',48,'全唐诗/poet.tang.35000.json','["冤禽名杜宇，此事更難知。", "昔帝一時恨，後人千古悲。", "斷腸思故國，啼血濺芳枝。", "況是天涯客，那堪□□眉。"]'),
('8b050f88-e4c9-4cba-aa14-1735bf5e4b3a','送劉將軍入關討賊','李山甫','唐','唐诗','tang','','[]','世人多恃武，何者是真雄。',48,'全唐诗/poet.tang.35000.json','["世人多恃武，何者是真雄。", "欲滅黃巾賊，須憑黑矟公。", "指星憂國計，望氣識天風。", "明日凌雲上，期君第一功。"]'),
('9a446816-cd3b-4dda-a1be-12796dc43592','陪鄭先輩華山羅谷訪張隱者','李山甫','唐','唐诗','tang','','[]','白雲閑洞口，飛蓋入嵐光。',48,'全唐诗/poet.tang.35000.json','["白雲閑洞口，飛蓋入嵐光。", "好鳥共人語，異花迎客香。", "谷風聞鼓吹，苔石見文章。", "不是陪仙侶，無因訪阮郎。"]'),
('ca70f842-d61e-4d41-ab95-12fa47fcc816','兵後尋邊三首 一','李山甫','唐','唐诗','tang','','[]','千里煙砂盡日昏，戰餘燒罷閉重門。',64,'全唐诗/poet.tang.35000.json','["千里煙砂盡日昏，戰餘燒罷閉重門。", "新成劒戟皆農器，舊著衣裳盡血痕。", "卷地朔風吹白骨，柱天青氣泣幽魂。", "自憐長策無人問，羞戴儒冠傍塞垣。"]'),
('cf73cabf-0d1b-4231-b0b4-ab22e1c96135','兵後尋邊三首 二','李山甫','唐','唐诗','tang','','[]','旗頭指處見黃埃，萬馬橫馳鶻翅迴。',64,'全唐诗/poet.tang.35000.json','["旗頭指處見黃埃，萬馬橫馳鶻翅迴。", "劒戟遠腥凝血在，山河先暗陣雲來。", "角聲惡殺悲於哭，鼓勢爭強怒若雷。", "日暮却登寒壘望，飽鴟清嘯伏屍堆。"]'),
('1fa8a2f7-2c17-4aa2-8801-363316ec8247','兵後尋邊三首 三','李山甫','唐','唐诗','tang','','[]','風怒邊沙迸鐵衣，胡兒胡馬正驕肥。',64,'全唐诗/poet.tang.35000.json','["風怒邊沙迸鐵衣，胡兒胡馬正驕肥。", "將軍對陣誰教入，戰士辭營不道歸。", "新血濺紅黏蔓草，舊骸堆白映寒暉。", "胸中縱有銷兵術，欲向何門說是非。"]'),
('b6967cf9-7689-4b9a-b18d-81a39068b6ef','滄浪峽','李山甫','唐','唐诗','tang','','[]','走轂飛蹄過此傍，幾人留意問滄浪。',32,'全唐诗/poet.tang.35000.json','["走轂飛蹄過此傍，幾人留意問滄浪。", "煙波莫笑趨名客，爲愛朝宗日夜忙。"]'),
('aa0be53e-c35f-4bcf-9963-a1a2ce76fa94','公子家二首 一','李山甫','唐','唐诗','tang','','[]','曾是皇家幾世侯，入雲高第照神州。',66,'全唐诗/poet.tang.35000.json','["曾是皇家幾世侯，入雲高第照神州。", "柳遮門戶橫金鎖，花擁弦歌咽畫樓。", "錦袖妒姬爭巧笑，玉銜[驕]馬索閑遊。", "麻衣酷獻平生業，醉倚春風不點頭。"]'),
('bf93a660-38dd-4394-bfbb-73bbed191eb0','公子家二首 二','李山甫','唐','唐诗','tang','','[]','柳底花陰壓露塵，醉煙輕罩一團春。',64,'全唐诗/poet.tang.35000.json','["柳底花陰壓露塵，醉煙輕罩一團春。", "鴛鴦占水能嗔客，鸚鵡嫌籠解駡人。", "騕褭似龍隨日換，輕盈如燕逐年新。", "不知買盡長安笑，活得蒼生幾戶貧。"]'),
('1bc7d111-5685-4bd6-87cf-80d17db7b4fc','山下殘夏偶作','李山甫','唐','唐诗','tang','','[]','等閑三伏後，獨臥此高丘。',48,'全唐诗/poet.tang.35000.json','["等閑三伏後，獨臥此高丘。", "殘暑炎於火，林風爽帶秋。", "聲名何要出，吟詠亦堪休。", "自許紅塵外，雲溪好漱流。"]'),
('fd54e990-4f28-4d16-9cbd-1ce909e3247a','夜吟','李山甫','唐','唐诗','tang','','[]','除却閑吟外，人間事事慵。',48,'全唐诗/poet.tang.35000.json','["除却閑吟外，人間事事慵。", "更深成一句，月冷上孤峯。", "窮理多瞑目，含毫靜倚松。", "終篇渾不寐，危坐到晨鐘。"]'),
('1a7353dc-27dd-4f11-a384-4cec7a407e29','代崇徽公主意','李山甫','唐','唐诗','tang','','[]','金釵墜地鬢堆雲，自別朝陽帝豈聞。',32,'全唐诗/poet.tang.35000.json','["金釵墜地鬢堆雲，自別朝陽帝豈聞。", "遣妾一身安社稷，不知何處用將軍。"]'),
('e3fb575b-cdf2-45a3-877a-29ff52418cc0','下第獻所知三首 一','李山甫','唐','唐诗','tang','','[]','偶向江頭別釣磯，等閑經歲與心違。',64,'全唐诗/poet.tang.35000.json','["偶向江頭別釣磯，等閑經歲與心違。", "虛教六尺受辛苦，枉把一身憂是非。", "青桂本來無欠負，碧霄何處有因依？", "春風不用相催促，迴避花時也解歸。"]'),
('636da7b1-f7f6-4a30-9b1a-c55ea8b60ff4','下第獻所知三首 二','李山甫','唐','唐诗','tang','','[]','不識人間巧路岐，只將端拙泥神祇。',64,'全唐诗/poet.tang.35000.json','["不識人間巧路岐，只將端拙泥神祇。", "與他名利本無分，却共水雲曾有期。", "大抵物情應莫料，近來天意也須疑。", "自憐心計今如此，憑仗春醪爲解頤。"]'),
('4876b9e7-9ce2-4881-9855-e2cffdf3abc4','下第獻所知三首 三','李山甫','唐','唐诗','tang','','[]','十年磨鏃事鋒鋩，始逐朱旗入戰塲。',64,'全唐诗/poet.tang.35000.json','["十年磨鏃事鋒鋩，始逐朱旗入戰塲。", "四海風雲難際會，一生肝膽易開張。", "退飛鶯谷春零落，倒卓龍門路渺茫。", "今日慙知也慙命，笑餘歌罷忽淒涼。"]'),
('08c626ac-6cb1-43a1-88ba-64644d1920f9','寄太常王少卿','李山甫','唐','唐诗','tang','','[]','別後西風起，新蟬坐臥聞。',48,'全唐诗/poet.tang.35000.json','["別後西風起，新蟬坐臥聞。", "秋天靜如水，遠岫碧侵雲。", "雅飲純和氣，清吟冰雪文。", "想思重回首，梧葉下紛紛。"]'),
('87836386-02d5-42f5-a158-d441cc399d96','遊俠兒','李山甫','唐','唐诗','tang','','[]','好把雄姿渾世塵，一塲閑事莫因循。',32,'全唐诗/poet.tang.35000.json','["好把雄姿渾世塵，一塲閑事莫因循。", "荆軻只爲閑言語，不與燕丹了得人。"]'),
('1e079c98-2067-4dd7-9665-8b84fdc7a7ad','下第出春明門','李山甫','唐','唐诗','tang','','[]','曾和秋雨驅愁入，却向春風領恨回。',32,'全唐诗/poet.tang.35000.json','["曾和秋雨驅愁入，却向春風領恨回。", "深謝灞陵堤畔柳，與人頭上拂塵埃。"]'),
('80d6dbb6-2425-49cd-b264-b02cf89d4a0b','望思臺','李山甫','唐','唐诗','tang','','[]','君父昏蒙死不回，謾將平地築高臺。',32,'全唐诗/poet.tang.35000.json','["君父昏蒙死不回，謾將平地築高臺。", "九層黃土是何物，銷得向前冤恨來。"]'),
('dfff3e3a-8dd6-45d7-afc2-cb2379c13cf0','病中答劉書記見贈','李山甫','唐','唐诗','tang','','[]','病來雙樹下，雲脚上禪袍。',48,'全唐诗/poet.tang.35000.json','["病來雙樹下，雲脚上禪袍。", "頻有瓊瑤贈，空瞻雪月高。", "已知捐俗態，時許話風騷。", "衰疾未能起，相思徒自勞。"]'),
('9db4aca4-0946-4b2a-be3e-f956540c9386','早秋山中作','李山甫','唐','唐诗','tang','','[]','誰到山中語，雨餘風氣秋。',48,'全唐诗/poet.tang.35000.json','["誰到山中語，雨餘風氣秋。", "煙嵐出澗底，瀑布落牀頭。", "至道亦非遠，僻詩須苦求。", "千峰有嘉景，拄杖獨巡遊。"]'),
('3650d400-b87b-405e-8235-45f67cbc43f1','別墅','李山甫','唐','唐诗','tang','','[]','此地可求息，開門足野情。',48,'全唐诗/poet.tang.35000.json','["此地可求息，開門足野情。", "窗明雨初歇，日落風更清。", "蒼蘚槎根匝，碧煙水面生。", "翫奇心自樂，暑月聽蟬聲。"]'),
('7ca86906-05b4-4767-b25b-d01fbd0ead36','柳十首 一','李山甫','唐','唐诗','tang','','[]','灞岸江頭臘雪消，東風偷軟入纖條。',32,'全唐诗/poet.tang.35000.json','["灞岸江頭臘雪消，東風偷軟入纖條。", "春來不忍登樓望，萬架金絲著地嬌。"]'),
('19cdb053-e124-471b-8dd2-985cbfcd581b','柳十首 二','李山甫','唐','唐诗','tang','','[]','受盡風霜得到春，一條條是逐年新。',32,'全唐诗/poet.tang.35000.json','["受盡風霜得到春，一條條是逐年新。", "尋常送別無餘事，爭忍攀將過與人。"]'),
('128ba1ca-fdcc-4dfb-986a-db65523adf7f','柳十首 三','李山甫','唐','唐诗','tang','','[]','長恨陽和也世情，把香和豔與紅英。',32,'全唐诗/poet.tang.35000.json','["長恨陽和也世情，把香和豔與紅英。", "家家只是栽桃李，獨自無根到處生。"]'),
('dbcd044a-da3b-4c27-9b15-64bb44afe41d','柳十首 四','李山甫','唐','唐诗','tang','','[]','只爲遮樓又拂橋，被人摧折好枝條。',32,'全唐诗/poet.tang.35000.json','["只爲遮樓又拂橋，被人摧折好枝條。", "假饒張緒如今在，須把風流暗裏銷。"]'),
('6106b1bf-bf97-4f80-956e-199203ab3384','柳十首 五','李山甫','唐','唐诗','tang','','[]','弱帶低垂可自由，傍他門戶倚他樓。',32,'全唐诗/poet.tang.35000.json','["弱帶低垂可自由，傍他門戶倚他樓。", "金風不解相擡舉，露壓煙欺直到秋。"]'),
('95c5f416-b8b0-456f-b022-c558e1a24090','柳十首 六','李山甫','唐','唐诗','tang','','[]','終日堂前學畫眉，幾人曾道勝花枝。',32,'全唐诗/poet.tang.35000.json','["終日堂前學畫眉，幾人曾道勝花枝。", "試看三月春殘後，門外青陰是阿誰。"]'),
('0804b937-3f23-4d55-a4d4-76339462f67b','柳十首 七','李山甫','唐','唐诗','tang','','[]','也曾飛絮謝家庭，從此風流別有名。',32,'全唐诗/poet.tang.35000.json','["也曾飛絮謝家庭，從此風流別有名。", "不是向人無用處，一枝愁殺別離情。"]'),
('2b997729-03fd-4a73-8a23-a79162f816c3','柳十首 八','李山甫','唐','唐诗','tang','','[]','從來只是愛花人，楊柳何曾占得春。',32,'全唐诗/poet.tang.35000.json','["從來只是愛花人，楊柳何曾占得春。", "多向客亭門外立，與他迎送往來塵。"]'),
('11d7f74f-d56c-46f5-a07c-1d2600905bba','柳十首 九','李山甫','唐','唐诗','tang','','[]','強扶柔態酒難醒，殢著春風別有情。',32,'全唐诗/poet.tang.35000.json','["強扶柔態酒難醒，殢著春風別有情。", "公子王孫且相伴，與君俱得幾時榮。"]'),
('11ae213e-73fa-4ab5-ba0a-78188a66ddb5','柳十首 十','李山甫','唐','唐诗','tang','','[]','無賴秋風斗覺寒，萬條煙草一時乾。',32,'全唐诗/poet.tang.35000.json','["無賴秋風斗覺寒，萬條煙草一時乾。", "遊人若要春消息，直向江頭臘後看。"]'),
('d6fd333f-417b-48e4-a8d6-b9198a8dad4b','酬劉書記見贈','李山甫','唐','唐诗','tang','','[]','獨在西峯末，憐君和氣多。',96,'全唐诗/poet.tang.35000.json','["獨在西峯末，憐君和氣多。", "勞生同朽索，急景似傾波。", "禪者行擔錫，樵師語隔坡。", "旱□生赤蘚，古木架青蘿。", "石澗新蟬脫，茅簷舊燕窠。", "篇章蒙見許，松月好相過。", "思苦通真理，吟清合大和。", "□□□□□，風起送漁歌。"]'),
('b382efc5-831e-47f6-8db8-e02330bbb27b','贈徐三十','李山甫','唐','唐诗','tang','','[]','春滿南宮白日長，夜來新值錦衣郎。',64,'全唐诗/poet.tang.35000.json','["春滿南宮白日長，夜來新值錦衣郎。", "朱排六相助神聳，玉襯一廳侵骨涼。", "砌竹拂袍爭草色，庭花飄豔妬蘭香。", "從今不羨乘槎客，曾到三星列宿傍。"]'),
('231418c4-d098-4d2e-8180-e83e5b9e79c4','牡丹','李山甫','唐','唐诗','tang','','[]','邀勒春風不早開，衆芳飄後上樓臺。',64,'全唐诗/poet.tang.35000.json','["邀勒春風不早開，衆芳飄後上樓臺。", "數苞仙豔火中出，一片異香天上來。", "曉露精神妖欲動，暮煙情態恨成堆。", "知君也解相輕薄，斜倚闌干首重迴。"]'),
('804ac476-3c58-4164-aaca-30549dd0970e','贈宿將','李山甫','唐','唐诗','tang','','[]','校獵燕山經幾春，雕弓白羽不離身。',32,'全唐诗/poet.tang.35000.json','["校獵燕山經幾春，雕弓白羽不離身。", "年來馬上渾無力，望見飛鴻指似人。"]'),
('03daac61-52d5-4b17-9b9c-1f38350768b1','水仙操','李咸用','唐','唐诗','tang','','[]','大波相拍流水鳴，蓬山鳥獸多奇形。',160,'全唐诗/poet.tang.35000.json','["大波相拍流水鳴，蓬山鳥獸多奇形。", "琴心不喜亦不驚，安弦緩爪何泠泠。", "水仙縹緲來相迎，伯牙從此留嘉名。", "嶧陽散木虛且輕，重華斧下知其聲。", "檿絲相糺成淒清，調和引得薰風生。", "指底先王長養情，曲終天下稱太平。", "後人好事傳其曲，有時聲足意不足。", "始峩峩兮復洋洋，但見山青兼水綠。", "成連入海移人情，豈是本來無嗜慾。", "琴兮琴兮在自然，不在徽金將軫玉。"]'),
('4ef8e21f-03b7-4d0e-b59f-26df8ef34195','雞鳴曲','李咸用','唐','唐诗','tang','','[]','海樹相扶烏影翹，戴紅拍翠聲膠膠。',88,'全唐诗/poet.tang.35000.json','["海樹相扶烏影翹，戴紅拍翠聲膠膠。", "鴛瓦凍危金距趫，誇雄鬬氣爭相高。", "漏殘雨急風蕭蕭，患亂忠臣欺寶刀。", "霜濃月薄星昭昭，太平才子能歌謠。", "山翁夢斷出衡茅，谷口霧中飢虎號，離人枕上心忉忉。"]'),
('0925b977-1e8a-435b-8c9c-c83039e3c518','西門行','李咸用','唐','唐诗','tang','','[]','勞禽不擇枝，飢虎不畏檻。',72,'全唐诗/poet.tang.35000.json','["勞禽不擇枝，飢虎不畏檻。", "君子當固窮，無爲仲由濫。", "爾奮空拳彼擊劍，水縱長瀾火飛焰。", "漢高偶試神蛇驗，武王龜筮驚人險。", "四龍或躍猶依泉，小狐勿恃衝波膽。"]'),
('cda3ba75-7ed6-4d6a-9ea1-b7f343115c80','輕薄怨','李咸用','唐','唐诗','tang','','[]','花驄躞蹀遊龍驕，連連寶節揮長鞘。',112,'全唐诗/poet.tang.35000.json','["花驄躞蹀遊龍驕，連連寶節揮長鞘。", "鳳雛麟子皆至交，春風相逐垂楊橋。", "捻笙軟玉開素苞，畫樓閃閃紅裙搖。", "碧蹄偃蹇連金鑣，狂情十里飛相燒。", "西母青禽輕飄飄，分環破璧來往勞。", "黃金千鎰新一宵，少年心事風中毛。", "明朝何處逢嬌饒，門前桃樹空夭夭。"]'),
('92067edc-02e7-4eca-b3e1-e7f0651b38bf','長歌行','李咸用','唐','唐诗','tang','','[]','要衣須破束，欲炙須解牛。',142,'全唐诗/poet.tang.35000.json','["要衣須破束，欲炙須解牛。", "當年不快意，徒爲他人留。", "百歲之約何悠悠，華髪星星稀滿頭。", "蛾眉螓首聊我仇，圓紅闕白令人愁，何不夕引清奏？", "朝登翠樓，逢花便折，聞勝即遊。", "鼓腕騰棍晴雷收，舞腰困褭垂楊柔。", "象筯擊折歌勿休，玉山未倒非風流。", "眼前有物俱是夢，莫將身作黃金讐。", "死生同域不用懼，富貴在天何足憂。"]'),
('1e85b3fc-0f9b-41ab-88ce-7be21972ab0f','巫山高','李咸用','唐','唐诗','tang','','[]','通蜀連秦山十二，中有妖靈會人意。',96,'全唐诗/poet.tang.35000.json','["通蜀連秦山十二，中有妖靈會人意。", "鬬豔傳情世不知，楚王魂夢春風裏。", "雨態雲容多似是，色荒見物皆成媚。", "露泫煙愁巖上花，至今猶滴相思淚。", "西眉南臉人中美，或者皆聞無所利。", "忍聽憑虛巧佞言，不求萬壽翻求死。"]'),
('9285deb1-301a-4f27-a4f9-2e02f7ad6f64','公無渡河','李咸用','唐','唐诗','tang','','[]','有叟有叟何清狂，行搔短髪提壺漿。',76,'全唐诗/poet.tang.35000.json','["有叟有叟何清狂，行搔短髪提壺漿。", "亂流直涉神洋洋，妻止不聽追沈湘。", "偕老不偕死，箜篌遺淒涼。", "刳松輕穩琅玕長，連呼急榜庸何妨。", "見溺不援能語狼，忍聽麗玉傳悲傷。"]'),
('8d50d76b-b580-4cd9-9f21-5cfbf582accc','春雨','李咸用','唐','唐诗','tang','','[]','大帝閑吹破凍風，青雲融液流長空。',64,'全唐诗/poet.tang.35000.json','["大帝閑吹破凍風，青雲融液流長空。", "天人醉引玄酒注，傾香旋入花根土。", "濕塵輕舞唐唐春，神娥無跡莓苔新。", "老農私與牧童論，紛紛便是倉箱本。"]'),
('aedd3f13-ad27-418f-b366-a0f5cf6ca6cb','石版歌','李咸用','唐','唐诗','tang','','["\u592a\u6e56"]','雲根劈裂雷斧痕，龍泉切璞青皮皴。',64,'全唐诗/poet.tang.35000.json','["雲根劈裂雷斧痕，龍泉切璞青皮皴。", "直方挺質貞且真，當庭卓立凝頑神。", "春雨流膏成立文，主人性靜看長新。", "明月夜來迴短影，何如照冷太湖濱。"]'),
('939820b9-39e1-45c4-bf95-2680b06a664e','春宮詞','李咸用','唐','唐诗','tang','','[]','風和氣淑宮殿春，感陽體解思君恩。',76,'全唐诗/poet.tang.35000.json','["風和氣淑宮殿春，感陽體解思君恩。", "眼光滴滴心振振，重瞳不轉憂生民，女當爲妾男當臣。", "男力百歲在，女色片時新。", "用不用，唯一人。", "敢放天寵私微身，六宮萬國教誰賓。"]'),
('5767a5df-ea11-4c46-bf8c-6ab84e0f9f15','富貴曲','李咸用','唐','唐诗','tang','','[]','畫藻雕山金碧彩，鴛鴦曡翠眠晴靄。',218,'全唐诗/poet.tang.35000.json','["畫藻雕山金碧彩，鴛鴦曡翠眠晴靄。", "編珠影裏醉春庭，團紅片下攢歌黛。", "革咽絲煩歡不改，繳絳垂緹忽如晦。", "活花起舞夜春來，蠟焰煌煌天日在。", "雪暖瑤杯鳳髓融，紅拖象筯猩唇細。", "空中漢轉星移蓋，火城擁出隨朝會。", "車如雷兮馬如龍，鬼神辟易不敢害。", "冠峩劍重鏘環珮，步入天門相真宰。", "開口長爲爵祿筌，迴眸便是公卿罪。", "珍珠索得龍宮貧，膏腴刮下蒼生背。", "九野干戈指著心，威福滿拳猶未快。", "我聞周公貴爲天子弟，富有半四海。", "蔑有驕奢貽後悔，紅錦障收。", "珊瑚樹碎，至今笑石崇王愷。"]'),
('f03bbe0c-559d-4226-8274-0f00a6087a42','獨鵠吟','李咸用','唐','唐诗','tang','','[]','碧玉喙長丹頂圓，亭亭危立風松間。',80,'全唐诗/poet.tang.35000.json','["碧玉喙長丹頂圓，亭亭危立風松間。", "啄萍吞鱗意已闌，舉頭咫尺輕重天。", "黑翎白本排雲煙，離羣脫侶孤如仙。", "披霜唳月驚嬋娟，逍遊忘却還青田。", "鳶寒鴉晚空相喧，時時側耳清冷泉。"]'),
('82f2cd68-0eb1-4ca2-a3a9-5420406b5e86','煌煌京洛行','李咸用','唐','唐诗','tang','','[]','長安近甸巡遊遍，洛陽尋有黃龍見。',96,'全唐诗/poet.tang.35000.json','["長安近甸巡遊遍，洛陽尋有黃龍見。", "千乘萬騎如雷轉，差差清蹕祥雲卷。", "百司舊分當玉殿，太平官屬無遺彥。", "歌鐘沸激香塵散，晨旗隱隱羅軒冕。", "周公舊跡生紅蘚，瀍澗波光春照晚。", "但聽嵩山萬歲聲，將軍旗鼓何時偃。"]'),
('bce1b608-14c7-4a09-a30f-93edae9f99b9','昇天行','李咸用','唐','唐诗','tang','','[]','堂堂削玉青蠅喧，寒鴉啄鼠愁飛鸞。',176,'全唐诗/poet.tang.35000.json','["堂堂削玉青蠅喧，寒鴉啄鼠愁飛鸞。", "梳玄洗白逡巡間，蘭言花笑俄衰殘。", "盤金束紫身屬官，強仁小德終無端。", "不如服取長流丹，潛神却入黃庭閑。", "志定功成飛九關，逍遙長揖辭人寰。", "空中龍駕時迴旋，左雲右鶴翔翩聯。", "雙童樹節當風翻，常娥倚桂開朱顏。", "河邊牛子星郎牽，三清宮殿浮晴煙。", "玉皇據案方凝然，仙官立仗森幢幡。", "引余再拜歸仙班，清聲妙色視聽安。", "飡和飲順中腸寬，虛無之樂不可言。"]'),
('3c9cbf40-1977-4747-b0ac-a01dbf737224','緋桃花歌','李咸用','唐','唐诗','tang','','[]','上帝春宮思麗絕，夭桃變態求新悅。',64,'全唐诗/poet.tang.35000.json','["上帝春宮思麗絕，夭桃變態求新悅。", "便是花中傾國容，牡丹露泣長門月。", "野樹滴殘龍戰血，曦車碾下朝霞屑。", "惆悵東風未解狂，爭教此物芳菲歇。"]'),
('ba307bc2-fca2-4441-8b4e-3077e577dd16','短歌行','李咸用','唐','唐诗','tang','','[]','一罇綠酒綠於染，拍手高歌天地險。',96,'全唐诗/poet.tang.35000.json','["一罇綠酒綠於染，拍手高歌天地險。", "上得青雲下不難，下在黃埃上須漸。", "少年歡樂須及時，莫學懦夫長泣岐。", "白日欲沈猶未沈，片月已來天半垂。", "坎鼓鏘鐘殺愁賊，挼碎是非佯不識。", "長短高卑不可求，莫歎人生頭雪色。"]'),
('5a91758f-e6d8-44cb-80a3-66390266ad68','小松歌','李咸用','唐','唐诗','tang','','[]','幽人不喜凡草生，秋鋤斸得寒青青。',96,'全唐诗/poet.tang.35000.json','["幽人不喜凡草生，秋鋤斸得寒青青。", "庭閑土瘦根脚獰，風搖雨拂精神醒。", "短影月斜不滿尺，清聲細入鳴蛩翼。", "天人戲剪蒼龍髯，參差簇在瑤堦側。", "金精水鬼欺不得，長與東皇逞顏色。", "勁節暫因君子移，貞心不爲麻中直。"]'),
('f4577b87-dc3b-4bee-8f03-206b385599fd','大雪歌','李咸用','唐','唐诗','tang','','[]','同雲慘慘如天怒，寒龍振鬣飛乾雨。',64,'全唐诗/poet.tang.35000.json','["同雲慘慘如天怒，寒龍振鬣飛乾雨。", "玉圃花飄朵不勻，銀河風急驚砂度。", "謝客憑軒吟未住，望中頓失縱橫路。", "應是羲和倦曉昏，暫反元元歸太素。"]'),
('2f0caadb-5178-4f09-a14c-639866673920','塘上行','李咸用','唐','唐诗','tang','','[]','橫塘日澹秋雲隔，浪織輕颸羅冪冪。',64,'全唐诗/poet.tang.35000.json','["橫塘日澹秋雲隔，浪織輕颸羅冪冪。", "紅綃撇水蕩舟人，畫橈摻摻柔荑白。", "鯉魚虛擲無消息，花老蓮疎愁未摘。", "却把金釵打綠荷，懊惱露珠穿不得。"]'),
('8246838a-99ce-49e5-bf69-3ce37023549d','寓意','李咸用','唐','唐诗','tang','','[]','直道荆棘生，斜徑紅塵起。',36,'全唐诗/poet.tang.35000.json','["直道荆棘生，斜徑紅塵起。", "蒼蒼杳無言，麒麟迴瑞趾。", "東風如未來，飛雪終不已。"]'),
('be1e2db2-1783-4fbf-aed6-c3e6acbfce0d','劍喻','李咸用','唐','唐诗','tang','','[]','黯黯秋水寒，至剛非可缺。',48,'全唐诗/poet.tang.35000.json','["黯黯秋水寒，至剛非可缺。", "風胡不出來，攝履人相蔑。", "縱挺倚天形，誰是躬提挈。", "願將百鍊身，助我王臣節。"]'),
('6159f836-285c-4101-bc4c-4dd055ff6b4f','蒼頡臺','李咸用','唐','唐诗','tang','','[]','先賢憂民詐，觀跡成綱紀。',24,'全唐诗/poet.tang.35000.json','["先賢憂民詐，觀跡成綱紀。", "自有書契來，爭及結繩理。"]'),
('909092a6-5da8-4673-b9f7-19d714ae81b7','荆山','李咸用','唐','唐诗','tang','','[]','良工指君疑，真玉却非玉。',24,'全唐诗/poet.tang.35000.json','["良工指君疑，真玉却非玉。", "寄言懷寶人，不須傷手足。"]'),
('4b40d13d-2b6f-4452-a816-233027b1bc1e','自君之出矣','李咸用','唐','唐诗','tang','','[]','自君之出矣，鸞鏡空塵生。',24,'全唐诗/poet.tang.35000.json','["自君之出矣，鸞鏡空塵生。", "思君如明月，明月逐君行。"]'),
('b42e7879-b2d3-4f59-94dd-6c69736de33c','妾薄命','李咸用','唐','唐诗','tang','','[]','妾命何太薄，不及宮中水。',24,'全唐诗/poet.tang.35000.json','["妾命何太薄，不及宮中水。", "時時對天顏，聲聲入君耳。"]'),
('b28c27f1-881e-416c-8da4-78cfa97903fd','君子行','李咸用','唐','唐诗','tang','','[]','君子慎所履，小人多所疑。',24,'全唐诗/poet.tang.35000.json','["君子慎所履，小人多所疑。", "尼甫至聖賢，猶爲匡所縻。"]'),
('c30599b0-833f-4761-a532-0ef4375b8b15','銅雀臺','李咸用','唐','唐诗','tang','','[]','但見西陵慘明月，女妓無因更相悅。',32,'全唐诗/poet.tang.35000.json','["但見西陵慘明月，女妓無因更相悅。", "有虞曾不有遺言，滴盡湘妃眼中血。"]'),
('38a0e28e-24f4-43fa-a526-f01acd371436','倢伃怨','李咸用','唐','唐诗','tang','','[]','莫恃芙蓉開滿面，更有身輕似飛燕。',32,'全唐诗/poet.tang.35000.json','["莫恃芙蓉開滿面，更有身輕似飛燕。", "不得團圓長近君，珪月鈋時泣秋扇。"]'),
('3c79b3b6-a192-4871-b4b3-9310179a7384','悲哉行','李咸用','唐','唐诗','tang','','[]','雲色陰沈弄秋氣，危葉高枝恨深翠。',32,'全唐诗/poet.tang.35000.json','["雲色陰沈弄秋氣，危葉高枝恨深翠。", "用却春風力幾多，微霜逼迫何容易。"]'),
('6f988bdf-67c8-4516-990c-a7c0badc9659','攜手曲','李咸用','唐','唐诗','tang','','[]','攜手春復春，未嘗漸離別。',60,'全唐诗/poet.tang.35000.json','["攜手春復春，未嘗漸離別。", "夭夭風前花，纖纖日中雪。", "不敢怨於天，唯驚添歲月。", "不敢怨於君，秪怕芳菲歇。", "芳菲若長然，君恩應不絕。"]'),
('5acc90a9-612e-42eb-8a2d-29ab6c655c92','空城雀','李咸用','唐','唐诗','tang','','[]','啾啾空城雀，一啄數跳躍。',36,'全唐诗/poet.tang.35000.json','["啾啾空城雀，一啄數跳躍。", "寧尋覆轍餘，豈比巢危幕。", "茫茫九萬鵬，百雉且爲樂。"]'),
('a6566b47-4995-4a3c-b87a-fc474110965a','放歌行','李咸用','唐','唐诗','tang','','[]','蠢蠢荼蓼蟲，薨薨避葵薺。',60,'全唐诗/poet.tang.35000.json','["蠢蠢荼蓼蟲，薨薨避葵薺。", "悠悠狷者心，寂寂厭清世。", "如何不食甘，命合苦其噬。", "如何不趣時，分合辱其體。", "至哉先哲言，於物不凝滯。"]'),
('92fd4bec-c397-4b44-b8b0-e5d3caa1b99f','猛虎行','李咸用','唐','唐诗','tang','','[]','猛虎不怯敵，烈士無虛言。',48,'全唐诗/poet.tang.35000.json','["猛虎不怯敵，烈士無虛言。", "怯敵辱其班，虛言負其恩。", "爪牙欺白刃，果敢無前陣。", "須知易水歌，至死無悔恡。"]'),
('8797f174-0807-4bb0-96ae-219c0bbb731c','隴頭行','李咸用','唐','唐诗','tang','','[]','行人何徬徨，隴頭水嗚咽。',48,'全唐诗/poet.tang.35000.json','["行人何徬徨，隴頭水嗚咽。", "寒沙戰鬼愁，白骨風霜切。", "薄日曚曨秋，怨氣陰雲結。", "殺成邊將名，名著生靈滅。"]'),
('797e6674-d389-4f87-bdfb-50861c154abe','關山月','李咸用','唐','唐诗','tang','','[]','離離天際雲，皎皎關山月。',60,'全唐诗/poet.tang.35000.json','["離離天際雲，皎皎關山月。", "羌笛一聲來，白盡征人髪。", "嘹唳孤鴻高，蕭索悲風發。", "雪壓塞塵清，鵰落沙場闊。", "何當胡無人，荷戈朝鳳闕。"]'),
('410ae66b-d8e5-454a-9394-ce259c8c4091','覽友生古風','李咸用','唐','唐诗','tang','','[]','伯牙鳴玉琴，幽音隨指發。',132,'全唐诗/poet.tang.35000.json','["伯牙鳴玉琴，幽音隨指發。", "不是鍾期聽，俗耳安能別。", "高山閑巍峩，流水聲嗚咽。", "一卷冰雪言，清泠冷心骨。", "分明古雅聲，諷諭成淒切。", "皴皵老松根，晃朗驪龍窟。", "荆璞且深藏，瑉石方如雪。", "金多醜女妍，木朽良工拙。", "姦宄欺雷霆，魑魅嫌日月。", "蝶迷桃李香，鮒惘江湖闊。", "不寐孤燈前，舒卷忘飢渴。"]'),
('787b7a62-4b3e-4010-b265-c5772c34dcba','題友生叢竹','李咸用','唐','唐诗','tang','','[]','菊華寒露濃，蘭愁曉霜重。',84,'全唐诗/poet.tang.35000.json','["菊華寒露濃，蘭愁曉霜重。", "指佞不長生，蒲萐今無種。", "安如植叢篁，他年待栖鳳。", "大則化龍騎，小可釣璜用。", "留煙伴獨醒，迴陰冷閑夢。", "何妨積雪凌，但爲清風動。", "乃知子猷心，不與常人共。"]'),
('2eca3daa-333c-4bb6-9509-5f32aa5022c0','石版','李咸用','唐','唐诗','tang','','[]','高人好自然，移得它山碧。',60,'全唐诗/poet.tang.35000.json','["高人好自然，移得它山碧。", "不磨如版平，大巧非因力。", "古蘚小青錢，塵中看野色。", "冷倚砌花春，靜伴疎篁直。", "山僧若轉頭，如逢舊相識。"]'),
('468099c0-de06-4952-9db7-27c905c8594b','江南曲','李咸用','唐','唐诗','tang','','[]','江南四月薰風低，江南女兒芳步齊。',64,'全唐诗/poet.tang.35000.json','["江南四月薰風低，江南女兒芳步齊。", "晚雲接水共渺瀰，遠沙曡草空萋萋。", "白苧不堪論古意，數花猶可醉前溪。", "孤舟有客歸未得，鄉夢欲成山鳥啼。"]'),
('88bcc6f6-8a16-4a94-970e-6fe45705a34e','臨川逢陳百年','李咸用','唐','唐诗','tang','','[]','麻姑山下逢真士，玄膚碧眼方瞳子。',96,'全唐诗/poet.tang.35000.json','["麻姑山下逢真士，玄膚碧眼方瞳子。", "自言混沌鑿不死，大笑老彭非久視。", "強爭龍虎是狂人，不保元和虛叩齒。", "桃花雨過春光膩，勸我一杯靈液味。", "教我無爲禮樂拘，利路名場多忌諱。", "不如含德反嬰兒，金玉滿堂真可貴。"]'),
('c597786f-a5f2-4b07-ad43-74ce16d1934a','寄修睦上人','李咸用','唐','唐诗','tang','','[]','衣服田方無內客，一入廬雲斷消息。',72,'全唐诗/poet.tang.35000.json','["衣服田方無內客，一入廬雲斷消息。", "應爲山中勝概偏，惠持惠遠多蹤跡。", "尋陽有箇虛舟子，相憶由來無一事。", "江邊月色到巖前，此際心情必相似。", "似不似，寄數字。"]'),
('f9443135-efc1-4f5a-85d0-991f03bb71d3','讀修睦上人歌篇','李咸用','唐','唐诗','tang','','[]','李白亡，李賀死。',132,'全唐诗/poet.tang.35000.json','["李白亡，李賀死。", "陳陶趙睦尋相次，須知代不乏騷人。", "貫休之後，惟修睦而已矣。", "睦公睦公真可畏，開口向人無所忌。", "才似煙霞生則媚，直如屈軼佞則指。", "意下紛紛造化機，筆頭滴滴文章髓。", "明月清風三十年，被君驅使如奴婢。", "勸君休，莫容易，世俗由來稀則貴。", "珊瑚高架五雲毫，小小不須煩藻思。"]'),
('2572035f-4df7-4a35-ae19-13155ff59d4d','遠公亭牡丹','李咸用','唐','唐诗','tang','','["\u5e90\u5c71"]','雁門禪客吟春亭，牡丹獨逞花中英。',136,'全唐诗/poet.tang.35000.json','["雁門禪客吟春亭，牡丹獨逞花中英。", "雙成膩臉偎雲屏，百般姿態因風生。", "延年不敢歌傾城，朝雲暮雨愁娉婷。", "蘂繁蟻脚黏不行，甜迷蜂醉飛無聲。", "廬山根脚含精靈，發妍吐秀叢君庭。", "湓江太守多閑情，欄朱繞絳留輕盈。", "潺潺綠醴當風傾，平頭奴子啾銀笙。", "紅葩豔豔交童星，左文右武憐君榮，白銅鞮上慙清明。"]'),
('c11b6611-4f6c-4581-9d9f-90a50ca8457e','謝僧寄茶','李咸用','唐','唐诗','tang','','["\u5e90\u5c71"]','空門少年初志堅，摘芳爲藥除睡眠。',136,'全唐诗/poet.tang.35000.json','["空門少年初志堅，摘芳爲藥除睡眠。", "匡山茗樹朝陽偏，暖萌如爪拏飛鳶。", "枝枝膏露凝滴圓，參差失向兜羅錦。", "傾筐短甑蒸新鮮，白紵眼細勻於研。", "甎排古砌春苔乾，殷勤寄我清明前。", "金槽無聲飛碧煙，赤獸呵冰急鐵喧。", "林風夕和真珠泉，半匙清粉攪潺湲。", "綠雲輕綰湘娥鬟，嘗來縱使重支枕，胡蝶寂寥空掩關。"]'),
('ad6e0da4-972f-4c71-9a55-6197676c79a3','送人','李咸用','唐','唐诗','tang','','[]','少皥開宮行帝業，無刃金風剪紅葉。',168,'全唐诗/poet.tang.35000.json','["少皥開宮行帝業，無刃金風剪紅葉。", "雁別邊沙入暖雲，蛩辭敗草鳴香閤。", "有客爲儒二十霜，酣歌郢雪時飄揚。", "不甘長在諸生下，束書攜劒離家鄉。", "利爪韝上鷹，雄文霧中豹。", "可堪長與烏鳶噪，是宜摩碧漢以遐飛。", "出南山而遠蹈，況今大朝公道。", "天子文明，團團月樹懸青青。", "燕中有馬如龍行，不換黃金無駿名。", "荆山有玉猶在璞，未遇良工虛擲鵲。", "一壺清酒酌離情，休向嵩中隨雀躍。"]'),
('c4b59c44-5d20-4657-8230-20936edb9367','古意論交','李咸用','唐','唐诗','tang','','[]','擇友如淘金，沙盡不得寶。',144,'全唐诗/poet.tang.35000.json','["擇友如淘金，沙盡不得寶。", "結交如乾銀，產竭不成道。", "我生四十年，相識苦草草。", "多爲勢利朋，少有歲寒操。", "通財能幾何，聞善寧相告。", "茫然同夜行，中路自不保。", "常恐管鮑情，參差忽終老。", "今來既見君，青天無片雲。", "語直瑟弦急，行高山桂芬。", "約我爲交友，不覺心醺醺。", "見義必許死，臨危當指囷。", "無令後世士，重廣孝標文。"]'),
('06274f5a-bc41-4b8a-9f97-645a16336434','春風','李咸用','唐','唐诗','tang','','[]','青帝使和氣，吹噓萬國中。',48,'全唐诗/poet.tang.35000.json','["青帝使和氣，吹噓萬國中。", "發生寧有異，先後自難同。", "輦草不消力，巖花應費功。", "年年三十騎，飄入玉蟾宮。"]'),
('dfe9b161-4cdc-4cb3-99a7-f250a07afe10','自愧','李咸用','唐','唐诗','tang','','[]','多負懸弧禮，危時隱薜蘿。',48,'全唐诗/poet.tang.35000.json','["多負懸弧禮，危時隱薜蘿。", "有心明俎豆，無力執干戈。", "壯士難移節，貞松不改柯。", "纓塵徒自滿，欲濯待清波。"]'),
('7a44a66f-c717-40af-aac0-15c5c26e8485','夜吟','李咸用','唐','唐诗','tang','','[]','白兔輪當午，儒家業敢慵。',48,'全唐诗/poet.tang.35000.json','["白兔輪當午，儒家業敢慵。", "竹軒吟未已，錦帳夢應重。", "落筆思成虎，懸梭待化龍。", "景清神自爽，風逓遠樓鐘。"]'),
('b067afe8-c19a-498b-bed2-65327983cb5b','昭君','李咸用','唐','唐诗','tang','','[]','古帝修文德，蠻夷莫敢侵。',48,'全唐诗/poet.tang.35000.json','["古帝修文德，蠻夷莫敢侵。", "不知桃李貌，能轉虎狼心。", "日暮邊風急，程遙磧雪深。", "千秋青塚骨，留怨在胡琴。"]'),
('1eb0e6a6-8e4a-42c9-b3c8-c58adfbf2f72','秋夕','李咸用','唐','唐诗','tang','','[]','寥廓秋雲薄，空庭月影微。',48,'全唐诗/poet.tang.35000.json','["寥廓秋雲薄，空庭月影微。", "樹寒棲鳥密，砌冷夜蛩稀。", "曉鼓軍容肅，疎鐘客夢歸。", "吟餘何所憶，聖主尚宵衣。"]'),
('de3932be-883b-4804-817f-ddfe13cc2220','秋日與友生言別','李咸用','唐','唐诗','tang','','[]','利名心未已，離別恨難休。',48,'全唐诗/poet.tang.35000.json','["利名心未已，離別恨難休。", "爲箇文儒業，致多岐路愁。", "數花籬菊晚，片葉井梧秋。", "又決出門計，一尊期少留。"]'),
('79d30b12-c3a7-4985-aac1-066f56fa52dd','邊城聽角','李咸用','唐','唐诗','tang','','[]','戍樓鳴畫角，寒露滴金槍。',48,'全唐诗/poet.tang.35000.json','["戍樓鳴畫角，寒露滴金槍。", "細引雲成陣，高催雁著行。", "喚迴邊將夢，吹薄曉蟾光。", "未遂終軍志，何勞思故鄉。"]'),
('02a6b142-7f05-4123-8877-220ea1439066','秋日訪同人','李咸用','唐','唐诗','tang','','[]','忽憶金蘭友，攜琴去自由。',48,'全唐诗/poet.tang.35000.json','["忽憶金蘭友，攜琴去自由。", "遠尋寒澗碧，深入亂山秋。", "見後却無語，別來長獨愁。", "幸逢三五夕，露坐對冥搜。"]'),
('53edfcf6-21b2-4677-9237-5dbfef58ab14','寄楚瓊上人','李咸用','唐','唐诗','tang','','[]','遙知無事日，靜對五峰秋。',48,'全唐诗/poet.tang.35000.json','["遙知無事日，靜對五峰秋。", "鳥隔寒煙語，泉和夕照流。", "凭欄疎磬盡，瞑目遠雲收。", "幾句出人意，風高白雪浮。"]'),
('16df96bc-83b9-4212-baac-a828c15caf97','遊寺','李咸用','唐','唐诗','tang','','[]','無家身自在，時得到蓮宮。',48,'全唐诗/poet.tang.35000.json','["無家身自在，時得到蓮宮。", "秋覺暑衣薄，老知塵世空。", "幽情憐水石，野性任萍蓬。", "是處堪閑坐，與僧行止同。"]'),
('ef6cc2fe-cf04-44b5-aa17-049709544d65','春日','李咸用','唐','唐诗','tang','','[]','浩蕩東風裏，裴回無所親。',36,'全唐诗/poet.tang.35000.json','["浩蕩東風裏，裴回無所親。", "危城三面水，古樹一邊春。", "衰世難修道，花時不稱貧。"]'),
('1dfb2d9f-2bcc-451a-9da5-8a33ef426f27','論交','李咸用','唐','唐诗','tang','','[]','行虧何必富，節在不妨貧。',48,'全唐诗/poet.tang.35000.json','["行虧何必富，節在不妨貧。", "易得笑言友，難逢終始人。", "松篁貞管鮑，桃李豔張陳。", "少見歲寒後，免爲霜雪塵。"]'),
('92d8d9c8-3feb-42bb-aca2-0c1bdcef504c','秋興','李咸用','唐','唐诗','tang','','[]','木葉亂飛盡，故人猶未還。',48,'全唐诗/poet.tang.35000.json','["木葉亂飛盡，故人猶未還。", "心雖遊紫闕，時合在青山。", "近寺僧鄰靜，臨池鶴對閑。", "兵戈如未息，名位莫相關。"]'),
('efbe7067-6be0-4f7e-8a3f-5e9d225940e0','山居','李咸用','唐','唐诗','tang','','[]','草堂書一架，苔徑竹千竿。',48,'全唐诗/poet.tang.35000.json','["草堂書一架，苔徑竹千竿。", "難世投誰是，清貧且自安。", "鄰居皆學稼，客至亦無官。", "焦尾何人聽，涼宵對月彈。"]'),
('458b9af4-8ced-4422-9c58-40fc59635d2a','遣興','李咸用','唐','唐诗','tang','','[]','風細酒初醒，憑欄別有情。',48,'全唐诗/poet.tang.35000.json','["風細酒初醒，憑欄別有情。", "蟬稀秋樹瘦，雨盡晚雲輕。", "旅鬢一絲出，鄉心寸火生。", "子牟魂欲斷，何日是升平。"]'),
('835ce4f2-24b9-4c25-a4ac-cce96100461d','待旦','李咸用','唐','唐诗','tang','','[]','簷靜燕雛語，窗虛蟾影過。',48,'全唐诗/poet.tang.35000.json','["簷靜燕雛語，窗虛蟾影過。", "時情因客老，歸夢入秋多。", "蔽日羣山霧，滔天四海波。", "吾皇思壯士，誰應大風歌。"]'),
('8beccc46-1d8b-4e32-8ae8-fcf621ce386a','送從兄坤載','李咸用','唐','唐诗','tang','','[]','忍淚不敢下，恐兄情更傷。',48,'全唐诗/poet.tang.35000.json','["忍淚不敢下，恐兄情更傷。", "別離當亂世，骨肉在他鄉。", "語盡意不盡，路長愁更長。", "那堪回首處，殘照滿衣裳。"]'),
('489d38f5-329b-4627-a6e1-8c521ae187a6','惜別','李咸用','唐','唐诗','tang','','[]','細雨妝行色，霏霏入戶來。',36,'全唐诗/poet.tang.35000.json','["細雨妝行色，霏霏入戶來。", "須知相識喜，却是別愁媒。", "白刃方盈國，黃金不上臺。"]'),
('d174cba5-5379-4a13-ba63-5d93c3079802','早秋遊山寺','李咸用','唐','唐诗','tang','','[]','閑臥雲巖穩，攀緣笑戲猱。',48,'全唐诗/poet.tang.35000.json','["閑臥雲巖穩，攀緣笑戲猱。", "靜於諸境靜，高却衆山高。", "至理無言了，浮生一夢勞。", "清風朝復暮，四海自波濤。"]'),
('56e0710a-ff8c-4707-ac10-97ff5ca0baca','秋日疾中寄諸同志','李咸用','唐','唐诗','tang','','[]','閑居無勝事，公幹臥來心。',48,'全唐诗/poet.tang.35000.json','["閑居無勝事，公幹臥來心。", "門靜秋風晚，人稀古巷深。", "花疎籬菊色，葉減井梧陰。", "賴有斯文在，時時得強尋。"]'),
('caa1cd0b-4de2-431c-ab43-701cf92dc45e','贈山僧','李咸用','唐','唐诗','tang','','[]','榮枯雖在目，名利不關身。',48,'全唐诗/poet.tang.35000.json','["榮枯雖在目，名利不關身。", "高出城隍寺，野爲雲鶴鄰。", "松聲寒後遠，潭色雨餘新。", "豈住空空裏，空空亦是塵。"]'),
('f3c5024a-4396-4ec5-bd66-115379050621','宿隱者居','李咸用','唐','唐诗','tang','','[]','永日連清夜，因君識躁君。',48,'全唐诗/poet.tang.35000.json','["永日連清夜，因君識躁君。", "竹扉難掩月，巖樹易延雲。", "曙鳥枕前起，寒泉夢裏聞。", "又須隨計吏，雞鶴迥然分。"]'),
('79bc43cf-ff1c-4f79-8ed7-ef23d3db3273','送錢契明尊師歸廬山','李咸用','唐','唐诗','tang','','["\u5e90\u5c71"]','瘦倚青竹杖，鑪峰指欲歸。',48,'全唐诗/poet.tang.35000.json','["瘦倚青竹杖，鑪峰指欲歸。", "霜黏行日屨，風暖到時衣。", "憑檻雲還在，攀松鶴不飛。", "何曾有別恨，楊柳自依依。"]'),
('ac9faf74-5f90-470e-a063-5444bd494af8','送進士劉松','李咸用','唐','唐诗','tang','','[]','滔滔皆魯客，難得是心知。',48,'全唐诗/poet.tang.35000.json','["滔滔皆魯客，難得是心知。", "到寺多同步，遊山未失期。", "雲低春雨後，風細暮鐘時。", "忽別垂楊岸，遙遙望所之。"]'),
('05730877-1741-4016-acda-56647cc356c5','贈任肅','李咸用','唐','唐诗','tang','','[]','玄髪難姑息，青雲有路岐。',48,'全唐诗/poet.tang.35000.json','["玄髪難姑息，青雲有路岐。", "莫言多事日，虛擲少年時。", "松色雪中出，人情難後知。", "聖朝公道在，中鵠勿差池。"]'),
('fd31eed7-1086-49ef-9eca-64b74ea9533e','題陳正字山居','李咸用','唐','唐诗','tang','','[]','怪來忘祿位，習學近瀟湘。',48,'全唐诗/poet.tang.35000.json','["怪來忘祿位，習學近瀟湘。", "見處雲山好，吟中歲月長。", "花光籠晚雨，樹映浸寒塘。", "幾日憑欄望，歸心自不忙。"]'),
('7eecbf0f-c2f3-45b8-8626-eba2f3fc57b0','贈來進士鵬','李咸用','唐','唐诗','tang','','[]','語玄人不到，星漢在靈空。',48,'全唐诗/poet.tang.35000.json','["語玄人不到，星漢在靈空。", "若使無良遇，虛言有至公。", "月明千嶠雪，灘急五更風。", "此際苦吟力，分將造化功。"]'),
('ab2d2305-2e50-4492-8762-10f52e08d644','送曹稅','李咸用','唐','唐诗','tang','','[]','摻袂向春風，何時約再逢。',48,'全唐诗/poet.tang.35000.json','["摻袂向春風，何時約再逢。", "若教相見密，肯恨別離重。", "芳草漁家路，殘陽水寺鐘。", "落帆當此處，吟興不應慵。"]'),
('c7ccf313-f574-4962-9a7e-d24e52c5747e','贈來鵬','李咸用','唐','唐诗','tang','','[]','默坐非關悶，凝情秪在詩。',48,'全唐诗/poet.tang.35000.json','["默坐非關悶，凝情秪在詩。", "庭閑花落後，山靜月明時。", "荅客言多簡，尋僧步稍遲。", "既同和氏璧，終有玉人知。"]'),
('aa6ebbf7-d0c5-4638-89cc-a1e4c01e4e73','途中作','李咸用','唐','唐诗','tang','','[]','瘦馬倦行役，斜陽勸著鞭。',48,'全唐诗/poet.tang.35000.json','["瘦馬倦行役，斜陽勸著鞭。", "野橋寒樹亞，山店暮雲連。", "退鷁風雖急，攀龍志已堅。", "路人休莫笑，百里有時賢。"]'),
('5f0518c3-c371-48cb-aee5-480af9a863ad','秋晚','李咸用','唐','唐诗','tang','','[]','斜陽山雨外，秋色思無窮。',48,'全唐诗/poet.tang.35000.json','["斜陽山雨外，秋色思無窮。", "柳葉飄乾翠，楓枝撼碎紅。", "鬢毛看似雪，生計尚如蓬。", "不及樵童樂，蒹葭一笛風。"]'),
('3917ec48-e51f-4e43-be54-d3d61563f0d5','曉望','李咸用','唐','唐诗','tang','','[]','露驚松上鶴，曉色動扶桑。',48,'全唐诗/poet.tang.35000.json','["露驚松上鶴，曉色動扶桑。", "碧浪催人老，紅輪照物忙。", "世情隨日變，利路與天長。", "好駕觥船去，陶陶入醉鄉。"]'),
('434606b8-d921-4fe0-95d9-2deaf7f1d2a4','寄友生','李咸用','唐','唐诗','tang','','[]','交情應不變，何事久離羣。',48,'全唐诗/poet.tang.35000.json','["交情應不變，何事久離羣。", "圓月思同步，寒泉憶共聞。", "雪霜松色在，風雨雁行分。", "每見人來說，窗前改舊文。"]'),
('92e19adb-fd2c-45af-a6f0-eab2d9803d30','江行','李咸用','唐','唐诗','tang','','[]','瀟湘無事後，征棹復嘔啞。',48,'全唐诗/poet.tang.35000.json','["瀟湘無事後，征棹復嘔啞。", "高岫留斜照，歸鴻背落霞。", "魚殘沙岸草，蝶寄洑流槎。", "共說干戈苦，汀洲減釣家。"]'),
('d45f485c-3c30-44b7-a414-f14cba61e690','題王氏山居','李咸用','唐','唐诗','tang','','[]','簷有煙嵐色，地多松竹風。',48,'全唐诗/poet.tang.35000.json','["簷有煙嵐色，地多松竹風。", "自言離亂後，不到鼓鼙中。", "徑柳拂雲綠，山櫻帶雪紅。", "南邊青嶂下，時見採芝翁。"]'),
('4c8b12d5-c287-4152-b546-bde4a09d753b','送別','李咸用','唐','唐诗','tang','','[]','別意說難盡，離盃深莫辭。',48,'全唐诗/poet.tang.35000.json','["別意說難盡，離盃深莫辭。", "長歌終此席，一笑又何時。", "棹入寒潭急，帆當落照遲。", "遠書如不寄，無以慰相思。"]'),
('85efa425-c26e-4ef8-9eb9-a3ce28d52c70','覽文僧卷','李咸用','唐','唐诗','tang','','[]','雖無先聖耳，異代得聞昭。',48,'全唐诗/poet.tang.35000.json','["雖無先聖耳，異代得聞昭。", "怪石難爲古，奇花不敢妖。", "調高非郢雪，思靜礙箕瓢。", "未可重吟過，雲山興轉饒。"]'),
('38549906-01a3-49e6-9e48-569aee2c1b73','望仰山憶玄泰上人','李咸用','唐','唐诗','tang','','[]','晴嵐凝片碧，知在此中禪。',48,'全唐诗/poet.tang.35000.json','["晴嵐凝片碧，知在此中禪。", "見面定何日，無書已一年。", "高秋關靜夢，良夜入新篇。", "仰德心如是，清風不我傳。"]'),
('116e161b-4964-4d91-aa3a-d48b88fd8090','聞泉','李咸用','唐','唐诗','tang','','[]','淅淅夢初驚，幽窗枕簟清。',48,'全唐诗/poet.tang.35000.json','["淅淅夢初驚，幽窗枕簟清。", "更無人共聽，秪有月空明。", "急想穿巖曲，低應過石平。", "欲將琴強寫，不是自然聲。"]'),
('36b816e2-7ec1-4d06-a3bb-fc8f1e1750a7','酬鄭進士九江新居見寄','李咸用','唐','唐诗','tang','','[]','躡屐扣柴關，因成盡日閑。',48,'全唐诗/poet.tang.35000.json','["躡屐扣柴關，因成盡日閑。", "獨聽黃鳥語，深似白雲間。", "萍沼寬於井，莎城綠當山。", "前期招我作，此景得吟還。"]'),
('acfaa4fa-3c35-4f86-80a6-5108a2436530','九江和人贈陳生','李咸用','唐','唐诗','tang','','[]','天畏斯文墜，憑君助素風。',48,'全唐诗/poet.tang.35000.json','["天畏斯文墜，憑君助素風。", "意深皆可補，句逸不因功。", "暮替雲愁遠，秋驚月占空。", "寄家當瀑布，時得笑言同。"]'),
('c9b97fac-69f5-4b09-af59-e59969077dc0','登樓值雨二首 一','李咸用','唐','唐诗','tang','','["\u5e90\u5c71"]','共訝高樓望，匡廬色已空。',48,'全唐诗/poet.tang.35000.json','["共訝高樓望，匡廬色已空。", "白雲橫野闊，遮嶽與天同。", "數點雨入酒，滿襟香在風。", "遠江吟得出，方下郡齋東。"]'),
('f6b573c8-62f4-4b6b-999b-8658ad52a3d9','登樓值雨二首 二','李咸用','唐','唐诗','tang','','[]','江徼多佳景，秋吟興未窮。',48,'全唐诗/poet.tang.35000.json','["江徼多佳景，秋吟興未窮。", "送來松檻雨，半是蓼花風。", "浪猛驚翹鷺，煙昏叫斷鴻。", "不知今夜客，幾處臥鳴篷。"]'),
('10c8ad77-2a19-46f6-9661-8b23996922a4','送趙舒處士歸廬山','李咸用','唐','唐诗','tang','','["\u5e90\u5c71", "\u6052\u5c71"]','歸岫香鑪碧，行吟步益遲。',48,'全唐诗/poet.tang.35000.json','["歸岫香鑪碧，行吟步益遲。", "諸侯師不得，樵客偶相隨。", "思舊江雲斷，談玄嶽月移。", "秪應張野輩，異代作心知。"]'),
('5d1ebc13-f6cf-4907-bed4-e0a19a60731f','僧院薔薇','李咸用','唐','唐诗','tang','','[]','客引擎茶看，離披曬錦紅。',48,'全唐诗/poet.tang.35000.json','["客引擎茶看，離披曬錦紅。", "不緣開淨域，爭忍負春風。", "小片當吟落，清香入定空。", "何人來此植，應固惱休公。"]'),
('4867c606-50fe-4d38-9db7-c07e52764cb2','友生攜修睦上人詩見訪','李咸用','唐','唐诗','tang','','[]','雪中敲竹戶，袖出岳僧詩。',48,'全唐诗/poet.tang.35000.json','["雪中敲竹戶，袖出岳僧詩。", "語盡景皆活，吟闌角獨吹。", "意如將俗背，業必少人知。", "共約冰銷日，雲邊訪所思。"]'),
('dcf7dfa4-fdc6-4ecb-bd85-e03092339cf8','冬夕喜友生至','李咸用','唐','唐诗','tang','','[]','天涯行欲遍，此夜故人情。',48,'全唐诗/poet.tang.35000.json','["天涯行欲遍，此夜故人情。", "鄉國別來久，干戈還未平。", "燈殘偏有焰，雪甚却無聲。", "多少新聞見，應須語到明。"]'),
('e3dec6a2-8c43-4760-a08e-a9619dfb8e91','牡丹','李咸用','唐','唐诗','tang','','[]','少見南人識，識來嗟復驚。',48,'全唐诗/poet.tang.35000.json','["少見南人識，識來嗟復驚。", "始知春有色，不信爾無情。", "恐是天地媚，暫隨雲雨生。", "緣何絕尤物，更可比妍明。"]'),
('7ccabf20-7fee-4e7c-b4f9-307e5b1ebf62','送春','李咸用','唐','唐诗','tang','','[]','四時爲第一，一歲一重來。',48,'全唐诗/poet.tang.35000.json','["四時爲第一，一歲一重來。", "好景應難勝，餘花虛自開。", "相思九箇月，得信數枝梅。", "不向東門送，還成負酒杯。"]'),
('fed4dece-4776-4243-9b90-0f7d0494c862','送邊將','李咸用','唐','唐诗','tang','','[]','天驕頻犯塞，鐵騎又征西。',48,'全唐诗/poet.tang.35000.json','["天驕頻犯塞，鐵騎又征西。", "臣節輕鄉土，雄心生鼓鼙。", "地寒花不豔，沙遠日難低。", "漸喜秋弓健，鵰翻白草齊。"]'),
('a86d87f4-33bb-4434-8bbd-3a04cbe6d949','春晴','李咸用','唐','唐诗','tang','','[]','簷滴春膏絕，憑欄晚吹生。',48,'全唐诗/poet.tang.35000.json','["簷滴春膏絕，憑欄晚吹生。", "良朋在何處，高樹忽流鶯。", "遊寺期應定，尋芳步已輕。", "新詩吟未穩，遲日又西傾。"]'),
('3158fdcf-4e90-438b-b999-37b423d08756','冬夜與修睦上人宿遠公亭寄南嶽玄泰禪師','李咸用','唐','唐诗','tang','','["\u8861\u5c71"]','丈室掩孤燈，更深霰雹增。',48,'全唐诗/poet.tang.35000.json','["丈室掩孤燈，更深霰雹增。", "相看雲夢客，共憶祝融僧。", "語合茶忘味，吟欹卷有稜。", "楚南山水秀，行止豈無憑。"]'),
('5cef109e-90f7-4734-924f-f81e826a52a6','落花','李咸用','唐','唐诗','tang','','[]','拾得移時看，重思造化功。',48,'全唐诗/poet.tang.35000.json','["拾得移時看，重思造化功。", "如何飄麗景，不似遇春風。", "滿地餘香在，繁枝一夜空。", "秪應公子見，先憶墜樓紅。"]'),
('e79a51a4-95e6-402f-a9ce-81371a5ce938','寄嵩陽隱者','李咸用','唐','唐诗','tang','','["\u5e90\u5c71"]','昔年江上別，初入亂離中。',48,'全唐诗/poet.tang.35000.json','["昔年江上別，初入亂離中。", "我住匡山北，君之少室東。", "信來經險道，詩半憶皇風。", "何事猶高臥，巖邊夢未通。"]'),
('978164b2-cc71-4ee7-b99e-250dbee9f7f5','早蟬','李咸用','唐','唐诗','tang','','[]','門柳不連野，乍聞爲早蟬。',48,'全唐诗/poet.tang.35000.json','["門柳不連野，乍聞爲早蟬。", "遊人無定處，入耳更應先。", "暫默斜陽雨，重吟遠岸煙。", "前年湘竹裏，風激遶離筵。"]'),
('43b75b1a-3a46-4106-89e8-945e7b31d082','酬蘊微','李咸用','唐','唐诗','tang','','[]','白衣經亂世，相遇一開顏。',48,'全唐诗/poet.tang.35000.json','["白衣經亂世，相遇一開顏。", "得句禪思外，論交野步間。", "舉朝無舊識，入眼秪青山。", "幾度斜陽寺，訪君還獨還。"]'),
('1b8a597f-c2ac-4f20-8a68-3876c5d0091f','萱草','李咸用','唐','唐诗','tang','','[]','芳草比君子，詩人情有由。',48,'全唐诗/poet.tang.35000.json','["芳草比君子，詩人情有由。", "秪應憐雅態，未必解忘憂。", "積雨莎庭小，微風蘚砌幽。", "莫言開太晚，猶勝菊花秋。"]'),
('51c51f72-e949-436f-a59b-7f8d0ddb8b8b','訪友人不遇','李咸用','唐','唐诗','tang','','[]','出門無至友，動即到君家。',48,'全唐诗/poet.tang.35000.json','["出門無至友，動即到君家。", "空掩一庭竹，去看何寺花。", "短童應捧杖，稚女學擎茶。", "吟罷留題處，苔階日影斜。"]'),
('720d5d2a-70b8-4f8f-b71d-fdfbed21d56e','苔','李咸用','唐','唐诗','tang','','[]','幾年風雨跡，曡在石孱顏。',48,'全唐诗/poet.tang.35000.json','["幾年風雨跡，曡在石孱顏。", "生處景長靜，看來情儘閑。", "吟亭侵壞壁，藥院掩空關。", "每憶東行徑，移筇獨自還。"]'),
('d7ad8641-b390-46e8-806b-aa9f9e5769aa','紅薇','李咸用','唐','唐诗','tang','','[]','春雨有五色，灑來花旋成。',48,'全唐诗/poet.tang.35000.json','["春雨有五色，灑來花旋成。", "欲留池上景，別染草中英。", "畫出看還欠，蓪爲插未輕。", "王孫多好事，攜酒寄吟傾。"]'),
('f8b14b39-e0f0-410f-9c43-88918e8a2f7c','別所知','李咸用','唐','唐诗','tang','','[]','有路有西東，天涯自恨同。',48,'全唐诗/poet.tang.35000.json','["有路有西東，天涯自恨同。", "却須深酌酒，況不比飄蓬。", "帆冒新秋雨，鼓傳微浪風。", "閏牽寒氣早，何浦值賓鴻。"]'),
('63bbd3d2-eb26-47f1-8aa3-6e012f9ff965','小雪','李咸用','唐','唐诗','tang','','[]','散漫陰風裏，天涯不可收。',48,'全唐诗/poet.tang.35000.json','["散漫陰風裏，天涯不可收。", "壓松猶未得，撲石暫能留。", "閣靜縈吟思，途長拂旅愁。", "崆峒山北面，早想玉成丘。"]'),
('99d23371-41cb-4840-b6b2-4ee068cb1a4d','和修睦上人聽猿','李咸用','唐','唐诗','tang','','[]','禪客聞猶苦，是聲應是啼。',48,'全唐诗/poet.tang.35000.json','["禪客聞猶苦，是聲應是啼。", "自然無穩夢，何必到巴溪。", "疎雨灑不歇，迴風吹暫低。", "此宵秋欲半，山在二林西。"]'),
('ff4b8352-b778-47a2-908f-4213ad72151e','庭竹','李咸用','唐','唐诗','tang','','[]','嫩綠與老碧，森然庭砌中。',48,'全唐诗/poet.tang.35000.json','["嫩綠與老碧，森然庭砌中。", "坐銷三伏景，吟起數竿風。", "葉影重還密，梢聲遠或通。", "更期春共看，桃映小花紅。"]'),
('c73f1743-c1e4-4353-973e-933723f4d058','早行','李咸用','唐','唐诗','tang','','[]','家國三千里，中宵算去程。',48,'全唐诗/poet.tang.35000.json','["家國三千里，中宵算去程。", "困纔成蝶夢，行不待雞鳴。", "馬首搖殘月，鴉羣起古城。", "發來經幾堠，村寺遠鐘聲。"]'),
('10eb553b-117a-42d3-856a-99e94d376742','哭所知','李咸用','唐','唐诗','tang','','[]','朝作青雲士，暮爲玄夜人。',48,'全唐诗/poet.tang.35000.json','["朝作青雲士，暮爲玄夜人。", "風燈無定度，露薤亦逡巡。", "乘馬驚新塚，書帷擺舊塵。", "秪應從此去，何處福生民。"]'),
('76a4e88d-6f6c-4011-8172-2e1088a2b126','分題雪霽望爐峰','李咸用','唐','唐诗','tang','','[]','雪霽上庭除，爐峰勢轉孤。',48,'全唐诗/poet.tang.35000.json','["雪霽上庭除，爐峰勢轉孤。", "略無煙作帶，獨有影沈湖。", "冷觸歸鴻急，明凝落照俱。", "□□□□□，□□□□□。"]'),
('9a58eafd-bfd1-4fbf-9c30-e0cb153dadb0','雪十二韻','李咸用','唐','唐诗','tang','','[]','六出凝陰氣，同雲指上天。',144,'全唐诗/poet.tang.35000.json','["六出凝陰氣，同雲指上天。", "結時風乍急，集處霰長先。", "草穗翹祥燕，陂樁吐白蓮。", "犬狂南陌上，竹醉小池前。", "樵徑花黏履，漁舟玉帖舷。", "陣經暘谷薄，勢想朔方偏。", "樓面光搖錫，籬頭曉列錢。", "石苔青鹿臥，殿網素蛾穿。", "嘶馬應思塞，蹲烏似爲燕。", "童癡爲獸揑，僧愛用茶煎。", "念物希周穆，含毫愧惠連。", "吟闌餘興逸，還憶剡溪船。"]'),
('411ff059-1d88-4da8-bf72-efedfefa833f','廬山','李咸用','唐','唐诗','tang','','["\u5e90\u5c71"]','非嶽不言嶽，此山通嶽言。',240,'全唐诗/poet.tang.35000.json','["非嶽不言嶽，此山通嶽言。", "高人居亂世，幾處滿前軒。", "秀作神仙宅，靈爲風雨根。", "餘陰鋪楚甸，一柱表吳門。", "靜得八公侶，雄臨九子尊。", "對猶青熨眼，到必冷凝魂。", "勢受重湖讓，形難七澤吞。", "黑巖藏晝電，紫霧泛朝暾。", "蓮墮寧唯華，玉焚堪小崑。", "倒松微發罅，飛瀑遠成痕。", "曡見雲容襯，稜收雪氣昏。", "裁詩曾困謝，作賦偶無孫。", "流礙星光撇，驚衝雁陣翻。", "峰奇寒倚劍，泉曲旋如盆。", "草短分雛雉，林明露擲猿。", "秋楓紅葉散，春石谷雷奔。", "月好虎溪路，煙深栗里源。", "醉吟長易醒，夢去亦銷煩。", "有覺南方重，無疑厚地掀。", "輕揚聞舊俗，端用鎮元元。"]'),
('1e32cb5d-fe81-4b60-b4b1-c786cc487cdf','和吳處士題村叟壁','李咸用','唐','唐诗','tang','','[]','因閱鄉居景，歸心寸火然。',240,'全唐诗/poet.tang.35000.json','["因閱鄉居景，歸心寸火然。", "吾家依碧嶂，小檻枕清川。", "遠雨籠孤戍，斜陽隔斷煙。", "沙虛遺虎跡，水洑聚蛟涎。", "糲麴芟汀蓼，甘茶挈石泉。", "霜朝巡栗樹，風夜探漁船。", "戲日魚呈腹，翹灘鷺並肩。", "碁尋盤石淨，酒傍野花妍。", "器以鋤爲利，家惟竹直錢。", "飯香同豆熟，湯暖摘松煎。", "睡島鳧藏足，攀藤狖凍拳。", "淺茅鳴鬬雉，曲枿嘯寒鳶。", "秋果𣙁梨澀，晨羞笋蕨鮮。", "衣蓑留冷閣，席草種閑田。", "椎髻擔餔餉，龐眉識稔年。", "嚇鷹芻戴笠，驅犢篠充鞭。", "不重官於社，常尊食作天。", "谷深青靄蔽，峰迥白雲纏。", "每憶關魂夢，長誇表愛憐。", "覽君書壁句，誘我率成篇。"]'),
('b2883592-eaf5-47a2-bd3d-7ded35fda71a','謝友生遺端溪硯瓦','李咸用','唐','唐诗','tang','','[]','尋常濡翰次，恨不到端溪。',240,'全唐诗/poet.tang.35000.json','["尋常濡翰次，恨不到端溪。", "得自新知己，如逢舊解攜。", "翫餘輕照乘，謝欲等懸黎。", "靜對勝凡客，閑窺憶好題。", "媧天補剩石，昆劍切來泥。", "著指痕猶濕，停旬水未低。", "呵雲潤柱礎，筆彩飲虹霓。", "鵒眼工諳謬，羊肝士乍刲。", "連澌光比鏡，囚墨膩於䃜。", "書信成池黑，吟須到日西。", "正誇憂盜竊，將隱怯攀躋。", "捧受同交印，矜持過秉珪。", "草顛終近旭，嬾癖必無嵇。", "用合緣鸚鵡，珍應負會稽。", "貞姿還落落，寒韻或淒淒。", "風月情相半，煙花思豈迷。", "宜從方袋挈，枉把短行批。", "淺小金爲斗，泓澄玉作堤。", "遇人依我惜，想爾與天齊。", "□□□□□，行時秪獨齎。"]'),
('d1160324-9771-4072-aba9-2d1c31cb3e76','和殷衙推春霖即事','李咸用','唐','唐诗','tang','','[]','東風吹暖雨，潤下不能休。',240,'全唐诗/poet.tang.35000.json','["東風吹暖雨，潤下不能休。", "古道雲橫白，移時客共愁。", "綠沈莎似藻，紅泛葉爲舟。", "忽起江湖興，疑鄰畎澮流。", "此時無勝會，何處滯奇遊？", "陣急如酣戰，點麤成亂漚。", "竹因添灑落，松得長颼飀。", "花慘閑庭晚，蘭深曲徑幽。", "絲牽汀鳥足，線挂嶽猿頭。", "天地昏同醉，寰區浩欲浮。", "柳眉低帶泣，蒲劍銳初抽。", "石燕飜空重，蟲羅綴滴稠。", "荷傾蛟淚盡，巖拆電鞭收。", "豈直望堯喜，却懷微禹憂。", "樹滋堪採菌，磯沒懶垂鈎。", "腥覺聞龍氣，寒宜擁豹裘。", "名膏那作沴，思稔必通侯。", "蚌鷸徒喧競，笙歌罷獻酬。", "山川藏秀媚，草木逞調柔。", "極目非吾意，行吟獨下樓。"]'),
('e1eb5b40-1b74-4c68-b5b2-769cf0826dd8','題陳將軍別墅','李咸用','唐','唐诗','tang','','[]','明王獵士猶疎在，巖谷安居最有才。',64,'全唐诗/poet.tang.35000.json','["明王獵士猶疎在，巖谷安居最有才。", "高虎壯言知鬼伏，葛龍閑臥待時來。", "雲藏山色晴還媚，風約溪聲靜又迴。", "不獨春光堪醉客，庭除長見好花開。"]'),
('0e4e4190-3c5e-4234-a828-2c8608dfc343','湘浦有懷','李咸用','唐','唐诗','tang','','[]','鴻雁哀哀背朔方，餘霞倒影畫瀟湘。',64,'全唐诗/poet.tang.35000.json','["鴻雁哀哀背朔方，餘霞倒影畫瀟湘。", "長汀細草愁春浪，古渡寒花倚夕陽。", "鬼樹夜分千炬火，漁舟朝巷一蓬霜。", "儂家本是持竿者，爲愛明時入帝鄉。"]'),
('7c32eeaf-fa61-44ce-8e59-8487d19e18ea','題陳處士山居','李咸用','唐','唐诗','tang','','[]','蓮遶閑停柳遶池，蟬吟暮色一枝枝。',64,'全唐诗/poet.tang.35000.json','["蓮遶閑停柳遶池，蟬吟暮色一枝枝。", "未逢皇澤搜遺逸，贏得青山避亂離。", "花圃春風邀客醉，茅簷秋雨對僧碁。", "樵童牧豎勞相問，巖穴從來出帝師。"]'),
('432e8516-22fb-41fa-b79c-5b3e5ce897ef','和蔣進士秋日','李咸用','唐','唐诗','tang','','[]','晚雨霏微思杪秋，不堪才子尚羇遊。',64,'全唐诗/poet.tang.35000.json','["晚雨霏微思杪秋，不堪才子尚羇遊。", "塵隨別騎東西急，波促年華日夜流。", "涼月雲開光自遠，古松風在韻難休。", "男兒但得功名立，縱是深恩亦易酬。"]'),
('eb17d113-a2f4-47aa-bdbd-4b4ff1cadfb6','陳正字山居','李咸用','唐','唐诗','tang','','[]','一葉閑飛斜照裏，江南仲蔚在蓬蒿。',64,'全唐诗/poet.tang.35000.json','["一葉閑飛斜照裏，江南仲蔚在蓬蒿。", "天衢雲險駑駘蹇，月桂風和夢想勞。", "遶枕泉聲秋雨細，對門山色古屏高。", "此中即是神仙地，引手何妨一釣鼇。"]'),
('125cba28-01d4-43f8-b9b1-acdfb4f82e0d','與劉三禮陳孝廉言志','李咸用','唐','唐诗','tang','','[]','真宰無私造化均，年年分散月中春。',64,'全唐诗/poet.tang.35000.json','["真宰無私造化均，年年分散月中春。", "皆期早躡青雲路，誰肯長爲白社人。", "宋國高風休斂翼，聖朝公道易酬身。", "大須審固穿楊箭，莫遣參差鬢雪新。"]'),
('91e5f4da-754c-4268-a8e3-072da60ba37f','秋日送嚴湘侍御歸京','李咸用','唐','唐诗','tang','','[]','蟾影珪圓湖始波，楚人相別恨偏多。',64,'全唐诗/poet.tang.35000.json','["蟾影珪圓湖始波，楚人相別恨偏多。", "知君有路昇霄漢，獨我無由出薜蘿。", "雖道危時難進取，到逢清世又如何。", "誰聽甯戚敲牛角，月落星稀一曲歌。"]'),
('74451b27-b85a-4856-b4fe-86f45bbe545f','題王處士山居','李咸用','唐','唐诗','tang','','[]','雲木沈沈夏亦寒，此中幽隱幾經年。',64,'全唐诗/poet.tang.35000.json','["雲木沈沈夏亦寒，此中幽隱幾經年。", "無多別業供王稅，大半生涯在釣船。", "蜀魄呌迴芳草色，鷺鷥飛破夕陽煙。", "干戈蝟起能高臥，只箇逍遙是謫仙。"]'),
('64b089aa-cb0f-401b-9aab-2067825e8b52','謝所知','李咸用','唐','唐诗','tang','','[]','狂歌狂舞慰風塵，心下多端亦嬾言。',64,'全唐诗/poet.tang.35000.json','["狂歌狂舞慰風塵，心下多端亦嬾言。", "早是亂離輕歲月，誰能愁悴過朝昏。", "聖朝公道如長在，賤子謀身自有門。", "却愧此時叨厚遇，他年何以報深恩。"]'),
('6ae7f452-3573-4dac-8db4-11f0d6c266c0','秋望','李咸用','唐','唐诗','tang','','[]','雲陰慘澹柳陰稀，遊子天涯一望時。',64,'全唐诗/poet.tang.35000.json','["雲陰慘澹柳陰稀，遊子天涯一望時。", "風閃雁行疎又密，地迴江勢急還遲。", "榮枯物理終難測，貴賤人生自不知。", "未達誰能多歎息，塵埃爭損得男兒。"]'),
('9a3d2235-89e3-44f2-bd33-78817a0663f5','送譚孝廉赴舉','李咸用','唐','唐诗','tang','','[]','鼓鼙聲裏尋詩禮，戈戟林間入鎬京。',64,'全唐诗/poet.tang.35000.json','["鼓鼙聲裏尋詩禮，戈戟林間入鎬京。", "好事盡從難處得，少年無向易中輕。", "也知貴賤皆前定，未見疎慵遂有成。", "吾道近來稀後進，善開金口荅公卿。"]'),
('8d30f3cb-bc81-4c58-a337-ebf6a7a5a038','途中逢友人','李咸用','唐','唐诗','tang','','[]','大道將窮阮籍哀，紅塵深翳步遲迴。',64,'全唐诗/poet.tang.35000.json','["大道將窮阮籍哀，紅塵深翳步遲迴。", "皇天有意自寒暑，白日無情空往來。", "霄漢何年徵賦客，煙花隨處作愁媒。", "相逢且快眼前事，莫厭狂歌酒百杯。"]'),
('209f6854-65c7-49b4-bd58-4abe2f99bf6f','和人湘中作','李咸用','唐','唐诗','tang','','[]','湘川湘岸兩荒涼，孤雁號空動旅腸。',64,'全唐诗/poet.tang.35000.json','["湘川湘岸兩荒涼，孤雁號空動旅腸。", "一棹寒波思范蠡，滿尊醇酒憶陶唐。", "年華蒲柳凋衰鬢，身跡萍蓬滯別鄉。", "不及東流趨廣漢，臣心日夜與天長。"]'),
('c10a1168-f269-43a4-98a9-4a809cd207fc','贈陳望堯','李咸用','唐','唐诗','tang','','[]','若說精通事藝長，詞人爭及孝廉郎。',64,'全唐诗/poet.tang.35000.json','["若說精通事藝長，詞人爭及孝廉郎。", "秋螢短焰難盈案，鄰燭餘光不滿行。", "鵠箭親疎雖異的，桂花高下一般香。", "明時公道還堪信，莫遣錐鋒久在囊。"]'),
('052aa241-7857-4f7d-bcf4-3f1aac9f5dd4','宿漁家','李咸用','唐','唐诗','tang','','[]','促杼聲繁螢影多，江邊秋興獨難過。',64,'全唐诗/poet.tang.35000.json','["促杼聲繁螢影多，江邊秋興獨難過。", "雲遮月桂幾枝恨，煙罩漁舟一曲歌。", "難世斯人雖隱遁，明時公道復如何。", "陶家壁上精靈物，風雨未來終是梭。"]'),
('a82a1a80-0ef8-4327-b909-f7e9a884364d','旅館秋夕','李咸用','唐','唐诗','tang','','[]','牢落生涯在水鄉，只思歸去泛滄浪。',64,'全唐诗/poet.tang.35000.json','["牢落生涯在水鄉，只思歸去泛滄浪。", "秋風螢影隨高柳，夜雨蛬聲上短牆。", "百歲易爲成荏苒，丹霄誰肯借梯航。", "若教名路無知己，匹馬塵中是自忙。"]'),
('af3091ce-59cc-44a4-ba92-8673a114b33a','悼范攄處士','李咸用','唐','唐诗','tang','','[]','家在五雲溪畔住，身遊巫峽作閑人。',64,'全唐诗/poet.tang.35000.json','["家在五雲溪畔住，身遊巫峽作閑人。", "安車未至柴關外，片玉已藏墳土新。", "雖有公卿聞姓字，惜無知己脫風塵。", "到頭積善成何事，天地茫茫秋又春。"]'),
('7e7c6b03-f6d5-4998-b653-0fc7d31abffd','送人','李咸用','唐','唐诗','tang','','[]','一軸煙花滿口香，諸侯相見肯相忘。',64,'全唐诗/poet.tang.35000.json','["一軸煙花滿口香，諸侯相見肯相忘。", "未聞珪璧爲人棄，莫倦江山去路長。", "盈耳暮蟬催別騎，數杯浮蟻咽離腸。", "眼前多少難甘事，自古男兒當自強。"]'),
('b4210c74-a311-49ed-aa4c-6a97d6553958','春暮途中','李咸用','唐','唐诗','tang','','[]','細雨如塵散暖空，數峰春色在雲中。',64,'全唐诗/poet.tang.35000.json','["細雨如塵散暖空，數峰春色在雲中。", "須知觸目皆成恨，縱道多文爭那窮。", "飛燕有情依舊閣，垂楊無力受東風。", "誰能會得乾坤意，九土枯榮自不同。"]'),
('78793102-a478-4ae8-a447-5f4ce25f846c','題陳正字林亭','李咸用','唐','唐诗','tang','','[]','曉煙輕翠拂簾飛，黃葉飄零弄所思。',64,'全唐诗/poet.tang.35000.json','["曉煙輕翠拂簾飛，黃葉飄零弄所思。", "正是低摧吾道日，不堪惆悵異鄉時。", "家林蛇豕方羣起，宮沼龜龍未有期。", "賴有平原憐賤子，滿亭山色借吟詩。"]'),
('948c0c60-ff9d-4a6e-a175-26e45d8d1ad1','送從兄入京','李咸用','唐','唐诗','tang','','[]','柳轉春心梅豔香，相看江上恨何長。',64,'全唐诗/poet.tang.35000.json','["柳轉春心梅豔香，相看江上恨何長。", "多情流水引歸思，無賴嚴風促別觴。", "大抵男兒須振奮，近來時事懶思量。", "雲帆高挂一揮手，目送煙霄雁斷行。"]'),
('a6de302a-f94f-49c4-9955-9259a28a3f68','秋夕書懷寄所知','李咸用','唐','唐诗','tang','','[]','秋螢一點雨中飛，獨立黃昏思所知。',64,'全唐诗/poet.tang.35000.json','["秋螢一點雨中飛，獨立黃昏思所知。", "三島路遙身汩沒，九天風急羽差池。", "年華逐浪催霜髪，旅恨和雲拂桂知。", "不向故人言此事，異鄉誰更念棲遲。"]'),
('bd77f37b-09c8-4862-860c-3454f47799f7','酬進士秦顒若','李咸用','唐','唐诗','tang','','[]','鶯默平林燕別軒，相逢相笑話生前。',64,'全唐诗/poet.tang.35000.json','["鶯默平林燕別軒，相逢相笑話生前。", "低飛旅恨看霜葉，曲寫歸情向暮川。", "在野孤雲終捧日，朝宗高浪本蒙泉。", "何勞悵望風雷便，且混魚龍黷武年。"]'),
('c995598e-1fef-45bf-afce-21f495a68375','山中夜坐寄故里友生','李咸用','唐','唐诗','tang','','[]','展轉簷前睡不成，一牀山月竹風清。',64,'全唐诗/poet.tang.35000.json','["展轉簷前睡不成，一牀山月竹風清。", "蟲聲促促催鄉夢，桂影高高挂旅情。", "禍福既能知倚伏，行藏爭不要分明。", "可憐任永真堅白，淨洗雙眸看太平。"]'),
('0666b456-7af2-4b9e-b1e4-9f5413adbd8f','物情','李咸用','唐','唐诗','tang','','[]','誰分萬類二儀間，稟性高卑各自然。',48,'全唐诗/poet.tang.35000.json','["誰分萬類二儀間，稟性高卑各自然。", "野鶴不棲蔥蒨樹，流鶯長喜豔陽天。", "李斯溷鼠心應動，莊叟泥龜意已堅。"]'),
('69d79950-c3ac-4dd4-bb8e-9faa98b49c6a','金谷園','李咸用','唐','唐诗','tang','','[]','石家舊地聊登望，寵辱從茲信可驚。',64,'全唐诗/poet.tang.35000.json','["石家舊地聊登望，寵辱從茲信可驚。", "鳥度野花迷錦障，蟬吟古樹想歌聲。", "雖將玉貌同時死，却羨蒼頭此日生。", "多積黃金買刑戮，千秋成得綠珠名。"]'),
('7f8e7dbb-8843-4bdd-a96b-cbcb8769342b','投所知','李咸用','唐','唐诗','tang','','[]','手欠東堂桂一枝，家書不敢便言歸。',64,'全唐诗/poet.tang.35000.json','["手欠東堂桂一枝，家書不敢便言歸。", "挂簷晚雨思山閣，拂岸煙嵐憶釣磯。", "公道甚平才自薄，丹霄好上力猶微。", "誰能借與摶扶勢，萬里飄飄試一飛。"]'),
('3ad50331-066f-4bbc-bb4e-8c4e3e2ea3fe','贈友弟','李咸用','唐','唐诗','tang','','[]','螢焰燒心雪眼勞，未逢佳夢見三刀。',64,'全唐诗/poet.tang.35000.json','["螢焰燒心雪眼勞，未逢佳夢見三刀。", "他時詎有鹽梅味，今日猶疑腹背毛。", "金埒曉羇千里駿，玉輪寒養一枝高。", "誰能終歲搖頳尾，唯唯洋洋向碧濤。"]'),
('cc6847e2-8cbc-4c4e-a033-6a8b5b3a1859','春日喜逢鄉人劉松','李咸用','唐','唐诗','tang','','[]','故人不見五春風，異地相逢嶽影中。',64,'全唐诗/poet.tang.35000.json','["故人不見五春風，異地相逢嶽影中。", "舊業久拋耕釣侶，新聞多說戰爭功。", "生民有恨將誰訴，花木無情秪自紅。", "莫把少年愁過日，一尊須對夕陽空。"]'),
('efe38507-b079-4ba5-8d9a-bcb354b8f997','夏日別余秀才','李咸用','唐','唐诗','tang','','[]','嶽麓雲深麥雨秋，滿傾杯酒對湘流。',64,'全唐诗/poet.tang.35000.json','["嶽麓雲深麥雨秋，滿傾杯酒對湘流。", "沙邊細柳牽行色，水面輕煙畫別愁。", "敢待傅巖成好夢，任從磻石挂纖鈎。", "鏡機沖漠非吾事，自要青雲識五侯。"]'),
('41baaaab-186e-4e02-a509-04a280ff65ac','廬陵九日','李咸用','唐','唐诗','tang','','[]','菊花山在碧江東，冷酒清吟興莫窮。',64,'全唐诗/poet.tang.35000.json','["菊花山在碧江東，冷酒清吟興莫窮。", "四十三年秋裏過，幾多般事亂來空。", "雖驚故國音書絕，猶喜新知語笑同。", "竟日開門無客至，笛聲迢逓夕陽中。"]'),
('3b12b807-49a5-40b3-9490-96ac981e87d3','和人遊東林','李咸用','唐','唐诗','tang','','[]','一從張野臥雲林，勝概誰人更解尋。',64,'全唐诗/poet.tang.35000.json','["一從張野臥雲林，勝概誰人更解尋。", "黃鳥不能言往事，白蓮虛發至如今。", "年年上國榮華夢，世世高流水石心。", "始欲共君重悵望，紫霄峰外日沈沈。"]'),
('e6587eda-dc75-4044-b031-3126116ac0f6','和彭進士秋日遊靖居山寺','李咸用','唐','唐诗','tang','','[]','秋山入望已無塵，況得閑遊謝事頻。',64,'全唐诗/poet.tang.35000.json','["秋山入望已無塵，況得閑遊謝事頻。", "問著盡能言祖祖，見時應不是真真。", "添瓶野水遮還急，伴塔幽花落又新。", "自笑未曾同逸步，終非宗炳社中人。"]'),
('2ec90340-a1fe-4c02-9fc7-bf06b5767c08','和彭進士感懷','李咸用','唐','唐诗','tang','','[]','人生誰肯便甘休，遇酒逢花且共遊。',64,'全唐诗/poet.tang.35000.json','["人生誰肯便甘休，遇酒逢花且共遊。", "若向雲衢陪驥尾，直須天畔落旄頭。", "三編大雅曾關興，一冊南華旋解憂。", "四海英雄多獨斷，不知何者是長籌。"]'),
('d19a4463-4990-490a-bc1c-320be0d652ac','寄題從兄坤載村居','李咸用','唐','唐诗','tang','','[]','鄰並無非樵釣者，莊生物論宛然齊。',64,'全唐诗/poet.tang.35000.json','["鄰並無非樵釣者，莊生物論宛然齊。", "雨中寒樹愁鴟立，江上殘陽瘦馬嘶。", "說與衆傭同版築，呂將羣叟共磻溪。", "覆巢破卵方堪懼，取次梧桐鳳且棲。"]'),
('28ea38b1-4bf1-4852-a60f-2e62bb278139','送黃賓于赴舉','李咸用','唐','唐诗','tang','','[]','秋風昨夜滿瀟湘，衰柳殘蟬思客腸。',64,'全唐诗/poet.tang.35000.json','["秋風昨夜滿瀟湘，衰柳殘蟬思客腸。", "早是亂來無勝事，更堪江上揖離觴。", "澄潭躍鯉搖輕浪，落日飛鳧趁遠檣。", "漁父不須探去意，一枝春褭月中央。"]'),
('1bcb0fee-a4f0-4119-a840-44912947fdca','冬日喜逢吳價','李咸用','唐','唐诗','tang','','[]','垂楊煙薄井梧空，千里遊人駐斷蓬。',64,'全唐诗/poet.tang.35000.json','["垂楊煙薄井梧空，千里遊人駐斷蓬。", "志意不因多事改，鬢毛難與別時同。", "鶯遷猶待銷冰日，鵬起還思動海風。", "窮達他年如賦命，且陶真性一杯中。"]'),
('76721884-eab0-4a51-899a-619a410b0fdd','題劉處士居','李咸用','唐','唐诗','tang','','[]','壓破嵐光半畝餘，竹軒蘭砌共清虛。',64,'全唐诗/poet.tang.35000.json','["壓破嵐光半畝餘，竹軒蘭砌共清虛。", "泉經小檻聲長急，月過修篁影旋疎。", "溪鳥時時窺戶牖，山雲往往宿庭除。", "干戈謾道因天意，渭水高人自釣魚。"]'),
('bab6d601-d98b-465f-bed6-95de6d2bfbe9','送李尊師歸臨川','李咸用','唐','唐诗','tang','','[]','蟠桃一別幾千春，謫下人間作至人。',64,'全唐诗/poet.tang.35000.json','["蟠桃一別幾千春，謫下人間作至人。", "塵外煙霞吟不盡，鼎中龍虎伏初馴。", "除存紫府無他意，終向青冥舉此身。", "辭我麻姑山畔去，蔡經蹤跡必相親。"]'),
('90a7228c-0203-469d-a757-f79899f4a0ba','投知','李咸用','唐','唐诗','tang','','[]','西望長安路幾千，遲回不爲別家難。',64,'全唐诗/poet.tang.35000.json','["西望長安路幾千，遲回不爲別家難。", "酌量才地心雖動，點檢囊裝意又闌。", "自是遠人多蹇滯，近來仙牓半孤寒。", "嘶風重訴牽鹽恥，伯樂何妨轉眼看。"]'),
('d3985cfe-ee56-4b06-bd3c-310d5ee11bb3','吳處士寄香兼勸入道','李咸用','唐','唐诗','tang','','[]','謝寄精專一捻香，勸予朝禮仕虛皇。',64,'全唐诗/poet.tang.35000.json','["謝寄精專一捻香，勸予朝禮仕虛皇。", "須知十極皆臣妾，豈止遺生奉混茫。", "空挂黃衣寧續壽，曾聞玄教在知常。", "但居平易俟天命，便是長生不死鄉。"]'),
('9a398735-4aa0-493a-b09d-5f9f1105fe4b','草蟲','李咸用','唐','唐诗','tang','','[]','如繰如織暮㗀㗀，應節催年使我愁。',64,'全唐诗/poet.tang.35000.json','["如繰如織暮㗀㗀，應節催年使我愁。", "行客語停孤店月，高人夢斷一牀秋。", "風低蘚徑疑偏急，雨咽槐亭得暫休。", "須付畫堂蘭燭畔，歌懷醉耳兩悠悠。"]'),
('da3cefc6-f2e8-4f56-ad36-7f1de6437964','詠柳','李咸用','唐','唐诗','tang','','[]','日近煙饒還有意，東垣西掖幾千株。',64,'全唐诗/poet.tang.35000.json','["日近煙饒還有意，東垣西掖幾千株。", "牽仍別恨知難盡，誇衒春光恐更無。", "解引人情長婉約，巧隨風勢強盤紆。", "天應繡出繁華景，處處茸絲惹路衢。"]'),
('0fac2f86-3808-453b-803b-3f5d3e2722f7','寄所知','李咸用','唐','唐诗','tang','','[]','曾將俎豆爲兒戲，爭奈干戈阻素心。',64,'全唐诗/poet.tang.35000.json','["曾將俎豆爲兒戲，爭奈干戈阻素心。", "遁去不同秦客逐，病來還作越人吟。", "名流古集典衣買，僻寺奇花貰酒尋。", "從道趣時身計拙，如非所好肯開襟。"]'),
('9b71846e-8e13-439b-b1aa-7580b8b9f9fa','雪','李咸用','唐','唐诗','tang','','[]','上帝無私意甚微，欲教霖雨更光輝。',64,'全唐诗/poet.tang.35000.json','["上帝無私意甚微，欲教霖雨更光輝。", "也知出處花相似，可到貧家影便稀。", "雲漢風多銀浪濺，崑山火後玉灰飛。", "高樓四望吟魂斂，却憶明皇月殿歸。"]'),
('36d2231e-be26-4876-b0ef-13c830e97c3b','緋桃花','李咸用','唐','唐诗','tang','','[]','茫茫天意爲誰留，深染夭桃備勝遊。',64,'全唐诗/poet.tang.35000.json','["茫茫天意爲誰留，深染夭桃備勝遊。", "未醉已知醒後憶，欲開先爲落時愁。", "癡蛾亂撲燈難滅，躍鯉傍驚電不收。", "何事梨花空似雪，也稱春色是悠悠。"]'),
('6644c8b3-782a-4a91-8b9e-1eac1cb6f12c','同友人秋日登庾樓','李咸用','唐','唐诗','tang','','[]','蘭摧菊暗不勝秋，倚著高樓思莫收。',64,'全唐诗/poet.tang.35000.json','["蘭摧菊暗不勝秋，倚著高樓思莫收。", "六代風光無問處，九條煙水但凝愁。", "誰能百歲長閑去，秪箇孤帆豈自由。", "欲學仲宣知是否，臂弓腰劍逐時流。"]'),
('4f48e71d-3783-4c0c-a66c-450dea55d1d4','和人詠雪','李咸用','唐','唐诗','tang','','[]','輕輕玉疊向風加，襟袖誰能認六葩。',48,'全唐诗/poet.tang.35000.json','["輕輕玉疊向風加，襟袖誰能認六葩。", "高岫人迷千尺布，平林天與一般花。", "橫空絡繹雲遺屑，撲浪翩聯蝶寄槎。"]'),
('2515bdbf-6c1a-4c24-b5e3-7ff748c8637d','和友人喜相遇十首 一','李咸用','唐','唐诗','tang','','[]','爲儒自愧已多年，文賦歌詩路不專。',64,'全唐诗/poet.tang.35000.json','["爲儒自愧已多年，文賦歌詩路不專。", "肯信披沙難見寶，只憐苫草易成編。", "燕昭寤寐常求駿，郭隗尋思未是賢。", "且固初心希一試，箭穿正鵠豈無緣。"]'),
('97fc5305-98c0-47b7-9f79-dc04792bd816','和友人喜相遇十首 二','李咸用','唐','唐诗','tang','','[]','揣情摩意已無功，只把篇章助國風。',64,'全唐诗/poet.tang.35000.json','["揣情摩意已無功，只把篇章助國風。", "宋玉謾誇雲雨會，謝連寧許夢魂通。", "愁成旅鬢千絲亂，吟得寒缸短焰終。", "難世好居郊野地，出門常喜與人同。"]'),
('2f35ca8f-b01e-41f8-b894-b19abf0e5179','和友人喜相遇十首 三','李咸用','唐','唐诗','tang','','[]','惠子休驚學五車，沛公方起斬長蛇。',64,'全唐诗/poet.tang.35000.json','["惠子休驚學五車，沛公方起斬長蛇。", "六雄互欲吞諸國，四海終須作一家。", "自古經綸成世務，暫時朱綠比朝霞。", "人生心口宜相副，莫使堯階草勢斜。"]'),
('5d6a37a7-f911-4c0a-b6d2-bba42aa374d8','和友人喜相遇十首 四','李咸用','唐','唐诗','tang','','[]','不傍江煙訪所思，更應無處展愁眉。',64,'全唐诗/poet.tang.35000.json','["不傍江煙訪所思，更應無處展愁眉。", "數杯竹閣花殘酒，一局松窗日午碁。", "多病却疑天與便，自愚潛喜衆相欺。", "非窮非達非高尚，冷笑行藏秪獨知。"]'),
('0d5a26cf-e3e6-48e9-9167-8ae2e35ca957','和友人喜相遇十首 五','李咸用','唐','唐诗','tang','','[]','閑吟閑坐道相應，遠想南華亦自矜。',64,'全唐诗/poet.tang.35000.json','["閑吟閑坐道相應，遠想南華亦自矜。", "拋擲家鄉輕似夢，尋常心地冷於僧。", "和羹使用非胥靡，憶鱠言詞小季鷹。", "唯仗十篇金玉韻，此中高旨莫階升。"]'),
('b34f8cde-a7c4-4ea5-b692-f75855cb5511','和友人喜相遇十首 六','李咸用','唐','唐诗','tang','','[]','已向丘門老此軀，可堪空作小人儒。',64,'全唐诗/poet.tang.35000.json','["已向丘門老此軀，可堪空作小人儒。", "吟中景象千般有，書外囊裝一物無。", "潤屋必能知早散，輝山應是不輕沽。", "短衣寧倦重修謁，誰識高陽舊酒徒。"]'),
('3a234084-1e40-48d2-972c-da2c28c09dba','和友人喜相遇十首 七','李咸用','唐','唐诗','tang','','[]','松桂寒多衆木分，輕浮如葉自紛紜。',64,'全唐诗/poet.tang.35000.json','["松桂寒多衆木分，輕浮如葉自紛紜。", "韶咸古曲教誰愛，山水清音喜獨聞。", "上國共知傳大寶，舊交寧復在青雲。", "相逢莫厭杯中酒，同醉同醒秪有君。"]'),
('1b0319d5-b430-485e-86f9-a959e3d01e91','和友人喜相遇十首 八','李咸用','唐','唐诗','tang','','[]','還淳反朴已難期，依德依仁敢暫違。',64,'全唐诗/poet.tang.35000.json','["還淳反朴已難期，依德依仁敢暫違。", "寡欲自應剛正立，無私翻覺友朋稀。", "旄頭影莫侵黃道，傅說星終近紫微。", "年紀少他蘧伯玉，幸因多難早知非。"]'),
('9205aa66-906c-48fe-8f50-c297bc508283','和友人喜相遇十首 九','李咸用','唐','唐诗','tang','','[]','麻衣未識帝城塵，四十爲儒是病身。',64,'全唐诗/poet.tang.35000.json','["麻衣未識帝城塵，四十爲儒是病身。", "有恨不關銜國恥，無愁直爲倚家貧。", "齊輕東海二高士，漢重商山四老人。", "一種愛閑閑不得，混時行止却應真。"]'),
('de117886-eef6-490e-bb04-4eb0e1d58232','和友人喜相遇十首 十','李咸用','唐','唐诗','tang','','[]','任說天長海影沈，友朋情比未爲深。',64,'全唐诗/poet.tang.35000.json','["任說天長海影沈，友朋情比未爲深。", "唯應樂處無虛日，大半危時得道心。", "命達夭殤同白首，價高甎瓦即黃金。", "他年有要玄珠者，赤水縈紆試一尋。"]'),
('67c7423b-14be-44f2-bddc-bfa358422cea','依韻修睦上人山居十首 一','李咸用','唐','唐诗','tang','','[]','生身便在亂離間，遇柳尋花作麽看。',64,'全唐诗/poet.tang.35000.json','["生身便在亂離間，遇柳尋花作麽看。", "老去轉諳無是事，本來何處有多般。", "長憐蠛蠓能隨暖，獨笑梧桐不耐寒。", "覆載我徒爭會得，大鵬飛尚未知寬。"]'),
('cee945d0-c713-442f-b914-123d6ec0dd6b','依韻修睦上人山居十首 二','李咸用','唐','唐诗','tang','','[]','雲泉日日長松寺，絲管年年細柳營。',64,'全唐诗/poet.tang.35000.json','["雲泉日日長松寺，絲管年年細柳營。", "靜躁殊途知自識，榮枯一貫亦何爭。", "道傍病樹人從老，溪上新苔我獨行。", "若見淨名居士語，逍遙全不讓莊生。"]'),
('479b6c5c-d1f0-4d28-a6f6-772e1c275ea7','依韻修睦上人山居十首 三','李咸用','唐','唐诗','tang','','[]','莫言天道終難定，須信人心盡自輕。',64,'全唐诗/poet.tang.35000.json','["莫言天道終難定，須信人心盡自輕。", "宣室三千雖有恨，成周八百豈無情。", "栢緣執性長時瘦，梅爲多知兩番生。", "不是不同明主意，嬾將脣舌與齊烹。"]'),
('bf4843e4-1757-4ca8-a9f8-20e43aa297dc','依韻修睦上人山居十首 四','李咸用','唐','唐诗','tang','','[]','不論軒冕及漁樵，性與情違漸漸遙。',64,'全唐诗/poet.tang.35000.json','["不論軒冕及漁樵，性與情違漸漸遙。", "季子禍從憐富貴，顏生道在樂簞瓢。", "清閑自可齊三壽，忿恨還須戒一朝。", "好學堯民偎舜日，短裁孤竹理雲韶。"]'),
('9ad8e520-0ef3-4eca-8a5c-5792a9133a72','依韻修睦上人山居十首 五','李咸用','唐','唐诗','tang','','[]','春風春雨一何頻，望極空江覺損神。',64,'全唐诗/poet.tang.35000.json','["春風春雨一何頻，望極空江覺損神。", "鶯有來由重入谷，柳無情緒強依人。", "漢庭謁者休言事，魯國諸生莫問津。", "賴是水鄉樗櫟賤，滿爐紅焰且相親。"]'),
('eefbb5ce-bebf-48bf-b2bb-9a9b0079e8f1','依韻修睦上人山居十首 六','李咸用','唐','唐诗','tang','','["\u5e90\u5c71"]','三十年來要自觀，履春冰恐未爲難。',64,'全唐诗/poet.tang.35000.json','["三十年來要自觀，履春冰恐未爲難。", "自於南國同埋劍，誰向東門便挂冠。", "早是人情飛絮薄，可堪時令太行寒。", "多慙幸住匡山下，偷得穠嵐坐臥看。"]'),
('38e2f261-c0dd-47f2-90d3-e24d8f8f343e','依韻修睦上人山居十首 七','李咸用','唐','唐诗','tang','','[]','畹蘭未必因香折，湖象多應爲齒焚。',64,'全唐诗/poet.tang.35000.json','["畹蘭未必因香折，湖象多應爲齒焚。", "兼濟直饒同巨楫，自由何似學孤雲。", "秋深櫟菌樵來得，木末山鼯夢斷聞。", "閑凭竹軒游子過，替他愁見日西曛。"]'),
('afc30e28-7c46-4501-abc6-33696c4e9501','依韻修睦上人山居十首 八','李咸用','唐','唐诗','tang','','[]','何事深山嘯復歌，短弓長劍不如他。',64,'全唐诗/poet.tang.35000.json','["何事深山嘯復歌，短弓長劍不如他。", "且圖青史垂名穩，從道前賢自滯多。", "𩿪鷃敢辭栖短棘，鳳凰猶解怯高羅。", "人生若得逢堯舜，便是巢由亦易過。"]'),
('aa7d5892-194f-45cf-936b-2f0134466487','依韻修睦上人山居十首 九','李咸用','唐','唐诗','tang','','[]','太玄太易小窗明，古義尋來醉復醒。',64,'全唐诗/poet.tang.35000.json','["太玄太易小窗明，古義尋來醉復醒。", "西伯縱逢頭已白，步兵如在眼應青。", "寒猿斷後雲爲檻，宿鳥驚時月滿庭。", "此景得閑閑去得，人間無事不曾經。"]'),
('3e867cb6-829b-4db8-bf67-757197a5547b','依韻修睦上人山居十首 十','李咸用','唐','唐诗','tang','','[]','壯氣雖同德不同，項王何似王江東。',64,'全唐诗/poet.tang.35000.json','["壯氣雖同德不同，項王何似王江東。", "鄉歌寂寂荒丘月，漁艇年年古渡風。", "難世斯人猶不達，此時吾道豈能通。", "吟君十首山中作，方覺多端總是空。"]'),
('38d0b6eb-1aa5-48c2-9b0c-e1df8846aa61','同友生春夜闻雨','李咸用','唐','唐诗','tang','','[]','春雨三更洗物華，亂和絲竹響豪家。',64,'全唐诗/poet.tang.35000.json','["春雨三更洗物華，亂和絲竹響豪家。", "滴繁知在長條柳，點重愁看破朵花。", "簷靜尚疑兼霧細，燈搖應是逐風斜。", "此時童叟渾無夢，爲喜流膏潤穀芽。"]'),
('569a716c-63e8-4db7-bb8d-dcad39b28a79','同友生题僧院杜鹃花','李咸用','唐','唐诗','tang','','[]','若比衆芳應有在，難同上品是中春。',64,'全唐诗/poet.tang.35000.json','["若比衆芳應有在，難同上品是中春。", "牡丹爲性疎南國，朱槿操心不滿旬。", "留得却緣真達者，見來寧作獨醒人。", "鶴林太盛今空地，莫放枝條出四鄰。"]'),
('81809a97-7b71-43d9-b357-b31cf5547b1d','春日題陈正字林亭','李咸用','唐','唐诗','tang','','[]','周迴勝異似仙鄉，稍減愁人日月長。',64,'全唐诗/poet.tang.35000.json','["周迴勝異似仙鄉，稍減愁人日月長。", "幕繞虛簷高岫色，鏡臨危檻小池光。", "絲垂楊柳當風軟，玉折含桃倚徑香。", "南北近來多少事，數聲橫笛怨斜陽。"]'),
('f05788dd-f54b-4f13-8d9c-5047582c056d','送河南韋主簿歸京','李咸用','唐','唐诗','tang','','[]','巖風愛日淚闌干，去住情途各萬端。',64,'全唐诗/poet.tang.35000.json','["巖風愛日淚闌干，去住情途各萬端。", "世亂敢言離別易，時清猶道路行難。", "舟維晚雨湘川暗，袖拂晴嵐峴首寒。", "見說滿朝親友在，肯教憔悴出長安。"]'),
('b32e2b62-59de-4268-99de-e4e54adc0082','喻道','李咸用','唐','唐诗','tang','','[]','漢武秦皇漫苦辛，那思俗骨本含真。',64,'全唐诗/poet.tang.35000.json','["漢武秦皇漫苦辛，那思俗骨本含真。", "不知流水潛催老，未悟三山也是塵。", "牢落沙丘終古恨，寂寥函谷萬年春。", "長生客待仙桃餌，月裏嬋娟笑煞人。"]'),
('cc190344-6143-4e56-ada7-38a2fa786587','山中','李咸用','唐','唐诗','tang','','[]','一簇煙霞榮辱外，秋山留得傍簷楹。',64,'全唐诗/poet.tang.35000.json','["一簇煙霞榮辱外，秋山留得傍簷楹。", "朝鐘暮鼓不到耳，明月孤雲長挂情。", "世上路岐何繚繞，水邊蓑笠稱平生。", "尋思阮籍當時意，豈是途窮泣利名。"]'),
('49b15831-23fa-46b2-bf4c-3491f3cae37a','同玄昶上人觀山榴','李咸用','唐','唐诗','tang','','[]','病隨支遁偶行行，正見榴花獨滿庭。',32,'全唐诗/poet.tang.35000.json','["病隨支遁偶行行，正見榴花獨滿庭。", "瘦竹成林人不看，却應著得強青青。"]'),
('60f8f9bd-f65a-41ef-a1f8-63b87bab7e5c','別李將軍','李咸用','唐','唐诗','tang','','[]','一拜虬髭便受恩，宮門細柳五搖春。',32,'全唐诗/poet.tang.35000.json','["一拜虬髭便受恩，宮門細柳五搖春。", "男兒自古多離別，嬾對英雄淚滿巾。"]'),
('95cc2ecb-9577-425b-9684-c0f7295433f3','早雞','李咸用','唐','唐诗','tang','','[]','錦翅朱冠驚四鄰，稻粱恩重職司晨。',32,'全唐诗/poet.tang.35000.json','["錦翅朱冠驚四鄰，稻粱恩重職司晨。", "不知下土兵難戢，但報明時向國人。"]'),
('1855f407-6e57-422e-961a-101e4afefbf3','別友','李咸用','唐','唐诗','tang','','[]','北吹微微動旅情，不堪分手在平明。',32,'全唐诗/poet.tang.35000.json','["北吹微微動旅情，不堪分手在平明。", "寒雞不待東方曙，喚起征人蹋月行。"]'),
('6c9ae0a4-2abb-464c-b83d-37cc48e06f4e','草檄荅南蠻有詠','胡曾','唐','唐诗','tang','','[]','辭天出塞陣雲空，霧捲霞開萬里通。',64,'全唐诗/poet.tang.35000.json','["辭天出塞陣雲空，霧捲霞開萬里通。", "親受虎符安宇宙，誓將龍劍定英雄。", "殘霜敢冒高懸日，秋葉爭禁大段風。", "爲報南蠻須屏跡，不同蜀將武侯功。"]'),
('cae41726-a7fd-4584-8f16-0b4e6c3b56dc','寒食都門作','胡曾','唐','唐诗','tang','','[]','二年寒食住京華，寓目春風萬萬家。',64,'全唐诗/poet.tang.35000.json','["二年寒食住京華，寓目春風萬萬家。", "金絡馬銜原上草，玉顏人折路傍花。", "軒車競出紅塵合，冠蓋爭回白日斜。", "誰念都門兩行淚，故園寥落在長沙。"]'),
('bc1674ca-58bd-4777-aadf-5f95fa66024d','薄命妾','胡曾','唐','唐诗','tang','','[]','阿嬌初失漢皇恩，舊賜羅衣亦罷薰。',64,'全唐诗/poet.tang.35000.json','["阿嬌初失漢皇恩，舊賜羅衣亦罷薰。", "倚枕夜悲金屋雨，卷簾朝泣玉樓雲。", "宮前葉落鴛鴦瓦，架上塵生翡翠裙。", "龍騎不巡時漸久，長門空掩綠苔紋。"]'),
('35e79af8-d41e-4ad4-949c-83f851a13447','獨不見','胡曾','唐','唐诗','tang','','[]','玉關一自有氛埃，年少從軍竟未回。',64,'全唐诗/poet.tang.35000.json','["玉關一自有氛埃，年少從軍竟未回。", "門外塵凝張樂榭，水邊香滅按歌臺。", "窗殘夜月人何處，簾卷春風燕復來。", "萬里寂寥音信絕，寸心爭忍不成灰。"]'),
('c0bd863f-b9ef-4cfa-bd67-f67b817fd7c4','交河塞下曲','胡曾','唐','唐诗','tang','','[]','交河冰薄日遲遲，漢將思家感別離。',64,'全唐诗/poet.tang.35000.json','["交河冰薄日遲遲，漢將思家感別離。", "塞北草生蘇武泣，隴西雲起李陵悲。", "曉侵雉堞烏先覺，春入關山雁獨知。", "何處疲兵心最苦，夕陽樓上笛聲時。"]'),
('45f4448e-7f26-41ff-a75f-91dfbdd58c04','車遙遙','胡曾','唐','唐诗','tang','','[]','自從車馬出門朝，便入空房守寂寥。',64,'全唐诗/poet.tang.35000.json','["自從車馬出門朝，便入空房守寂寥。", "玉枕夜殘魚信絕，金鈿秋盡雁書遙。", "臉邊楚雨臨風落，頭上春雲向日銷。", "芳草又衰還不至，碧天霜冷轉無憀。"]'),
('1dc9c736-e1a5-45f3-acc2-159d869223c8','早發潛水驛謁郎中員外','胡曾','唐','唐诗','tang','','[]','半床秋月一聲雞，萬里行人費馬蹄。',64,'全唐诗/poet.tang.35000.json','["半床秋月一聲雞，萬里行人費馬蹄。", "青野霧銷凝晉洞，碧山煙散避秦溪。", "樓臺稍辨烏城外，更漏微聞鶴柱西。", "已是大仙憐後進，不應來向武陵迷。"]'),
('9d7c0f89-a723-4026-bdde-23983426ad0a','贈漁者','胡曾','唐','唐诗','tang','','[]','不媿人間萬戶侯，子孫相繼老扁舟。',64,'全唐诗/poet.tang.35000.json','["不媿人間萬戶侯，子孫相繼老扁舟。", "往來南越諳鮫室，生長東吳識蜃樓。", "自爲釣竿能遣悶，不因萱草解銷憂。", "羨君獨得逃名趣，身外無機任白頭。"]'),
('5cd000a6-22f5-4b17-8fd7-7e4b2b27bc9c','自嶺下泛鷁到清遠峽作','胡曾','唐','唐诗','tang','','[]','乘船浮鷁下韶水，絕境方知在嶺南。',64,'全唐诗/poet.tang.35000.json','["乘船浮鷁下韶水，絕境方知在嶺南。", "薜荔雨餘山自黛，蒹葭煙盡島如藍。", "旦遊蕭帝新松寺，夜宿嫦娥桂影潭。", "不爲篋中書未獻，便來茲地結茅庵。"]'),
('86a6d290-78c5-49da-afa7-0f7790b20f52','題周瑜將軍廟','胡曾','唐','唐诗','tang','','[]','共說生前國步難，山川龍戰血漫漫。',64,'全唐诗/poet.tang.35000.json','["共說生前國步難，山川龍戰血漫漫。", "交鋒魏帝旌旂退，委任君王社稷安。", "庭際雨餘春草長，廟前風起晚光殘。", "功勳碑碣今何在，不得當時一字看。"]'),
('9be03bf0-0236-475b-a9ce-6d39fd2a36c3','詠史詩 烏江','胡曾','唐','唐诗','tang','','[]','爭帝圖王勢已傾，八千兵散楚歌聲。',32,'全唐诗/poet.tang.35000.json','["爭帝圖王勢已傾，八千兵散楚歌聲。", "烏江不是無船渡，耻向東吳再起兵。"]'),
('ba01bb4b-8467-47d4-889a-052a319dfa36','詠史詩 章華臺','胡曾','唐','唐诗','tang','','[]','茫茫衰草沒章華，因笑靈王昔好奢。',32,'全唐诗/poet.tang.35000.json','["茫茫衰草沒章華，因笑靈王昔好奢。", "臺土未乾簫管絕，可憐身死野人家。"]'),
('d6127d65-19b9-491b-9107-11a56b13b928','詠史詩 細腰宮','胡曾','唐','唐诗','tang','','[]','楚王辛苦戰無功，國破城荒霸業空。',32,'全唐诗/poet.tang.35000.json','["楚王辛苦戰無功，國破城荒霸業空。", "唯有青春花上露，至今猶泣細腰宮。"]'),
