('699d92a4-5707-4dae-96db-24767b82a07c','詠史詩 霸陵','胡曾','唐','唐诗','tang','','[]','原頭日落雪邊雲，猶放韓盧逐兔羣。',32,'全唐诗/poet.tang.36000.json','["原頭日落雪邊雲，猶放韓盧逐兔羣。", "況是四方無事日，霸陵誰識舊將軍。"]'),
('efbcdbfb-6307-45d0-820c-1d18df752e70','詠史詩 昆明池','胡曾','唐','唐诗','tang','','[]','欲出昆明萬里師，漢皇習戰此穿池。',32,'全唐诗/poet.tang.36000.json','["欲出昆明萬里師，漢皇習戰此穿池。", "如何一面圖攻取，不念生靈氣力疲。"]'),
('f8c4b9bc-b775-4fa1-b186-ac41d37992b7','詠史詩 迴中','胡曾','唐','唐诗','tang','','[]','武皇無路及昆丘，青鳥西沈隴樹秋。',32,'全唐诗/poet.tang.36000.json','["武皇無路及昆丘，青鳥西沈隴樹秋。", "欲問生前躬祀日，幾煩龍駕到涇州。"]'),
('98ac4269-52bf-4fd8-b8bf-578e2e7765a9','詠史詩 東門','胡曾','唐','唐诗','tang','','[]','何人知足反田廬，玉管東門餞二疏。',32,'全唐诗/poet.tang.36000.json','["何人知足反田廬，玉管東門餞二疏。", "豈是不榮天子祿，後賢那使久閑居。"]'),
('4801c0d9-52d1-4bd3-a263-c3ebbb002599','詠史詩 射熊館','胡曾','唐','唐诗','tang','','[]','漢帝荒唐不解憂，大誇田獵廢農收。',32,'全唐诗/poet.tang.36000.json','["漢帝荒唐不解憂，大誇田獵廢農收。", "子雲徒獻長楊賦，肯念高皇沐雨秋。"]'),
('bd9066c4-64a1-44ea-b9b7-c71b04eaf807','詠史詩 昆陽','胡曾','唐','唐诗','tang','','[]','師克由來在協和，蕭王兵馬固無多。',32,'全唐诗/poet.tang.36000.json','["師克由來在協和，蕭王兵馬固無多。", "誰知大敵昆陽敗，却笑前朝困楚歌。"]'),
('25e28997-3e96-4c7b-bec4-6a0c7b5361eb','詠史詩 七里灘','胡曾','唐','唐诗','tang','','[]','七里青灘映碧層，九天星象感嚴陵。',32,'全唐诗/poet.tang.36000.json','["七里青灘映碧層，九天星象感嚴陵。", "釣魚臺上無絲竹，不是高人誰解登。"]'),
('7932689a-6c71-4120-838f-b1233f5f959d','詠史詩 潁川','胡曾','唐','唐诗','tang','','[]','古賢高尚不爭名，行止由來動杳冥。',32,'全唐诗/poet.tang.36000.json','["古賢高尚不爭名，行止由來動杳冥。", "今日浪爲千里客，看花慙上德星亭。"]'),
('5302460c-2666-4f95-96b5-3c76e4a1497b','詠史詩 江夏','胡曾','唐','唐诗','tang','','[]','黃祖才非長者儔，禰衡珠碎此江頭。',32,'全唐诗/poet.tang.36000.json','["黃祖才非長者儔，禰衡珠碎此江頭。", "今來鸚鵡洲邊過，惟有無情碧水流。"]'),
('e0d2b11b-73ed-41d6-adab-de9ac7d5e227','詠史詩 官渡','胡曾','唐','唐诗','tang','','[]','本初屈指定中華，官渡相持勒虎牙。',32,'全唐诗/poet.tang.36000.json','["本初屈指定中華，官渡相持勒虎牙。", "若使許攸財用足，山河爭得屬曹家。"]'),
('b68b35df-a8e0-4f72-b82b-051b09958349','詠史詩 灞岸','胡曾','唐','唐诗','tang','','[]','長安城外白雲秋，蕭索悲風灞水流。',32,'全唐诗/poet.tang.36000.json','["長安城外白雲秋，蕭索悲風灞水流。", "因想漢朝離亂日，仲宣從此向荆州。"]'),
('0c9c5f7c-00fe-4d24-a95c-aa09b963ef79','詠史詩 濡須橋','胡曾','唐','唐诗','tang','','[]','徒向濡須欲受降，英雄才略獨無雙。',32,'全唐诗/poet.tang.36000.json','["徒向濡須欲受降，英雄才略獨無雙。", "天心不與金陵便，高步何由得渡江。"]'),
('b27ab6de-7501-4cc2-987b-afddf703bfd6','詠史詩 豫州','胡曾','唐','唐诗','tang','','[]','策馬行行到豫州，祖生寂寞水空流。',32,'全唐诗/poet.tang.36000.json','["策馬行行到豫州，祖生寂寞水空流。", "當時更有三年壽，石勒尋爲關下囚。"]'),
('c10fc0e5-1f53-4be8-8806-8b4f502137a9','詠史詩 八公山','胡曾','唐','唐诗','tang','','[]','苻堅舉國出西秦，東晉危如累卵晨。',32,'全唐诗/poet.tang.36000.json','["苻堅舉國出西秦，東晉危如累卵晨。", "誰料此山諸草木，盡能排難化爲人。"]'),
('1a78f81c-6a0a-438a-8c5e-cd331e1efa4d','下第','胡曾','唐','唐诗','tang','','[]','翰苑何時休嫁女，文昌早晚罷生兒。',32,'全唐诗/poet.tang.36000.json','["翰苑何時休嫁女，文昌早晚罷生兒。", "上林新桂年年發，不許平人折一枝。"]'),
('b440d330-6c31-4e27-ae2b-b1be83d528d1','贈薛濤','胡曾','唐','唐诗','tang','','["\u5199\u4eba", "\u8d5e\u7f8e", "\u5199\u4eba\u8bd7"]','萬里橋邊女校書，枇杷花下閉門居。',32,'全唐诗/poet.tang.36000.json','["萬里橋邊女校書，枇杷花下閉門居。", "掃眉才子知多少，管領春風總不如。"]'),
('ea443c03-ab3d-4119-af2e-88011345610a','採蓮','方干','唐','唐诗','tang','','[]','採蓮女兒避殘熱，隔夜相期侵早發。',64,'全唐诗/poet.tang.36000.json','["採蓮女兒避殘熱，隔夜相期侵早發。", "指剝春葱腕似雪，畫橈輕撥蒲根月。", "蘭舟遲速有輸贏，先到河灣賭何物。", "纔到河灣分首去，散在花間不知處。"]'),
('9f7bd3ff-6c6a-4935-b4e1-bcae3436a9a4','寄李頻','方干','唐','唐诗','tang','','[]','衆木又搖落，望君還不還。',48,'全唐诗/poet.tang.36000.json','["衆木又搖落，望君還不還。", "軒車在何處，雨雪滿前山。", "思苦文星動，鄉遙釣渚閑。", "明年見名姓，唯我獨何顏。"]'),
('db89ed07-30e2-4bee-a251-524b1e3d56b1','東溪別業寄吉州段郎中','方干','唐','唐诗','tang','','[]','前山含遠翠，羅列在窗中。',48,'全唐诗/poet.tang.36000.json','["前山含遠翠，羅列在窗中。", "盡日人不到，一尊誰與同。", "涼隨蓮葉雨，暑避柳條風。", "豈分長岑寂，明時有至公。"]'),
('216b4a68-f610-4bf3-a613-b4ad905f8682','懷州客舍','方干','唐','唐诗','tang','','[]','誤飲覃懷酒，誰知滯去程。',48,'全唐诗/poet.tang.36000.json','["誤飲覃懷酒，誰知滯去程。", "朝昏太行色，坐臥沁河聲。", "白道穿秦甸，嚴鼙似戍城。", "鄰雞莫相促，遊子自晨征。"]'),
('912006bc-4b5e-44b5-8725-c284293b7c91','中路寄喻鳧先輩','方干','唐','唐诗','tang','','[]','求名如未遂，白首亦難歸。',48,'全唐诗/poet.tang.36000.json','["求名如未遂，白首亦難歸。", "送我尊前酒，典君身上衣。", "寒蕪隨楚盡，落葉渡淮稀。", "莫歎干時晚，前心豈便非。"]'),
('88dcf393-efa8-45df-9c79-8987380fc203','送趙明府還北','方干','唐','唐诗','tang','','[]','故園終不住，劍鶴在扁舟。',48,'全唐诗/poet.tang.36000.json','["故園終不住，劍鶴在扁舟。", "盡室無餘俸，還家得白頭。", "鐘催吳岫曉，月遶渭河流。", "曾是棲安邑，恩期異日酬。"]'),
('282c33b7-cfce-4c95-9204-c01fb7745b2c','過朱協律故山','方干','唐','唐诗','tang','','[]','地下無餘恨，人間得盛名。',48,'全唐诗/poet.tang.36000.json','["地下無餘恨，人間得盛名。", "殘篇續大雅，稚子托諸生。", "度日山空暮，緣溪鶴自鳴。", "難收故交意，寒笛一聲聲。"]'),
('7814a03b-b322-4816-8227-0340f927d314','途中寄劉沆','方干','唐','唐诗','tang','','[]','登車誤相遠，談笑亦何因。',48,'全唐诗/poet.tang.36000.json','["登車誤相遠，談笑亦何因。", "路入瀟湘樹，書隨巴蜀人。", "歛衣寒犯雪，傾篋病看春。", "莫負髫年志，清朝作獻臣。"]'),
('28fc5eea-2f45-454b-9c0f-ab669bfd3c0f','送班主簿入謁荆南韋常侍','方干','唐','唐诗','tang','','[]','束書成遠去，還計莫經春。',48,'全唐诗/poet.tang.36000.json','["束書成遠去，還計莫經春。", "倒篋唯求醉，登舟自笑貧。", "波移彭蠡月，樹沒漢陵人。", "試吏曾趨府，旌幢自可親。"]'),
('2e9708d4-3043-4daf-9177-4a7bea0a21d6','夏日登靈隱寺後峰','方干','唐','唐诗','tang','','[]','絕頂無煩暑，登臨三伏中。',48,'全唐诗/poet.tang.36000.json','["絕頂無煩暑，登臨三伏中。", "深蘿難透日，喬木更含風。", "山疊雲霞際，川傾世界東。", "那知茲夕興，不與古人同。"]'),
('537c1a86-c967-41d8-a11e-aec849d9bb43','聽新蟬寄張晝','方干','唐','唐诗','tang','','[]','細聲頻斷續，審聽亦難分。',48,'全唐诗/poet.tang.36000.json','["細聲頻斷續，審聽亦難分。", "髣髴應移處，從容却不聞。", "蘭棲朝咽露，樹隱暝吟雲。", "莫遣鄉愁起，吾懷祗是君。"]'),
('9ea9b609-5f2d-4983-b566-9748ed50076e','送喻坦之下第還江東','方干','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','文戰偶未勝，無令移壯心。',48,'全唐诗/poet.tang.36000.json','["文戰偶未勝，無令移壯心。", "風塵辭帝里，舟檝到家林。", "過楚寒方盡，浮淮月正沈。", "持杯話來日，不聽洞庭砧。"]'),
('6c6d015a-9fe2-49c4-83f1-56718c7ce894','送姚舒下第遊蜀','方干','唐','唐诗','tang','','[]','蜀路何迢遞，憐君獨去遊。',48,'全唐诗/poet.tang.36000.json','["蜀路何迢遞，憐君獨去遊。", "風煙連北虜，山水似東甌。", "九折盤荒坂，重江遶漢州。", "臨邛一壺酒，能遣長卿愁。"]'),
('0ab7d88d-bb22-4137-a4c4-3ef6ffa2fee7','旅次錢塘','方干','唐','唐诗','tang','','[]','此地似鄉國，堪爲朝夕吟。',48,'全唐诗/poet.tang.36000.json','["此地似鄉國，堪爲朝夕吟。", "雲藏吳相廟，樹引越山禽。", "潮落海人散，鐘遲秋寺深。", "我來無舊識，誰見寂寥心。"]'),
('33fddbd6-5437-4c79-bd4c-58fcdb7d244e','別喻鳧','方干','唐','唐诗','tang','','[]','知心似古人，歲久分彌親。',48,'全唐诗/poet.tang.36000.json','["知心似古人，歲久分彌親。", "離別波濤闊，留連槐柳新。", "蟆陵寒貰酒，漁浦夜垂綸。", "自此星居後，音書豈厭頻。"]'),
('a6649093-93d8-4ebb-a384-5cfd06f2aa86','送相里燭','方干','唐','唐诗','tang','','[]','相逢未作期，相送定何之。',48,'全唐诗/poet.tang.36000.json','["相逢未作期，相送定何之。", "不得長年少，那堪遠別離。", "泛湖乘月早，踐雪過山遲。", "永望多時立，翻如在夢思。"]'),
('9df3fe52-6f0b-4e28-9009-924934ad580b','君不來','方干','唐','唐诗','tang','','[]','閑花未零落，心緒已紛紛。',48,'全唐诗/poet.tang.36000.json','["閑花未零落，心緒已紛紛。", "久客無人見，新禽何處聞？", "舟隨一水遠，路出萬山分。", "夜月生愁望，孤光必照君。"]'),
('f7423aa8-a14c-403d-9dc0-cdbff5feffe9','將謁商州呂郎中道出楚州留獻章中丞','方干','唐','唐诗','tang','','[]','江流盤復直，浮棹出家林。',48,'全唐诗/poet.tang.36000.json','["江流盤復直，浮棹出家林。", "商洛路猶遠，山陽春已深。", "青雲應有望，白髮未相侵。", "才小知難薦，終勞許郭心。"]'),
('aa40e360-14cf-4b65-a7dd-54f4b17de13c','金州客舍','方干','唐','唐诗','tang','','[]','卷箔羣峰暮，蕭條未掩關。',50,'全唐诗/poet.tang.36000.json','["卷箔羣峰暮，蕭條未掩關。", "江流嶓[冢]雨，路入漢家山。", "落葉欹眠後，孤砧倚望間。", "此情偏耐醉，難遣酒罍閑。"]'),
('06b8584f-8aba-4c65-b082-f2fb23694ab1','途中逢孫輅因得李頻消息','方干','唐','唐诗','tang','','[]','灞上寒仍在，柔條亦自新。',48,'全唐诗/poet.tang.36000.json','["灞上寒仍在，柔條亦自新。", "山河雖度臘，雨雪未知春。", "正憶同袍者，堪逢共國人。", "銜杯益無語，與爾轉相親。"]'),
('988873f6-5213-41bc-aefa-b82a2610326c','送從兄郜','方干','唐','唐诗','tang','','["\u79bb\u522b", "\u5c81\u6708"]','道路本無限，又應何處逢？',48,'全唐诗/poet.tang.36000.json','["道路本無限，又應何處逢？", "流年莫虛擲，華髪不相容。", "野渡波搖月，空城雨翳鐘。", "此心隨去馬，迢遞過千峰。"]'),
('e948e721-0489-4665-b340-a65e258c8c80','送許溫','方干','唐','唐诗','tang','','[]','壯歲分冞切，少年心正同。',48,'全唐诗/poet.tang.36000.json','["壯歲分冞切，少年心正同。", "當聞千里去，難遣一尊空。", "翳燭蒹葭雨，吹帆橘柚風。", "明年見親族，盡集在懷中。"]'),
('c02dd15a-1ca1-4d58-8dca-7905382a5a20','鏡中別業二首 一','方干','唐','唐诗','tang','','[]','寒山壓鏡心，此處是家林。',48,'全唐诗/poet.tang.36000.json','["寒山壓鏡心，此處是家林。", "梁燕窺春醉，嵒猿學夜吟。", "雲連平地起，月向白波沈。", "猶自聞鐘角，棲身可在深。"]'),
('e0910975-76bf-4a43-aec8-ab2898d6f05c','鏡中別業二首 二','方干','唐','唐诗','tang','','[]','世人如不容，吾自縱天慵。',48,'全唐诗/poet.tang.36000.json','["世人如不容，吾自縱天慵。", "落葉憑風掃，香秔倩水舂。", "花朝連郭霧，雪夜隔湖鐘。", "身外無能事，頭宜白此峰。"]'),
('0a25656f-290c-497a-b5d7-670022ecd9ae','經周處士故居','方干','唐','唐诗','tang','','[]','愁吟與獨行，何事不傷情。',48,'全唐诗/poet.tang.36000.json','["愁吟與獨行，何事不傷情。", "久立釣魚處，唯聞啼鳥聲。", "山蔬和草嫩，海樹入籬生。", "吾在茲溪上，懷君恨不平。"]'),
('e11586ae-a259-416a-a0e9-6dd2835066f2','贈喻鳧','方干','唐','唐诗','tang','','[]','所得非衆語，衆人那得知。',48,'全唐诗/poet.tang.36000.json','["所得非衆語，衆人那得知。", "纔吟五字句，又白幾莖髭。", "月閣欹眠夜，霜軒正坐時。", "沈思心更苦，恐作滿頭絲。"]'),
('37d6d80a-b183-4fbc-8d1f-bc7da73bb3bc','早發洞庭','方干','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','長天接廣澤，二氣共含秋。',48,'全唐诗/poet.tang.36000.json','["長天接廣澤，二氣共含秋。", "舉目無平地，何心戀直鉤。", "孤鐘鳴大岸，片月落中流。", "却憶鴟夷子，當時此泛舟。"]'),
('08ff2f82-8894-4219-96b7-d5b5500ad123','貽錢塘縣路明府','方干','唐','唐诗','tang','','[]','志業不得力，到今猶苦吟。',48,'全唐诗/poet.tang.36000.json','["志業不得力，到今猶苦吟。", "唫成五字句，用破一生心。", "世路屈聲遠，寒溪怨氣深。", "前賢多晚達，莫怕鬢霜侵。"]'),
('70d1abe4-fd20-446e-bb56-340dfed6c886','湖上言事寄長城喻明府','方干','唐','唐诗','tang','','[]','吟霜與臥雲，此興亦甘貧。',48,'全唐诗/poet.tang.36000.json','["吟霜與臥雲，此興亦甘貧。", "吹箭落翠羽，垂絲牽錦鱗。", "滿湖風撼月，半日雨藏春。", "却笑縈簪組，勞心字遠人。"]'),
('f20efba0-0932-4f14-8e68-dc4c8f8c6d78','涵碧亭','方干','唐','唐诗','tang','','[]','高低竹雜松，積翠復留風。',48,'全唐诗/poet.tang.36000.json','["高低竹雜松，積翠復留風。", "路極陰溪裏，寒生暑氣中。", "閑雲低覆草，片水靜涵空。", "方見洋源牧，心侔造化功。"]'),
('2910d0ab-6354-4a43-af9d-ecbcf9a977df','除夜','方干','唐','唐诗','tang','','[]','永懷難自問，此夕衆愁興。',48,'全唐诗/poet.tang.36000.json','["永懷難自問，此夕衆愁興。", "曉韻侵春角，寒光隔歲燈。", "心燃一寸火，淚結兩行冰。", "煦育誠非遠，陽和又欲昇。"]'),
('87fe9ca3-ecf3-46b3-9cbe-be9ba6cf3a03','贈許牘山人','方干','唐','唐诗','tang','','[]','才子醉更逸，一吟傾一觴。',48,'全唐诗/poet.tang.36000.json','["才子醉更逸，一吟傾一觴。", "支頤忍有得，搖筆便成章。", "王粲實可重，禰衡爭不狂。", "何時應會面，夢裏是瀟湘。"]'),
('4ec6ad27-5cb4-4979-bb59-e25d2358e790','贈功成將','方干','唐','唐诗','tang','','[]','定難在明略，何曾勞戰爭。',48,'全唐诗/poet.tang.36000.json','["定難在明略，何曾勞戰爭。", "飛書諭強寇，計日下重城。", "深雪移軍夜，寒笳出塞情。", "苦心殊易老，新髪早年生。"]'),
('c1acb0da-22b0-424a-b376-b752b4cf00d0','白艾原客','方干','唐','唐诗','tang','','[]','原上桑柘瘦，再來還見貧。',48,'全唐诗/poet.tang.36000.json','["原上桑柘瘦，再來還見貧。", "滄州幾年隱，白髮一莖新。", "敗葉平空塹，殘陽滿近隣。", "閑言說知己，半是學禪人。"]'),
('446becdb-0cc3-4ef8-8bca-c24e8f2ee3c0','朔管','方干','唐','唐诗','tang','','[]','寥寥落何處，一夜過胡天。',48,'全唐诗/poet.tang.36000.json','["寥寥落何處，一夜過胡天。", "送苦秋風外，吹愁白髮邊。", "望鄉皆下淚，久戍盡休眠。", "寂寞空沙曉，開眸片月懸。"]'),
('98447cde-dbfc-4d23-8e37-367b4c4b3108','憶故山','方干','唐','唐诗','tang','','[]','舊山長繫念，終日臥邊亭。',48,'全唐诗/poet.tang.36000.json','["舊山長繫念，終日臥邊亭。", "道路知已遠，夢魂空再經。", "秋泉涼好引，乳鶴靜宜聽。", "獨上高樓望，蓬身且未寧。"]'),
('56af8751-f431-4937-8723-7028c0b90ae0','冬夜泊僧舍','方干','唐','唐诗','tang','','[]','江東寒近臘，野寺水天昏。',48,'全唐诗/poet.tang.36000.json','["江東寒近臘，野寺水天昏。", "無酒能消夜，隨僧早閉門。", "照墻燈焰細，著瓦雨聲繁。", "漂泊仍千里，清吟欲斷魂。"]'),
('898d1a7c-c627-428d-8ca9-44741ea4d987','新秋獨夜寄戴叔倫','方干','唐','唐诗','tang','','[]','遙夜獨不臥，寂寥庭戶中。',48,'全唐诗/poet.tang.36000.json','["遙夜獨不臥，寂寥庭戶中。", "河明五陵上，月滿九門東。", "萬里親朋散，故園滄海空。", "歸懷正南望，此夕起秋風。"]'),
('3d92e117-b18e-42b7-ba62-865dd047f58d','送沛縣司馬丞之任','方干','唐','唐诗','tang','','[]','舉酒一相勸，逢春聊盡歡。',48,'全唐诗/poet.tang.36000.json','["舉酒一相勸，逢春聊盡歡。", "羇遊故交少，遠別後期難。", "路上野花發，雨中青草寒。", "悠悠兩都夢，小沛與長安。"]'),
('4b07b91d-182e-4a91-b430-7f0515c4c110','送盧評事東歸','方干','唐','唐诗','tang','','[]','萬里楊柳色，出關隨故人。',48,'全唐诗/poet.tang.36000.json','["萬里楊柳色，出關隨故人。", "輕煙覆流水，落日照行塵。", "積夢江湖闊，憶家兄弟貧。", "裴回灞亭上，不語共傷春。"]'),
('469ebce1-1cc8-4396-b86a-92d2d747c9cf','清明日送鄧芮還鄉','方干','唐','唐诗','tang','','[]','鐘鼓喧離室，車徒促夜裝。',48,'全唐诗/poet.tang.36000.json','["鐘鼓喧離室，車徒促夜裝。", "曉榆新變火，輕柳暗飛霜。", "轉鏡看華髪，傳杯話故鄉。", "每嫌兒女淚，今日自沾裳。"]'),
('5349b866-ffbc-45f6-b94d-cd7fd3a5008b','送崔拾遺出使江東','方干','唐','唐诗','tang','','[]','九門思諫諍，萬里采風謠。',48,'全唐诗/poet.tang.36000.json','["九門思諫諍，萬里采風謠。", "關外逢秋月，天涯過晚潮。", "雁飛雲杳杳，木落浦蕭蕭。", "空怨他鄉別，回舟暮寂寥。"]'),
('b81fee60-8250-47f6-b541-7442dac7a613','重陽日送洛陽李丞之任','方干','唐','唐诗','tang','','[]','爲文通絕境，從宦及良辰。',48,'全唐诗/poet.tang.36000.json','["爲文通絕境，從宦及良辰。", "洛下知名早，腰邊結綬新。", "且傾浮菊酒，聊拂染衣塵。", "獨恨滄州侶，愁來別故人。"]'),
('614337bb-d830-451e-ae52-2dd6d7b87ed6','江州送李侍御歸東洛','方干','唐','唐诗','tang','','[]','獨乘驄馬去，不並旅人還。',48,'全唐诗/poet.tang.36000.json','["獨乘驄馬去，不並旅人還。", "中外名卿貴，田園高步閑。", "暮春經楚縣，新月上淮山。", "道路空瞻望，軒車不敢攀。"]'),
('c2ae6fc3-2b66-4f79-b8b3-37748ee60dd7','送郭太祝歸江東','方干','唐','唐诗','tang','','[]','鄉人去欲盡，北雁又南飛。',48,'全唐诗/poet.tang.36000.json','["鄉人去欲盡，北雁又南飛。", "京洛風塵久，江淮音信稀。", "舊山知獨往，一醉莫相違。", "未得解羇旅，無勞問是非。"]'),
('971f3450-5edd-4da1-8b4a-820be76cfb69','送李恬及第後還貝州','方干','唐','唐诗','tang','','[]','成名年少日，就業聖人書。',48,'全唐诗/poet.tang.36000.json','["成名年少日，就業聖人書。", "擢桂誰相比，籝金已不如。", "東城送歸客，秋日待征車。", "若到清潭畔，儒風變里閭。"]'),
('195db8dd-0613-4715-81e4-585888488b56','收兩京後還上都兼訪一二親故','方干','唐','唐诗','tang','','[]','離堂千里客，歸騎五陵人。',48,'全唐诗/poet.tang.36000.json','["離堂千里客，歸騎五陵人。", "路轉函關晚，煙開上苑新。", "天涯將野服，闕下見鄉親。", "問得存亡事，裁詩寄海濱。"]'),
('550f1927-69d1-46e2-b74c-1e4277b576f5','送汶上王明府之任','方干','唐','唐诗','tang','','[]','何時到故鄉，歸去佩銅章。',48,'全唐诗/poet.tang.36000.json','["何時到故鄉，歸去佩銅章。", "親友移家盡，閭閻百戰傷。", "背關餘草木，出塞足風霜。", "遺老應相賀，知君不下堂。"]'),
('7f91ab51-a47a-44fb-9b6d-5a57cdea3db3','湖南使院遣情送江夏賀侍郎','方干','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','雲雨一消散，悠悠關復河。',48,'全唐诗/poet.tang.36000.json','["雲雨一消散，悠悠關復河。", "俱從泛舟役，遂隔洞庭波。", "楚水去不盡，秋風今更過。", "無由得相見，却恨寄書多。"]'),
('a2f4ad5f-7fc4-4038-a17c-4a124bf9e937','過申州作','方干','唐','唐诗','tang','','[]','萬人曾死戰，幾戶免刀兵。',48,'全唐诗/poet.tang.36000.json','["萬人曾死戰，幾戶免刀兵。", "井邑初安堵，兒童未長成。", "涼風吹古木，野火燒殘營。", "寥落千餘里，山高水復清。"]'),
('98ab4706-5c35-4616-a758-587cdce03600','汝南過訪田評事','方干','唐','唐诗','tang','','[]','移家近漢陰，不復問華簪。',48,'全唐诗/poet.tang.36000.json','["移家近漢陰，不復問華簪。", "買酒宜城遠，燒田夢澤深。", "暮山逢鳥入，寒水見魚沈。", "與物皆無累，終年愜本心。"]'),
('f7af4fd9-6339-4c67-8962-16fe5caf52bf','送道上人遊方','方干','唐','唐诗','tang','','[]','律儀通外學，詩思入玄關。',48,'全唐诗/poet.tang.36000.json','["律儀通外學，詩思入玄關。", "煙景隨人別，風姿與物閑。", "貫花留靜室，咒水度空山。", "誰識浮雲意，悠悠天地間。"]'),
('542f3f61-746d-41fb-82ea-47ff0a40f0a2','送饒州王司法之任兼寄朱處士','方干','唐','唐诗','tang','','[]','莫辭還作吏，且喜速回車。',48,'全唐诗/poet.tang.36000.json','["莫辭還作吏，且喜速回車。", "留醉悲殘歲，含情寄遠書。", "共看衰老近，轉覺宦名虛。", "遙想清溪畔，幽人得自如。"]'),
('af31dddf-eee7-445a-8511-3c4c3f1e9bfa','詹碏山居','方干','唐','唐诗','tang','','[]','愛此棲心靜，風塵路已賒。',48,'全唐诗/poet.tang.36000.json','["愛此棲心靜，風塵路已賒。", "十餘莖野竹，一兩樹山花。", "遶石開泉細，穿蘿引徑斜。", "無人會幽意，來往在煙霞。"]'),
('23de0fd0-fefe-418a-ac6f-71c62443860b','曉角','方干','唐','唐诗','tang','','[]','畫角吹殘月，寒聲發戍樓。',48,'全唐诗/poet.tang.36000.json','["畫角吹殘月，寒聲發戍樓。", "立霜嘶馬怨，攢磧泣兵愁。", "燕雁鳴雲畔，胡風冷草頭。", "罷聞三會後，天逈曉星流。"]'),
('e2369358-7d9d-49ba-acb1-c7b85ba94e95','冬日','方干','唐','唐诗','tang','','[]','燒火掩關坐，窮居客訪稀。',48,'全唐诗/poet.tang.36000.json','["燒火掩關坐，窮居客訪稀。", "凍雲愁暮色，寒日淡斜暉。", "穿牖竹風滿，遶庭雲葉飛。", "已嗟周一歲，羇寓尚何依。"]'),
('7b774434-3435-4dbe-b5a5-558913822fab','殘秋送友','方干','唐','唐诗','tang','','[]','早爲千里別，況復是秋殘。',48,'全唐诗/poet.tang.36000.json','["早爲千里別，況復是秋殘。", "木葉怨先老，江雲愁暮寒。", "交情如水淡，離酒泛杯寬。", "料想還家後，休吟行路難。"]'),
('28e1801c-e062-4514-bd71-1198dc4a4c62','客行','方干','唐','唐诗','tang','','[]','藕葉綴爲衣，東西泣路岐。',48,'全唐诗/poet.tang.36000.json','["藕葉綴爲衣，東西泣路岐。", "鄉心日落後，身計酒醒時。", "觸目多添感，凝情足所思。", "羈愁難盡遣，行坐一低眉。"]'),
('dfc43e14-5ffd-41cf-b444-89f6e3da1e4d','秋夜','方干','唐','唐诗','tang','','[]','度鴻驚睡醒，欹枕已三更。',48,'全唐诗/poet.tang.36000.json','["度鴻驚睡醒，欹枕已三更。", "夢破寂寥思，燈殘零落明。", "空窗閑月色，幽壁靜蟲聲。", "況是離鄉久，依然無限情。"]'),
('38f15ae7-30ca-44c5-b4d1-ce74c370c84e','新月','方干','唐','唐诗','tang','','[]','入夜天西見，蛾[眉]冷素光。',50,'全唐诗/poet.tang.36000.json','["入夜天西見，蛾[眉]冷素光。", "潭魚驚釣落，雲雁怯弓張。", "隱隱臨珠箔，微微上粉墻。", "更憐三五夕，仙桂滿輪芳。"]'),
('603d1bd2-1966-4bf1-a83d-ac3ec14ca31f','滁上懷周賀','方干','唐','唐诗','tang','','[]','就枕忽不寐，孤懷興歎初。',48,'全唐诗/poet.tang.36000.json','["就枕忽不寐，孤懷興歎初。", "南譙收舊曆，上苑絕來書。", "暝雪細聲積，晨鐘寒韻疎。", "侯門昔彈鋏，曾共食江魚。"]'),
('38102412-14f3-414c-9d2d-9ac27471726c','寄石湓清越上人','方干','唐','唐诗','tang','','[]','寺處唯高僻，雲生石枕前。',48,'全唐诗/poet.tang.36000.json','["寺處唯高僻，雲生石枕前。", "靜吟因得句，獨夜不妨禪。", "窗接停猨樹，巖飛浴鶴泉。", "相思有書札，俱倩獵人傳。"]'),
('3330b9a5-01c5-46e5-8f8b-b88b4c7f7212','陳式水墨山水','方干','唐','唐诗','tang','','[]','造化有功力，平分歸筆端。',48,'全唐诗/poet.tang.36000.json','["造化有功力，平分歸筆端。", "溪如冰後聽，山似燒來看。", "立意雪髯出，支頤煙汗乾。", "世間從爾後，應覺致名難。"]'),
('31b2aa54-caed-497d-9062-0b31ff8c26fe','陳秀才亭際木蘭','方干','唐','唐诗','tang','','[]','昔見初栽日，今逢成樹時。',48,'全唐诗/poet.tang.36000.json','["昔見初栽日，今逢成樹時。", "存思心更感，遶看步還遲。", "蝶舞搖風蘂，鶯啼含露枝。", "裴回不忍去，應與醉相宜。"]'),
('2d079a36-af6d-4dcd-b933-d2b6516a7b89','贈鏡公','方干','唐','唐诗','tang','','[]','幽獨度遙夜，夜清神更閑。',48,'全唐诗/poet.tang.36000.json','["幽獨度遙夜，夜清神更閑。", "高風吹越樹，細露濕湖山。", "月皎微吟後，鐘鳴不寐間。", "如教累簪組，此興豈相關。"]'),
('0065a4a9-d0d0-47b6-81c3-f7a2661f9c5e','登雪竇僧家','方干','唐','唐诗','tang','','[]','登寺尋盤道，人煙遠更微。',48,'全唐诗/poet.tang.36000.json','["登寺尋盤道，人煙遠更微。", "石窗秋見海，山靄暮侵衣。", "衆木隨僧老，高泉盡日飛。", "誰能厭軒冕，來此便忘機。"]'),
('3db59a4a-6a16-4baa-b7c9-e27b60550c05','途中逢進士許巢','方干','唐','唐诗','tang','','[]','聲望去已遠，門人無不知。',48,'全唐诗/poet.tang.36000.json','["聲望去已遠，門人無不知。", "義行相識處，貧過少年時。", "妨寐夜吟苦，愛閑身達遲。", "難求似君者，我去更逢誰。"]'),
('38c6a382-acaa-4635-8ff6-a1f64a8db1df','贈瑪瑙山禪者','方干','唐','唐诗','tang','','[]','芿草不停獸，因師山更靈。',48,'全唐诗/poet.tang.36000.json','["芿草不停獸，因師山更靈。", "村林朝乞食，風雨夜開扃。", "井味兼松粉，雲根着淨瓶。", "塵勞如醉夢，對此暫能醒。"]'),
('3f0a2210-7ade-4233-bb78-127bd6c5a5f7','詶故人陳乂都','方干','唐','唐诗','tang','','[]','遠別那無夢，重遊自有期。',48,'全唐诗/poet.tang.36000.json','["遠別那無夢，重遊自有期。", "半年鄉信到，兩地赤心知。", "坐久吟移調，更長硯結凘。", "文人才力薄，終怕阿戎欺。"]'),
('04cb418e-1a3f-487d-b3c3-4b4beb822fda','閏春','方干','唐','唐诗','tang','','[]','冪冪復蒼蒼，微和傍早陽。',48,'全唐诗/poet.tang.36000.json','["冪冪復蒼蒼，微和傍早陽。", "前春寒已盡，待閏日猶長。", "柳變雖因雨，花遲豈爲霜。", "自茲延聖曆，誰不駐年光。"]'),
('ccceb8ba-2faf-41b6-86fe-4cf0d7609dca','方著作畫竹','方干','唐','唐诗','tang','','[]','疊葉與高節，俱從毫末生。',48,'全唐诗/poet.tang.36000.json','["疊葉與高節，俱從毫末生。", "流傳千古譽，研鍊十年情。", "向月本無影，臨風疑有聲。", "吾家釣臺畔，似此兩三莖。"]'),
('d5705d7d-10e8-422f-945c-e56061f5f416','題友人山花','方干','唐','唐诗','tang','','[]','平明方發盡，爲待好風吹。',48,'全唐诗/poet.tang.36000.json','["平明方發盡，爲待好風吹。", "不見移來日，先愁落去時。", "濃香薰疊葉，繁朵壓卑枝。", "坐看皆終夕，遊蜂似有期。"]'),
('0d8e1226-937d-46b3-83f8-c071463ac5e4','贈詩僧懷靜','方干','唐','唐诗','tang','','[]','幾生餘習在，時復作微吟。',48,'全唐诗/poet.tang.36000.json','["幾生餘習在，時復作微吟。", "坐夏莓苔合，行禪檜柏深。", "入山成白首，學道是初心。", "心地不移變，徒云寒暑侵。"]'),
('2943d552-63b0-456f-9da9-a7cf0735c907','贈許牘秀才','方干','唐','唐诗','tang','','[]','理論與妙用，皆從人外來。',48,'全唐诗/poet.tang.36000.json','["理論與妙用，皆從人外來。", "山河澄正氣，雪月助宏才。", "傲世寄漁艇，藏名歸酒杯。", "升沈在方寸，即恐起風雷。"]'),
('6d1354ef-d056-45b8-b3d0-c571af440158','送于丹','方干','唐','唐诗','tang','','[]','至業是至寶，莫過心自知。',48,'全唐诗/poet.tang.36000.json','["至業是至寶，莫過心自知。", "時情如甚暢，天道即無私。", "入洛霜霰苦，離家蘭菊衰。", "焚舟不回顧，薄暮又何之。"]'),
('1c9bbf31-a372-4b6d-8c81-36c2b0eb7a66','送人遊日本國','方干','唐','唐诗','tang','','[]','滄茫大荒外，風教即難知。',48,'全唐诗/poet.tang.36000.json','["滄茫大荒外，風教即難知。", "連夜揚帆去，經年到岸遲。", "波濤含左界，星斗定東維。", "或有歸風便，當爲相見期。"]'),
('3f9b15c7-c353-48fd-951a-3acc4ee43150','東溪言事寄于丹','方干','唐','唐诗','tang','','[]','日月晝夜轉，年光難駐留。',48,'全唐诗/poet.tang.36000.json','["日月晝夜轉，年光難駐留。", "軒窗才過雨，枕簟即知秋。", "草際鳥行出，溪中虹影收。", "唯君壯心在，應笑臥滄洲。"]'),
('86ed3878-bba1-474c-92c3-f29908bb7bb9','暮發七里灘夜泊嚴光臺下','方干','唐','唐诗','tang','','[]','一瞬即七里，箭馳猶是難。',48,'全唐诗/poet.tang.36000.json','["一瞬即七里，箭馳猶是難。", "檣邊走嵐翠，枕底失風湍。", "但訝猨鳥定，不知霜月寒。", "前賢竟何益，此地誤垂竿。"]'),
('330e085f-4b9e-413e-9281-e4753fc5a4b3','處州洞溪','方干','唐','唐诗','tang','','[]','氣象四時清，無人畫得成。',48,'全唐诗/poet.tang.36000.json','["氣象四時清，無人畫得成。", "衆山寒疊翠，兩派綠分聲。", "坐月何曾夜，聽松不似晴。", "混元融結後，便有此溪名。"]'),
('520556ce-3f7f-41f5-98fe-7a66e6e7227b','稱心寺中島','方干','唐','唐诗','tang','','[]','水木深不極，似將星漢連。',48,'全唐诗/poet.tang.36000.json','["水木深不極，似將星漢連。", "中州唯此地，上界別無天。", "雪折停猨樹，花藏浴鶴泉。", "師爲終老意，日日復年年。"]'),
('32fdf308-96cd-4f85-9759-81c2500d4986','歲晚苦寒','方干','唐','唐诗','tang','','[]','地氣寒不暢，嚴風無定時。',48,'全唐诗/poet.tang.36000.json','["地氣寒不暢，嚴風無定時。", "挑燈青燼少，呵筆尺書遲。", "白兔沒已久，晨雞僵未知。", "竚看開聖曆，喧煦立爲期。"]'),
('5ed1226c-2321-4a25-ade8-2929fe0f2c87','杜鵑花','方干','唐','唐诗','tang','','[]','未問移栽日，先愁落地時。',48,'全唐诗/poet.tang.36000.json','["未問移栽日，先愁落地時。", "疎中從間葉，密處莫燒枝。", "郢客教誰探，胡蜂是自知。", "周回兩三步，常有醉鄉期。"]'),
('d7d2a57b-425a-47a7-b2a6-e0e2f18ad089','山中','方干','唐','唐诗','tang','','[]','散拙亦自遂，麤將猨鳥同。',48,'全唐诗/poet.tang.36000.json','["散拙亦自遂，麤將猨鳥同。", "飛泉高瀉月，獨樹逈含風。", "果落盤盂上，雲生篋笥中。", "未甘明聖日，終作釣漁翁。"]'),
('5b610d25-f37d-4ac4-ac2a-7b467aeab436','路支使小池','方干','唐','唐诗','tang','','[]','兒童戲穿鑿，咫尺見津涯。',48,'全唐诗/poet.tang.36000.json','["兒童戲穿鑿，咫尺見津涯。", "蘚岸和纖草，松泉濺淺沙。", "光含半牀月，影入一枝花。", "到此無醒日，當時有習家。"]'),
('00751342-bbcf-49ed-bf65-9959762a06be','清源標公','方干','唐','唐诗','tang','','[]','師爲衆人重，始得衆人師。',48,'全唐诗/poet.tang.36000.json','["師爲衆人重，始得衆人師。", "年到白頭日，行如新戒時。", "缾添放魚澗，窗逈褭猿枝。", "此地堪終老，迷癡自不知。"]'),
('959dbe2a-b2da-4c33-b668-9df20b9af13c','題雪竇禪師壁','方干','唐','唐诗','tang','','[]','飛泉濺禪石，缾注亦生苔。',48,'全唐诗/poet.tang.36000.json','["飛泉濺禪石，缾注亦生苔。", "海上山不淺，天邊人自來。", "長年隨檜柏，獨夜任風雷。", "獵者聞疎磬，知師入定迴。"]'),
('ef9c43ce-c331-4ad0-a52a-da9d765271b0','重寄金山寺僧','方干','唐','唐诗','tang','','[]','風濤匝山寺，磬韻達漁船。',48,'全唐诗/poet.tang.36000.json','["風濤匝山寺，磬韻達漁船。", "此處別師久，遠懷無信傳。", "月華妨靜燭，鳥語答幽禪。", "已見如如理，灰心應不然。"]'),
('8f3e181f-cc78-47e9-a3d1-a64fcf3b7eb3','哭胡珪','方干','唐','唐诗','tang','','[]','才高登上第，孝極歿廬塋。',48,'全唐诗/poet.tang.36000.json','["才高登上第，孝極歿廬塋。", "一命何無定，片言徒有聲。", "故園花自發，新塚月初明。", "寂寞重泉裏，豈知春物榮。"]'),
('430f8354-f18e-4ad5-bf56-48cb21a7df37','與清溪趙明府','方干','唐','唐诗','tang','','[]','清規暫趨府，獨立與誰親。',48,'全唐诗/poet.tang.36000.json','["清規暫趨府，獨立與誰親。", "遂性無非酒，求閑却愛貧。", "林泉應入夢，印綬莫留人。", "王事聞多暇，吟來幾首新。"]'),
('0af0a74b-6ea4-4991-a64c-37f452e4105c','送剡縣陳永秩滿歸越','方干','唐','唐诗','tang','','[]','俸祿三年後，程途一月間。',48,'全唐诗/poet.tang.36000.json','["俸祿三年後，程途一月間。", "舟中非客路，鏡裏是家山。", "密雪霑行袂，離杯變別顏。", "古人唯賀滿，今挈解由還。"]'),
('ae2b08be-ec91-4d23-8dbc-272e8b814f59','示鄉叟','方干','唐','唐诗','tang','','[]','暮齒甘衰謝，逢人惜別離。',48,'全唐诗/poet.tang.36000.json','["暮齒甘衰謝，逢人惜別離。", "青山前代業，老樹此身移。", "買藥將衣盡，尋方見字遲。", "如何鑷殘鬢，覽鏡變成絲。"]'),
('3a23b415-da76-496d-a249-e827701da499','遊竹林寺','方干','唐','唐诗','tang','','[]','得路到深寺，幽虛曾識名。',48,'全唐诗/poet.tang.36000.json','["得路到深寺，幽虛曾識名。", "蘚濃陰砌古，煙起暮香生。", "曙月落松翠，石泉流梵聲。", "聞僧說真理，煩惱自然輕。"]'),
('cd73391b-28e2-47d6-98c5-1f0dd512f531','陸處士別業','方干','唐','唐诗','tang','','[]','問道遠相訪，無人覺路長。',48,'全唐诗/poet.tang.36000.json','["問道遠相訪，無人覺路長。", "夜深回釣檝，月影出書林。", "蟬噪蓼花發，禽來山果香。", "多時欲歸去，西望又斜陽。"]'),
('c2e63615-7b07-4e87-b53e-b02d641f8a6b','贈中岳僧','方干','唐','唐诗','tang','','[]','坐來藂木大，誰見入嵒年。',48,'全唐诗/poet.tang.36000.json','["坐來藂木大，誰見入嵒年。", "多病長留藥，無憂亦是禪。", "搘牀移片石，舂粟引高泉。", "盡願求心法，逢誰即擬傳。"]'),
('2239a873-dbc7-45d7-a297-1d3aa0f2fe1e','寄普州賈司倉島','方干','唐','唐诗','tang','','[]','亂山重復疊，何路訪先生。',47,'全唐诗/poet.tang.36000.json','["亂山重復疊，何路訪先生。", "豈料多才者，空垂不世名閑曹猶得醉，薄俸亦勝耕。", "莫問吟詩石，年年芳草平。"]'),
('128f52c6-06a9-4066-b17e-a1c180217db8','送鏡空上人遊江南','方干','唐','唐诗','tang','','[]','去住如雲鶴，飄然不可留。',48,'全唐诗/poet.tang.36000.json','["去住如雲鶴，飄然不可留。", "何山逢後夏，一食在孤舟。", "細雨蓮塘晚，疎蟬橘岸秋。", "應懷舊溪月，夜過石窗流。"]'),
('64996b37-9d84-497c-9c25-ac280b138765','新正','方干','唐','唐诗','tang','','[]','篳門惆悵內，時節暗來頻。',48,'全唐诗/poet.tang.36000.json','["篳門惆悵內，時節暗來頻。", "每見新正雪，長思故國春。", "雲西斜去雁，江上未歸人。", "又一年爲客，何媒得到秦。"]'),
('9a3f5069-b98e-449b-a61c-59a1db20801c','夜聽步虛','方干','唐','唐诗','tang','','[]','寂寂永宮裏，天師朝禮聲。',48,'全唐诗/poet.tang.36000.json','["寂寂永宮裏，天師朝禮聲。", "步虛聞一曲，渾欲到三清。", "瑞草秋風起，仙堦夜月明。", "多年遠塵意，此地欲鋪平。"]'),
('c894ea12-d454-4e07-bb6b-1c9ceec478a4','題碧溪山禪老','方干','唐','唐诗','tang','','[]','師步有雲隨，師情唯鶴知。',52,'全唐诗/poet.tang.36000.json','["師步有雲隨，師情唯鶴知。", "蘿迷收{艹/朮}路，雪隔出溪時。", "竹狖窺沙井，巖禽停檜枝。", "由來傲卿相，臥穩答書遲。"]'),
('e53c7dfa-6d87-4122-8cd6-261901a57ca6','寒食宿先天寺無可上人房','方干','唐','唐诗','tang','','[]','雙扉檜下開，寄宿石房苔。',48,'全唐诗/poet.tang.36000.json','["雙扉檜下開，寄宿石房苔。", "幡北燈花動，城西雪霰來。", "收棊想雲夢，罷茗議天台。", "同憶前年臘，師初白閣回。"]'),
('2c943c10-ea7d-4271-aacc-d33a5b87ce6f','中秋月','方干','唐','唐诗','tang','','[]','涼霄煙靄外，三五玉蟾秋。',48,'全唐诗/poet.tang.36000.json','["涼霄煙靄外，三五玉蟾秋。", "列野星辰正，當空鬼魅愁。", "泉澄寒魄瑩，露滴冷光浮。", "未折青青桂，吟看不忍休。"]'),
('582a27dc-0a99-47d2-a859-8a9b95bb7a42','暮冬書懷呈友人','方干','唐','唐诗','tang','','[]','空爲梁甫吟，誰竟是知音。',48,'全唐诗/poet.tang.36000.json','["空爲梁甫吟，誰竟是知音。", "風雪生寒夜，鄉園來舊心。", "滄江孤棹逈，白閣一鐘深。", "君子久忘我，此懷甘自沈。"]'),
('d4d0cc8b-cb2e-412d-a446-a176ffffe758','贈江南僧','方干','唐','唐诗','tang','','[]','忘機室亦空，禪與沃州同。',48,'全唐诗/poet.tang.36000.json','["忘機室亦空，禪與沃州同。", "唯有半庭竹，能生竟日風。", "思山海月上，出定印香終。", "繼後傳衣者，還須立雪中。"]'),
('ef0dace3-e56c-4647-8c04-778b3ec84416','柳','方干','唐','唐诗','tang','','[]','搖曳惹風吹，臨堤軟勝絲。',48,'全唐诗/poet.tang.36000.json','["搖曳惹風吹，臨堤軟勝絲。", "態濃誰爲識，力弱自難持。", "學舞枝翻袖，呈妝葉展眉。", "如何一攀折，懷友又題詩。"]'),
('67cfb00b-b7fb-4f48-824c-e942a27a8bfc','送姚合員外赴金州','方干','唐','唐诗','tang','','[]','受詔從華省，開旗發帝州。',48,'全唐诗/poet.tang.36000.json','["受詔從華省，開旗發帝州。", "野煙新驛曙，殘照古山秋。", "樹勢連巴沒，江聲入楚流。", "唯應化行後，吟句上閑樓。"]'),
('3766d1a6-b5d4-4f74-ba93-c9fa0a497af1','送江陰霍明府之任','方干','唐','唐诗','tang','','[]','遙遙去舸新，浸郭葦兼蘋。',48,'全唐诗/poet.tang.36000.json','["遙遙去舸新，浸郭葦兼蘋。", "樹列巢灘鶴，鄉多釣浦人。", "虹分陽羨雨，浪隔廣陵春。", "知竟三年秩，琴書外是貧。"]'),
('9a3a597e-db3d-40a3-8927-47550775edf8','送友及第歸淛東','方干','唐','唐诗','tang','','[]','南行無俗侶，秋雁與寒雲。',48,'全唐诗/poet.tang.36000.json','["南行無俗侶，秋雁與寒雲。", "野趣自多愜，鄉名人共聞。", "吳山中路斷，淛水半江分。", "此地登臨慣，攄情一送君。"]'),
('c626fcd6-22e5-4865-9a8e-1470243c9386','山中即事','方干','唐','唐诗','tang','','[]','趍世非身事，山中適性情。',48,'全唐诗/poet.tang.36000.json','["趍世非身事，山中適性情。", "野花多異色，幽鳥少凡聲。", "樹影搜涼臥，苔光破碧行。", "閑尋採藥處，仙路漸分明。"]'),
('1c2723ad-321e-4af7-9aa1-d252731e0d50','過黃州作','方干','唐','唐诗','tang','','[]','弭節齊安郡，孤城百戰殘。',48,'全唐诗/poet.tang.36000.json','["弭節齊安郡，孤城百戰殘。", "傍村林有虎，帶郭縣無官。", "暮角梅花怨，清江桂影寒。", "黍離緣底事，撩我起長歎。"]'),
('74a6951a-81f5-427a-b059-be5ad4f56372','元日','方干','唐','唐诗','tang','','[]','晨雞兩遍報更闌，刁斗無聲曉漏乾。',64,'全唐诗/poet.tang.36000.json','["晨雞兩遍報更闌，刁斗無聲曉漏乾。", "暖日映山調正氣，東風入樹舞殘寒。", "軒車欲識人間感，獻歲須來帝里看。", "纔酌屠蘇定年齒，坐中惟笑鬢毛斑。"]'),
('88d93546-b84b-4852-9106-4aa36a944fe0','別從兄郜','方干','唐','唐诗','tang','','[]','展翅開帆秪待風，吹噓成事古今同。',64,'全唐诗/poet.tang.36000.json','["展翅開帆秪待風，吹噓成事古今同。", "已呼斷雁歸行裏，全勝枯鱗在轍中。", "若許死前恩少報，終期言下命潛通。", "臨岐再拜無餘事，願取文章達聖聰。"]'),
('049d78d9-0440-4e3a-9e8c-03351c35c1ec','寄江陵王少府','方干','唐','唐诗','tang','','[]','分手頻曾變寒暑，迢迢遠意各何如。',64,'全唐诗/poet.tang.36000.json','["分手頻曾變寒暑，迢迢遠意各何如。", "波濤一阻兩鄉夢，歲月無過雙鯉魚。", "吟處落花藏筆硯，睡時斜雨濕圖書。", "此來俗輩皆疎我，唯有故人心不疎。"]'),
('efec4dcb-35ba-4a3b-8937-15b9cc95f65e','題睦州烏龍山禪居','方干','唐','唐诗','tang','','[]','曙後月華猶冷濕，自知坐臥逼天宮。',64,'全唐诗/poet.tang.36000.json','["曙後月華猶冷濕，自知坐臥逼天宮。", "晨雞未暇鳴山底，早日先來照屋東。", "人世驅馳方丈內，海波搖動一杯中。", "伴師長住應難住，歸去仍須入俗籠。"]'),
('6f6a63fc-dea5-420a-98cd-e68f033e6ed3','寄杭州于郎中','方干','唐','唐诗','tang','','[]','雖云聖代識賢明，自是山河應數生。',64,'全唐诗/poet.tang.36000.json','["雖云聖代識賢明，自是山河應數生。", "大雅篇章無弟子，高門世業有公卿。", "入樓早月中秋色，遶郭寒潮半夜聲。", "白屋青雲至懸闊，愚儒肝膽若爲傾。"]'),
('4e9821fd-2707-408c-a964-9f4a962bf4a9','寄靈武胡常侍','方干','唐','唐诗','tang','','[]','青雲直上路初通，已在明君倚注中。',64,'全唐诗/poet.tang.36000.json','["青雲直上路初通，已在明君倚注中。", "欲遣爲霖安九有，先令作相贊東宮。", "自從忠讜承天睠，更用文篇續國風。", "最是何人感恩德，謝敷星下釣漁翁。"]'),
('5eae777f-8dcc-4fbf-8a7e-a49c98f91eba','上張舍人','方干','唐','唐诗','tang','','[]','海內芳聲誰可竝，承家三代相門深。',64,'全唐诗/poet.tang.36000.json','["海內芳聲誰可竝，承家三代相門深。", "剖符已副東人望，援筆曾傳聖主心。", "此地清廉惟飲水，四方焦熱待爲霖。", "他年莫學鴟夷子，遠泛扁舟用鑄金。"]'),
('a6fc0aae-c655-4432-9a0e-98a4aa985c3d','題慈溪張丞壁','方干','唐','唐诗','tang','','[]','因君貳邑藍溪上，遣我維舟紅葉時。',64,'全唐诗/poet.tang.36000.json','["因君貳邑藍溪上，遣我維舟紅葉時。", "共向鄉中非半面，俱驚鬢裏有新絲。", "竚看孤潔成三考，應笑愚疎捨一枝。", "貌似故人心尚喜，相逢況是舊相知。"]'),
('6e022ea6-7a91-4af3-aac0-e25f22f753d9','贈鄰居袁明府','方干','唐','唐诗','tang','','[]','隔竹每呼皆得應，二心親熟更如何。',64,'全唐诗/poet.tang.36000.json','["隔竹每呼皆得應，二心親熟更如何。", "文章鍛鍊猶相似，年齒參差不校多。", "雨後卷簾看越嶺，更深欹枕聽湖波。", "朝昏幸得同醒醉，遮莫光陰自下坡。"]'),
('c6ea1d13-938a-4f3e-a1a2-55207b23d391','孫氏林亭','方干','唐','唐诗','tang','','[]','池亭纔有二三畝，風景勝於千萬家。',64,'全唐诗/poet.tang.36000.json','["池亭纔有二三畝，風景勝於千萬家。", "瑟瑟林排全巷竹，猩猩血染半園花。", "竝牀欹枕逢春盡，援筆持杯到日斜。", "丱角相知成白首，而今歡笑莫咨嗟。"]'),
('fd89828b-ef35-48f0-898d-c944feb0a50e','漳州陽亭言事寄于使君','方干','唐','唐诗','tang','','[]','謝守登城對遠峰，金英泛泛滿金鍾。',64,'全唐诗/poet.tang.36000.json','["謝守登城對遠峰，金英泛泛滿金鍾。", "樓頭風景八九月，牀下水雲千萬重。", "紅斾朝昏雖許近，清才今古定難逢。", "鯉魚縱是凡鱗鬣，得在膺門合作龍。"]'),
('53d6b63f-37b6-45d6-a01f-ae1128cd5770','別胡中丞','方干','唐','唐诗','tang','','[]','二年朝夜見雙旌，心魄知恩夢亦驚。',64,'全唐诗/poet.tang.36000.json','["二年朝夜見雙旌，心魄知恩夢亦驚。", "幽賤麤能分菽麥，從容豈合遇公卿。", "吹噓若自毫端出，羽翼應從肉上生。", "却恨此身唯一死，空將一死報猶輕。"]'),
('1e0380b1-949f-495a-b793-965c5590f4fb','遊張公洞寄陶校書','方干','唐','唐诗','tang','','[]','步步勢穿江底去，此中危滑轉身難。',64,'全唐诗/poet.tang.36000.json','["步步勢穿江底去，此中危滑轉身難。", "下蒸陰氣松蘿濕，外制溫風杖屨寒。", "數里煙雲方覺異，前程世界更應寬。", "由來委曲尋仙路，不似先生換骨丹。"]'),
('ad92e00b-71d8-4b50-9730-e8c57b455288','題睦州郡中千峰榭','方干','唐','唐诗','tang','','[]','豈知平地似天台，朱戶深沈別徑開。',64,'全唐诗/poet.tang.36000.json','["豈知平地似天台，朱戶深沈別徑開。", "曳響露蟬穿樹去，斜行沙鳥向池來。", "窗中早月當琴榻，墻上秋山入酒杯。", "何事此中如世外，應緣羊祜是仙才。"]'),
('b83f6e50-25f4-4bc8-bce6-5c156c0a6024','登新城縣樓贈蔡明府','方干','唐','唐诗','tang','','[]','楊震東來是宦遊，政成登此自消憂。',64,'全唐诗/poet.tang.36000.json','["楊震東來是宦遊，政成登此自消憂。", "草中白道穿村去，樹裏清溪照郭流。", "縱目四山宜永日，開襟五月似高秋。", "不知縣籍添新戶，但見川原桑柘稠。"]'),
('a7fc9e84-5406-414d-b84e-d6cfeaf18d2f','和于中丞登扶風亭','方干','唐','唐诗','tang','','[]','避石攀蘿去不迷，行時舉步似丹梯。',64,'全唐诗/poet.tang.36000.json','["避石攀蘿去不迷，行時舉步似丹梯。", "東軒海日已先照，下界晨雞猶未啼。", "郭裏雲山全占寺，村前竹樹半藏溪。", "謝公吟望多來此，此地應將峴首齊。"]'),
('23890fc3-a94b-4440-858e-a0e4359cbc09','贈信州高員外','方干','唐','唐诗','tang','','[]','溪勢盤回繞郡流，饒陽春色滿溪樓。',64,'全唐诗/poet.tang.36000.json','["溪勢盤回繞郡流，饒陽春色滿溪樓。", "豈唯啼鳥催人醉，更有繁花笑客愁。", "蹇拙命中迷直道，仁慈風裏駐扁舟。", "膺門若感深恩去，終殺微軀未足酬。"]'),
('97ffa4ab-cabb-4bc5-804a-d51ea5afdfc5','漳州于使君罷郡如之任漳南去上國二十四州使君無非親故','方干','唐','唐诗','tang','','[]','漳南罷郡如之任，二十四州相次迎。',48,'全唐诗/poet.tang.36000.json','["漳南罷郡如之任，二十四州相次迎。", "泊岸旗幡郵吏拜，連山風雨探人行。", "月中倚棹吟漁浦，花底垂鞭醉鳳城。"]'),
('fdec4fa2-f3a0-4ff0-a2e7-df910aa4d5f8','送弟子伍秀才赴舉','方干','唐','唐诗','tang','','[]','天遣相門延積慶，今同太廟薦嘉賓。',64,'全唐诗/poet.tang.36000.json','["天遣相門延積慶，今同太廟薦嘉賓。", "柳條此日同誰折，桂樹明年爲爾春。", "倚棹寒吟漁浦月，垂鞭醉入鳳城塵。", "由來不要文章得，要且文章出衆人。"]'),
('ed461f61-6556-44c0-a5ef-5495da32eeec','貽高讜','方干','唐','唐诗','tang','','[]','都緣相府有宗兄，却恐妨君正路行。',64,'全唐诗/poet.tang.36000.json','["都緣相府有宗兄，却恐妨君正路行。", "石上長松自森秀，雪中孤玉更凝明。", "西陵曉月中秋色，北固軍鼙半夜聲。", "幸有清才與洪筆，何愁高節不公卿。"]'),
('b730dd33-0194-4192-ba53-6fd2400e3ad8','題長洲陳明府小亭','方干','唐','唐诗','tang','','[]','坐看孤峭却勞神，還是微吟到日曛。',64,'全唐诗/poet.tang.36000.json','["坐看孤峭却勞神，還是微吟到日曛。", "松鶴認名呼得下，沙蟬飛處聽猶聞。", "夜闌亦似深山月，雨後唯關滿屋雲。", "便此逍遙應不易，朱衣紅斾未容君。"]'),
('beb07467-6eed-45ec-bc9d-d7d5b25d3786','送朱二十赴漣水','方干','唐','唐诗','tang','','[]','到縣却應嫌水闊，離家終是見山疎。',64,'全唐诗/poet.tang.36000.json','["到縣却應嫌水闊，離家終是見山疎。", "笙歌不駐難辭酒，舟檝將行負擔書。", "爲政必能安楚老，向公猶可釣淮魚。", "鸞凰取便多如此，掠地斜飛上太虛。"]'),
('51229c91-cca0-47c8-a852-df998ee7bc06','德政上睦州胡中丞','方干','唐','唐诗','tang','','[]','上德由來合動天，旌旗到日是豐年。',64,'全唐诗/poet.tang.36000.json','["上德由來合動天，旌旗到日是豐年。", "羣書已熟無人似，五字研成舉世傳。", "莫道政聲同宇宙，須知紫氣滿山川。", "豈唯里巷皆蘇息，猶有恩波及釣船。"]'),
('34a43b74-4edd-44bb-ae10-2f9e13dc7730','袁明府以家醖寄余余以山梅答贈非唯四韻兼亦雙關','方干','唐','唐诗','tang','','[]','封匏寄酒提攜遠，織籠盛梅答贈遲。',64,'全唐诗/poet.tang.36000.json','["封匏寄酒提攜遠，織籠盛梅答贈遲。", "九度攪和誰用法，四邊窺摘自攀枝。", "罇罍泛蟻堪嘗日，童稚驅禽欲熟時。", "畢卓醉狂潘氏少，傾來擲去恰相宜。"]'),
('85ae6a7f-804d-4e56-9530-46037811b29d','上杭州姚郎中','方干','唐','唐诗','tang','','[]','能除疾瘼似良醫，一郡鄉風當日移。',64,'全唐诗/poet.tang.36000.json','["能除疾瘼似良醫，一郡鄉風當日移。", "身貴久離行藥伴，才高獨作後人師。", "春遊下馬皆成醼，吏散看山即有詩。", "借問公方與文道，而今中夏更傳誰。"]'),
('2d9229ab-880d-442a-bb15-0f3766fdbefa','送葉秀才赴舉兼呈呂少監','方干','唐','唐诗','tang','','[]','君辭舊里一年期，藝至心身亦自知。',64,'全唐诗/poet.tang.36000.json','["君辭舊里一年期，藝至心身亦自知。", "尊盡離人看北斗，月寒驚鵲繞南枝。", "書迴冊市砧應絕，棹出村潭菊未衰。", "與爾相逢終不遠，昨聞秘監在台墀。"]'),
('d3aaf758-19a6-407d-b2e8-37be27d5c577','自縉雲赴郡溪流百里輕棹一發曾不崇朝敘事四韻寄獻段郎中','方干','唐','唐诗','tang','','[]','激箭溪湍勢莫憑，飄然一葉若爲乘。',64,'全唐诗/poet.tang.36000.json','["激箭溪湍勢莫憑，飄然一葉若爲乘。", "仰瞻青壁開天罅，斗轉寒灣避石稜。", "巢鳥夜驚離島樹，啼猿晝怯下巖藤。", "此中明日尋知己，恐似龍門不易登。"]'),
('65a418eb-3ed3-4581-8772-7c5d32023d24','胡中丞早梅','方干','唐','唐诗','tang','','[]','不獨閑花不共時，一株寒豔尚參差。',64,'全唐诗/poet.tang.36000.json','["不獨閑花不共時，一株寒豔尚參差。", "凌晨未噴含霜朵，應候先開亞水枝。", "芬郁合將蘭竝茂，凝明應與雪相宜。", "謝公吟賞愁飄落，可得更拈長笛吹。"]'),
('1f175f8d-0a34-47c7-aaf5-6851c06cac2a','牡丹','方干','唐','唐诗','tang','','[]','借問庭芳早晚栽，座中疑展畫屏開。',64,'全唐诗/poet.tang.36000.json','["借問庭芳早晚栽，座中疑展畫屏開。", "花分淺淺臙脂臉，葉墮殷殷膩粉腮。", "紅砌不須誇芍藥，白蘋何用逞重臺。", "慇懃爲報看花客，莫學遊蜂日日來。"]'),
('6f535e3b-37eb-4733-9014-658a90e965c4','觀項信水墨','方干','唐','唐诗','tang','','[]','險峭雖從筆下成，精能皆自意中生。',64,'全唐诗/poet.tang.36000.json','["險峭雖從筆下成，精能皆自意中生。", "倚雲孤檜知無朽，挂壁高泉似有聲。", "轉扇驚波連岸動，迴燈落日向山明。", "小年師祖過今祖，異域應傳項信名。"]'),
('4af061fd-f83e-4f62-954c-0c43a1a52d40','書桃花塢周處士壁','方干','唐','唐诗','tang','','[]','醉吟雪月思深苦，思苦神勞華髪生。',64,'全唐诗/poet.tang.36000.json','["醉吟雪月思深苦，思苦神勞華髪生。", "自學古賢修靜節，唯應野鶴識高情。", "細泉出石飛難盡，孤燭和雲濕不明。", "何事嬾於嵇叔夜，更無書札答公卿。"]'),
('6ef6063d-a846-408a-8bd0-03b414728b00','題桐廬謝逸人江居','方干','唐','唐诗','tang','','[]','少小高眠無一事，五侯勳盛欲如何。',64,'全唐诗/poet.tang.36000.json','["少小高眠無一事，五侯勳盛欲如何。", "湖邊倚仗寒吟苦，石上橫琴夜醉多。", "鳥自樹梢隨果落，人從窗外卸帆過。", "由來朝市爲真隱，可要棲身向薜蘿。"]'),
('1bd00edd-4bb4-4361-91ec-5d936ba754eb','敘雪寄喻鳧','方干','唐','唐诗','tang','','[]','密片無聲急復遲，紛紛猶勝落花時。',64,'全唐诗/poet.tang.36000.json','["密片無聲急復遲，紛紛猶勝落花時。", "從容不覺藏苔逕，宛轉偏宜傍柳絲。", "透室虛明非月照，滿空迴散是風吹。", "高人坐臥才方逸，援筆應成六出詞。"]'),
('0013efd8-546f-4eaa-8152-876fbad71de5','又敘雪寄喻鳧','方干','唐','唐诗','tang','','[]','密片繁聲旋不銷，縈風雜霰轉飄颻。',64,'全唐诗/poet.tang.36000.json','["密片繁聲旋不銷，縈風雜霰轉飄颻。", "澄江莫蔽長流色，衰柳難黏自動條。", "濕氣添寒酤酒夜，素花迎曙卷簾朝。", "此時明逕無行跡，唯望徽之問寂寥。"]'),
('580d7c16-f26c-4682-b843-92dc7227880d','哭秘書姚少監','方干','唐','唐诗','tang','','[]','寒空此夜落文星，星落文留萬古名。',64,'全唐诗/poet.tang.36000.json','["寒空此夜落文星，星落文留萬古名。", "入室幾人成弟子，爲儒是處哭先生。", "家無諫草逢明代，國有遺篇續正聲。", "曉向平原陳葬禮，悲風吹雨濕銘旌。"]'),
('55c08e91-b311-45bc-b944-4fb7d5edbe43','送人宰永泰','方干','唐','唐诗','tang','','[]','北人雖泛南流水，稱意南行莫恨賒。',64,'全唐诗/poet.tang.36000.json','["北人雖泛南流水，稱意南行莫恨賒。", "道路先經毛竹嶺，風煙漸近刺桐花。", "舟停漁浦猶爲客，縣入樵溪似到家。", "下馬政聲王事少，應容閑吏日高衙。"]'),
('49a003d9-bac0-4745-9dc2-58fb0c2fb266','旅次洋州寓居郝氏林亭','方干','唐','唐诗','tang','','["\u601d\u4e61", "\u611f\u4f24", "\u5199\u666f"]','舉目縱然非我有，思量似在故山時。',64,'全唐诗/poet.tang.36000.json','["舉目縱然非我有，思量似在故山時。", "鶴盤遠勢投孤嶼，蟬曳殘聲過別枝。", "涼月照窗欹枕倦，澄泉遶石泛觴遲。", "青雲未得平行去，夢到江南身旅羇。"]'),
('d14107ed-9502-4b0e-ab11-ffa35978b7a9','茅山贈洪拾遺','方干','唐','唐诗','tang','','[]','聖代諫臣停諫舌，求歸故里傲雲霞。',64,'全唐诗/poet.tang.36000.json','["聖代諫臣停諫舌，求歸故里傲雲霞。", "溪頭講樹纜漁艇，篋裏朝衣輸酒家。", "但愛身閑辭祿俸，那嫌歲計在桑麻。", "我來幸與諸生異，問答時容近絳紗。"]'),
('1e5d4e6e-dd62-4def-8857-9a7a1bf525e6','睦州呂郎中郡中環溪亭','方干','唐','唐诗','tang','','[]','爲是仙才登望處，風光便似武陵春。',64,'全唐诗/poet.tang.36000.json','["爲是仙才登望處，風光便似武陵春。", "閑花半落猶迷蝶，白鳥雙飛不避人。", "樹影興餘侵枕簟，荷香坐久著衣巾。", "暫來此地非多日，明主那容借寇恂。"]'),
('698985e5-f06c-4ea2-af3e-599b9e7ca958','贈華陰隱者','方干','唐','唐诗','tang','','[]','少微夜夜當仙掌，更有何人在此居。',64,'全唐诗/poet.tang.36000.json','["少微夜夜當仙掌，更有何人在此居。", "花月舊應看浴鶴，松蘿本自伴刪書。", "素琴醉去經宵枕，衰髪寒來向日梳。", "故國多年歸未遂，因逢此地憶君廬。"]'),
('9e4e4ba5-3431-47b0-ae7f-cf18fb9b02a3','上杭州杜中丞','方干','唐','唐诗','tang','','[]','昔用雄才登上第，今將重德合明君。',64,'全唐诗/poet.tang.36000.json','["昔用雄才登上第，今將重德合明君。", "苦心多爲安民術，援筆皆成出世文。", "寒角細吹孤嶠月，秋濤橫卷半江雲。", "掠天逸勢應非久，一鶚那棲衆鳥羣。"]'),
('0d049c01-a2b0-4d7e-bda5-6fa098dd100f','贈處州段郎中','方干','唐','唐诗','tang','','[]','幸見仙才領郡初，郡城孤峭似仙居。',64,'全唐诗/poet.tang.36000.json','["幸見仙才領郡初，郡城孤峭似仙居。", "杉蘿色裏遊亭榭，瀑布聲中閱簿書。", "德重自將天子合，情高元與世人疎。", "寒潭是處清連底，賓席何心望食魚。"]'),
('bf0fab86-68e7-439a-a314-53db63afebe6','書法華寺上方禪壁','方干','唐','唐诗','tang','','[]','砌下松巔有鶴棲，孤猿亦在鶴邊啼。',64,'全唐诗/poet.tang.36000.json','["砌下松巔有鶴棲，孤猿亦在鶴邊啼。", "臥聞雷雨歸巖早，坐見星辰去地低。", "一逕穿緣應就郭，千花掩映似無溪。", "是非生死多憂惱，此日蒙師爲破迷。"]'),
('64f0f921-339b-4608-9b43-830a0b49f218','書吳道隱林亭','方干','唐','唐诗','tang','','[]','蘚榭莎亭蘿篠陰，依稀氣象似山林。',64,'全唐诗/poet.tang.36000.json','["蘚榭莎亭蘿篠陰，依稀氣象似山林。", "橘枝亞路黃苞重，井脈牽湖碧甃深。", "稚子遮門留熟客，驚蟬入座避遊禽。", "四鄰不見孤高處，翻笑騰騰只醉吟。"]'),
('a0b41f5a-e7c8-48c7-bf5d-9ec3c8d713d9','陪王大夫泛湖','方干','唐','唐诗','tang','','[]','去去凌晨迴見星，木蘭舟穩畫橈輕。',64,'全唐诗/poet.tang.36000.json','["去去凌晨迴見星，木蘭舟穩畫橈輕。", "白波潭上魚龍氣，紅樹林中雞犬聲。", "蜜炬燒殘銀漢昃，羽觴飛急玉山傾。", "此時檢點諸名士，却是漁翁無姓名。"]'),
('11bba374-5127-4853-9eae-e243cb86d54d','贈會稽張少府','方干','唐','唐诗','tang','','[]','高節何曾似任官，藥苗香潔備常餐。',64,'全唐诗/poet.tang.36000.json','["高節何曾似任官，藥苗香潔備常餐。", "一分酒戶添猶得，五字詩名隱即難。", "笑我無媒生鶴髪，知君有意憶漁竿。", "明年莫便還家去，鏡裏雲山且共看。"]'),
('dad56060-a0a2-4084-8b52-d172fd264080','送鄭台處士歸絳巖','方干','唐','唐诗','tang','','[]','榮啓先生挾琴去，厭尋靈勝憶巖栖。',64,'全唐诗/poet.tang.36000.json','["榮啓先生挾琴去，厭尋靈勝憶巖栖。", "白猿垂樹窗邊月，紅鯉驚鉤竹外溪。", "慣採藥苗供野饌，曾書蕉葉寄新題。", "古賢猶愴河梁別，未可怱怱便解攜。"]'),
('de86f00f-9cb8-416f-bfd8-1587f7a44a8f','因話天台勝異仍送羅道士','方干','唐','唐诗','tang','','[]','積翠千層一徑開，遙盤山腹到瓊臺。',64,'全唐诗/poet.tang.36000.json','["積翠千層一徑開，遙盤山腹到瓊臺。", "藕花飄落前巖去，桂子流從別洞來。", "石上叢林礙星斗，窗邊瀑布走風雷。", "縱云孤鶴無留滯，定恐煙蘿不放迴。"]'),
('01c487bc-5775-4c13-8a61-3216b4bbbc63','哭喻鳧先輩','方干','唐','唐诗','tang','','[]','日夜役神多損壽，先生下世未中年。',64,'全唐诗/poet.tang.36000.json','["日夜役神多損壽，先生下世未中年。", "撰碑縱託登龍伴，營奠應支賣鶴錢。", "孤壠陰風吹細草，空窗濕氣漬殘篇。", "人間別更無冤事，到此誰能與問天。"]'),
('314bd64b-c7d2-40e5-8c72-3c5677414ef2','湖北有茅齋湖西有松島輕棹往返頗諧素心因成四韻','方干','唐','唐诗','tang','','[]','湖北湖西往復還，朝昏只處自由間。',64,'全唐诗/poet.tang.36000.json','["湖北湖西往復還，朝昏只處自由間。", "暑天移榻就深竹，月夜乘舟歸淺山。", "遶砌紫鱗欹枕釣，垂簷野果隔窗攀。", "古賢暮齒方如此，多笑愚儒鬢未斑。"]'),
('4d5603e7-c931-48b0-a94b-3be81dbda988','鑑湖西島言事','方干','唐','唐诗','tang','','[]','慵拙幸便荒僻地，縱聽猨鳥亦何愁。',64,'全唐诗/poet.tang.36000.json','["慵拙幸便荒僻地，縱聽猨鳥亦何愁。", "偶斟藥酒欺梅雨，却著寒衣過麥秋。", "歲計有時添橡實，生涯一半在漁舟。", "世人若便無知己，應向此溪成白頭。"]'),
('86eb8fc6-f33d-44a3-850a-2d879467406f','山中言事','方干','唐','唐诗','tang','','[]','欹枕亦吟行亦醉，臥吟行醉更何營。',64,'全唐诗/poet.tang.36000.json','["欹枕亦吟行亦醉，臥吟行醉更何營。", "貧來猶有故琴在，老去不過新髪生。", "山鳥踏枝紅果落，家童引釣白魚驚。", "潛夫自有孤雲侶，可要王侯知姓名。"]'),
('8aca568e-ef41-4db0-b1c0-7489e5640c45','贈蕭山彭少府','方干','唐','唐诗','tang','','[]','作尉孜孜更寒苦，操心至癖不爲清。',64,'全唐诗/poet.tang.36000.json','["作尉孜孜更寒苦，操心至癖不爲清。", "雖將劍鶴支殘債，猶有歌篇取盛名。", "盡擬勤求爲弟子，皆將疑義問先生。", "與君相識因儒術，歲月彌多別有情。"]'),
('03368df1-771c-489b-964f-a094084d86ab','贈式上人','方干','唐','唐诗','tang','','[]','縱居鼙角喧闐處，亦共雲溪邃僻同。',64,'全唐诗/poet.tang.36000.json','["縱居鼙角喧闐處，亦共雲溪邃僻同。", "萬慮全離方寸內，一生多在五言中。", "芰荷葉上難停雨，松檜枝間自有風。", "莫笑旅人終日醉，吾將大醉與禪通。"]'),
('698608ee-0eff-4d41-9fd5-57bbd7991016','贈錢塘湖上唐處士','方干','唐','唐诗','tang','','["\u897f\u6e56", "\u6d1e\u5ead\u6e56"]','我愛君家似洞庭，衝灣潑岸夜波聲。',64,'全唐诗/poet.tang.36000.json','["我愛君家似洞庭，衝灣潑岸夜波聲。", "蟾蜍影裏清吟苦，舴艋舟中白髮生。", "常共酒杯爲侶伴，復聞紗帽見公卿。", "莫言舉世無知己，自有孤雲識此情。"]'),
('7e788505-144a-49bf-a394-5fdc3fd76a6f','山中言事','方干','唐','唐诗','tang','','[]','日與村家事漸同，燒松啜茗學鄰翁。',64,'全唐诗/poet.tang.36000.json','["日與村家事漸同，燒松啜茗學鄰翁。", "池塘月撼芙蕖浪，窗戶涼生薜荔風。", "書幌晝昏嵐氣裏，巢枝俯折雪聲中。", "山陰釣叟無知己，窺鏡撏多鬢欲空。"]'),
('219840bc-43a1-4319-b302-8ee40a49b3c5','題陶詳校書陽羨隱居','方干','唐','唐诗','tang','','[]','芸香署裏從容步，陽羨山中嘯傲情。',64,'全唐诗/poet.tang.36000.json','["芸香署裏從容步，陽羨山中嘯傲情。", "竿底紫鱗輸釣伴，花邊白犬吠流鶯。", "長潭五月含冰氣，孤檜中宵學雨聲。", "便泛扁舟應未得，鴟夷棄相始垂名。"]'),
('e2f87f2a-df54-481f-9c30-f42de1929152','秋晚林中寄賓幕','方干','唐','唐诗','tang','','[]','八月蕭條九月時，沙蟬海燕各分飛。',64,'全唐诗/poet.tang.36000.json','["八月蕭條九月時，沙蟬海燕各分飛。", "杯盂未稱嘗生酒，砧杵先催試熟衣。", "泉漱玉聲衝石竇，橘垂朱實壓荆扉。", "無過縱有家山思，印綬留連爭得歸。"]'),
('a79294e3-38ff-4617-bb89-b0ddbcc62ef0','與鄉人鑒休上人別','方干','唐','唐诗','tang','','[]','此日因師話鄉里，故鄉風土我偏諳。',64,'全唐诗/poet.tang.36000.json','["此日因師話鄉里，故鄉風土我偏諳。", "一枝竹葉如溪北，半樹梅花似嶺南。", "山夜獵徒多信犬，雨天村舍未催蠶。", "如今休作還家意，兩鬚垂絲已不堪。"]'),
('7bdd79ba-21f7-467d-96a0-a6201acfc39c','送王霖赴舉','方干','唐','唐诗','tang','','[]','自古主司看薦士，明年應是不參差。',64,'全唐诗/poet.tang.36000.json','["自古主司看薦士，明年應是不參差。", "須憑吉夢爲先兆，必恐長才偶盛時。", "北闕上書衝雪早，西陵中酒趂潮遲。", "郄詵可要真消息，只向春前便得知。"]'),
('1d0bd591-16cb-4cbb-8082-517f3c5ef211','思越中舊遊寄友','方干','唐','唐诗','tang','','[]','甸外山川無越國，依稀只似劍門西。',64,'全唐诗/poet.tang.36000.json','["甸外山川無越國，依稀只似劍門西。", "鏡中疊浪搖星斗，城上繁花咽鼓鼙。", "斷臂青猿啼玉笥，成行白鳥下耶溪。", "此中曾是同遊處，迢遞尋君夢不迷。"]'),
('93e8fe54-0498-46a2-8564-59cf7b27ea50','陪胡中丞泛湖','方干','唐','唐诗','tang','','[]','仙舟仙藥醉行春，上界稀逢下界人。',64,'全唐诗/poet.tang.36000.json','["仙舟仙藥醉行春，上界稀逢下界人。", "綺繡峰前聞野鶴，旌旗影裏見遊鱗。", "澄潭徹底齊心鏡，雜樹含芳讓錦茵。", "凡許從容誰不幸，就中光顯是州民。"]'),
('d2c3b930-6ef4-4548-8dd8-f544f2381e79','敘雪獻員外','方干','唐','唐诗','tang','','[]','紛紜宛轉更堪看，壓竹摧巢井徑漫。',64,'全唐诗/poet.tang.36000.json','["紛紜宛轉更堪看，壓竹摧巢井徑漫。", "風柳細條粘不得，春溪綠色蔽應難。", "清輝直認中庭月，濕氣偏添半夜寒。", "謝守來吟才更逸，郢詞先至彩毫端。"]'),
('5e08d19b-a0bb-48dc-b561-1ec365edbf2f','王將軍','方干','唐','唐诗','tang','','[]','大志無心守章句，終懷上畧致殊功。',64,'全唐诗/poet.tang.36000.json','["大志無心守章句，終懷上畧致殊功。", "保寧帝業青萍在，投棄儒書絳帳空。", "密雪曙連葱嶺道，青松夜起柳營風。", "將星依舊當文座，應念愚儒命未通。"]'),
('19118f03-caa0-4c76-9dcf-582138961a18','陽亭言事獻漳州于使君','方干','唐','唐诗','tang','','[]','重疊山前對酒罇，騰騰兀兀度朝昏。',64,'全唐诗/poet.tang.36000.json','["重疊山前對酒罇，騰騰兀兀度朝昏。", "平明疎磬白雲寺，遙夜孤砧紅葉村。", "去鳥豈知煙樹遠，驚魚應覺露荷翻。", "旅人寄食逢黃菊，每見故人思故園。"]'),
('ba970512-e02b-48c0-bf95-d18e3a2bc599','海石榴','方干','唐','唐诗','tang','','[]','亭際夭妍日日看，每朝顏色一般般。',64,'全唐诗/poet.tang.36000.json','["亭際夭妍日日看，每朝顏色一般般。", "滿枝猶待春風力，數朵先欺臘雪寒。", "舞蝶似隨歌拍轉，遊人只怕酒杯乾。", "久長年少應難得，忍不叢邊到夜觀。"]'),
('f77afa59-211a-41fc-9f77-3f4b5823b370','嘉興許明府','方干','唐','唐诗','tang','','[]','檇李轉聞風教好，重門夜不上重關。',64,'全唐诗/poet.tang.36000.json','["檇李轉聞風教好，重門夜不上重關。", "腰懸墨綬三年外，身去青雲一步間。", "勤苦字人酬帝力，從容對客問家山。", "升沈路別情猶在，不忘鄉中舊往還。"]'),
('18450793-5eda-461d-8116-5d6d6ee367b5','再題路支使南亭','方干','唐','唐诗','tang','','[]','行處避松兼礙石，即須門徑落斜開。',64,'全唐诗/poet.tang.36000.json','["行處避松兼礙石，即須門徑落斜開。", "愛邀舊友看漁釣，貪聽新禽駐酒杯。", "樹影不隨明月去，溪聲常送落花來。", "睡時分得江淹夢，五色毫端弄逸才。"]'),
('b0ca1ce6-b3b0-419e-96b8-1cee5eb75a66','路支使小池','方干','唐','唐诗','tang','','[]','廣狹偶然非製定，猶將方寸像滄溟。',64,'全唐诗/poet.tang.36000.json','["廣狹偶然非製定，猶將方寸像滄溟。", "一泓春水無多浪，數尺晴天幾箇星。", "露滿玉盤當半夜，匣開金鏡在中庭。", "主人垂釣常來此，雖把魚竿醉未醒。"]'),
('f7e0d0d6-2063-4b07-bafd-01bc247f209f','哭江西處士陳陶','方干','唐','唐诗','tang','','[]','壽盡天年命不通，釣溪吟月便成翁。',64,'全唐诗/poet.tang.36000.json','["壽盡天年命不通，釣溪吟月便成翁。", "雖云掛劍來墳上，亦恐藏書在壁中。", "巢父精靈歸大夜，客兒才調振遺風。", "南華至理須齊物，生死即應無異同。"]'),
('9813c7bf-4e9f-4077-8c55-51a920e30c98','越中言事二首 一','方干','唐','唐诗','tang','','[]','異術閑和合聖明，湖光浩氣共澄清。',64,'全唐诗/poet.tang.36000.json','["異術閑和合聖明，湖光浩氣共澄清。", "郭中雲吐啼猿寺，山上花藏調角城。", "香起荷灣停棹飲，絲垂柳陌約鞭行。", "遊人今日又明日，不覺鏡中新髪生。"]'),
('4b945626-9876-42b1-aaf5-604eef9071ec','越中言事二首 二','方干','唐','唐诗','tang','','[]','雲霞水木共蒼蒼，元化分功秀一方。',64,'全唐诗/poet.tang.36000.json','["雲霞水木共蒼蒼，元化分功秀一方。", "百里湖波輕撼月，五更軍角慢吹霜。", "沙邊賈客喧魚市，島上潛夫醉笋莊。", "終歲逍遙仁術內，無名甘老買臣鄉。"]'),
('bb219c41-8710-4792-9e73-33a0b4f27527','題龍瑞觀兼呈徐尊師','方干','唐','唐诗','tang','','[]','或雨或雲常不定，地靈雲雨自無時。',64,'全唐诗/poet.tang.36000.json','["或雨或雲常不定，地靈雲雨自無時。", "世人莫識神方字，仙鳥偏棲藥樹枝。", "遠壑度年如晦暝，陰溪入夏有凌澌。", "此中唯有師知我，未得尋師即夢師。"]'),
('7bd0bb5a-d305-4afc-80f0-d842dbdf023d','送陳秀才將遊霅上便議北歸','方干','唐','唐诗','tang','','[]','婆娑戀酒山花盡，繞繚還家水路通。',64,'全唐诗/poet.tang.36000.json','["婆娑戀酒山花盡，繞繚還家水路通。", "轉檝擬從青草岸，吹帆猶是白蘋風。", "淮邊欲暝軍鼙急，洛下先寒苑樹空。", "詩句因余更孤峭，書題不合忘江東。"]'),
('5e7eb93e-9294-474c-b83b-257898357a45','送吳彥融赴舉','方干','唐','唐诗','tang','','[]','用心精至自無疑，千萬人中似汝稀。',64,'全唐诗/poet.tang.36000.json','["用心精至自無疑，千萬人中似汝稀。", "上國纔將五字去，全家便待一枝歸。", "西陵柳路搖鞭盡，北固潮程掛席飛。", "想見明年榜前事，當時分散著來衣。"]'),
('8b68f064-cd74-4b78-867a-165b29488e28','同蕭山陳長官縣樓登望','方干','唐','唐诗','tang','','[]','坐看南北與西東，遠近無非禮義中。',64,'全唐诗/poet.tang.36000.json','["坐看南北與西東，遠近無非禮義中。", "一縣繁花香送雨，五株垂柳綠牽風。", "寒濤背海喧還靜，驛路穿林斷復通。", "仲叔受恩多感戀，裴回却怕酒壺空。"]'),
('0f9172b0-4e23-4bd3-8a8e-5de0ef6ad17b','送何道者','方干','唐','唐诗','tang','','[]','何事忽來還忽去，孤雲不定鶴情高。',64,'全唐诗/poet.tang.36000.json','["何事忽來還忽去，孤雲不定鶴情高。", "真經與術添年壽，靈藥分功入鬢毛。", "必擬一身生羽翼，終看陸地作波濤。", "遍尋巖洞求仙者，即恐無人似爾曹。"]'),
('1ee88668-70ec-4e83-866c-5f458783fc23','酬將作于少監','方干','唐','唐诗','tang','','[]','由來至寶出毫端，五色炎光照室寒。',64,'全唐诗/poet.tang.36000.json','["由來至寶出毫端，五色炎光照室寒。", "仰望孤峰知聳峻，前臨積水見波瀾。", "冰絲織絡經心久，瑞玉雕磨措手難。", "不是散齋兼拭目，尋常未便借人看。"]'),
('448178d2-a4fd-4881-80d6-dbbae17f5f88','雪中寄殷道士','方干','唐','唐诗','tang','','[]','大片紛紛小片輕，雨和風擊更縱橫。',64,'全唐诗/poet.tang.36000.json','["大片紛紛小片輕，雨和風擊更縱橫。", "園林入夜寒光動，窗戶凌晨濕氣生。", "蔽野吞村飄未歇，摧巢壓竹密無聲。", "山陰道士吟多興，六出花邊五字成。"]'),
('6da6fa2f-1363-47fa-bc30-f4e58f4c2118','宋從事','方干','唐','唐诗','tang','','[]','出衆仙才是謫仙，裁霞曳繡一篇篇。',64,'全唐诗/poet.tang.36000.json','["出衆仙才是謫仙，裁霞曳繡一篇篇。", "雖將潔白酬知己，自有風流助少年。", "欹枕臥吟荷葉雨，持杯坐醉菊花天。", "冥搜太苦神應乏，心在虛無更那邊。"]'),
('38e4dc8c-ad08-42b7-ad37-f567ca0e0104','出山寄蘇從事','方干','唐','唐诗','tang','','[]','寸心似火頻求薦，兩鬢如霜始息機。',64,'全唐诗/poet.tang.36000.json','["寸心似火頻求薦，兩鬢如霜始息機。", "隔岸雞鳴春耨去，鄰家犬吠夜漁歸。", "倚松長嘯宜疎拙，拂石欹眠絕是非。", "多謝元瑜憐野賤，時迴車馬發光輝。"]'),
('9db8c539-b088-4546-89fd-6a8b06278601','送杭州李員外','方干','唐','唐诗','tang','','[]','政成何用滿三年，上界羣仙待謫仙。',64,'全唐诗/poet.tang.36000.json','["政成何用滿三年，上界羣仙待謫仙。", "便赴新恩歸紫禁，還從舊路上青天。", "笙歌怨咽當離席，更漏丁東在畫船。", "必恐駐班留立位，前程一步是爐煙。"]'),
('6d49094f-55f8-4c88-ba18-2aabc71e7130','贈李支使','方干','唐','唐诗','tang','','[]','藥成平地是寥天，三十人中最少年。',64,'全唐诗/poet.tang.36000.json','["藥成平地是寥天，三十人中最少年。", "白雪振聲來輦下，青雲開路到牀前。", "公卿位近應翹足，荀宋才微可拍肩。", "一等孔門爲弟子，愚儒獨自賦歸田。"]'),
('f390f8db-8215-45fe-900e-b2b3f728a0ba','盧卓山人畫水','方干','唐','唐诗','tang','','[]','常聞畫石不畫水，畫水至難君得名。',64,'全唐诗/poet.tang.36000.json','["常聞畫石不畫水，畫水至難君得名。", "海色未將藍汁染，筆鋒猶傍墨花行。", "散吞高下應無岸，斜蹙東南勢欲傾。", "坐久神迷不能決，却疑身在小蓬瀛。"]'),
('e622114b-9dec-44cd-9335-d0aa5c5d37d2','廢宅','方干','唐','唐诗','tang','','[]','主人何處獨裴回，流水自流花自開。',64,'全唐诗/poet.tang.36000.json','["主人何處獨裴回，流水自流花自開。", "若見故交皆散去，即應新燕不歸來。", "入門繚繞穿荒竹，坐石逡巡染綠苔。", "應是曾經惡風雨，修桐半折損琴材。"]'),
('9713e138-57fe-4bae-a364-8f38cd449bf6','題寶林山禪院','方干','唐','唐诗','tang','','[]','山捧亭臺郭遶山，遙盤蒼翠到山巔。',64,'全唐诗/poet.tang.36000.json','["山捧亭臺郭遶山，遙盤蒼翠到山巔。", "嵒中古井雖通海，窟裏陰雲不上天。", "羅列衆星依木末，周迴萬室在簷前。", "我來可要歸禪老，一寸寒灰已達玄。"]'),
('805df95b-c30d-4773-ac47-68f6574f6d81','題越州袁秀才林亭','方干','唐','唐诗','tang','','[]','清邃林亭指畫開，幽巖別派像天台。',64,'全唐诗/poet.tang.36000.json','["清邃林亭指畫開，幽巖別派像天台。", "坐牽蕉葉題詩句，醉觸藤花落酒杯。", "白鳥不歸山裏去，紅鱗多自鏡中來。", "終年此地爲吟伴，早起尋君薄暮迴。"]'),
('81f683ef-6473-46a1-bb41-7d1888aaad58','題龜山穆上人院','方干','唐','唐诗','tang','','[]','修持百法過半百，日往月來心更堅。',64,'全唐诗/poet.tang.36000.json','["修持百法過半百，日往月來心更堅。", "牀上水雲隨坐夏，林西山月伴行禪。", "寒蜩遠韻來窗裏，白鳥斜行起砌邊。", "我愛尋師師訪我，只應尋訪是因緣。"]'),
('08db89b6-4d7c-4074-8bd6-3b33ebbde829','贈美人四首 一','方干','唐','唐诗','tang','','[]','直緣多藝用心勞，心路玲瓏格調高。',64,'全唐诗/poet.tang.36000.json','["直緣多藝用心勞，心路玲瓏格調高。", "舞袖低徊真蛺蝶，朱唇深淺假櫻桃。", "粉胸半掩疑晴雪，醉眼斜迴小樣刀。", "才會雨雲須別去，語慙不及琵琶槽。"]'),
('0d9deda2-45b5-48e1-87df-5ac40d378827','贈美人四首 二','方干','唐','唐诗','tang','','[]','嚴冬忽作看花日，盛暑翻爲見雪時。',64,'全唐诗/poet.tang.36000.json','["嚴冬忽作看花日，盛暑翻爲見雪時。", "坐上弄嬌聲不轉，尊前掩笑意難知。", "含歌媚盼如桃葉，妙舞輕盈似柳枝。", "年幾未多猶怯在，些些私語怕人疑。"]'),
('205e4696-114f-411a-b878-207f4252123d','贈美人四首 三','方干','唐','唐诗','tang','','[]','酒蘊天然自性靈，人間有藝總關情。',64,'全唐诗/poet.tang.36000.json','["酒蘊天然自性靈，人間有藝總關情。", "剝葱十指轉籌疾，舞柳細腰隨拍輕。", "常恐胸前春雪釋，惟愁座上慶雲生。", "若教梅尉無仙骨，爭得仙娥駐玉京。"]'),
('05b510f0-bbe5-4fc3-b5eb-aadb25008942','贈美人四首 四','方干','唐','唐诗','tang','','[]','昔日仙人今玉人，深冬相見亦如春。',64,'全唐诗/poet.tang.36000.json','["昔日仙人今玉人，深冬相見亦如春。", "倍酬金價微含笑，纔發歌聲早動塵。", "昔歲曾爲蕭史伴，今朝應作宋家鄰。", "百年別後知誰在，須遣丹青畫取真。"]'),
('2ac33c00-bd81-45a3-a893-f18aa9617e71','聽段處士彈琴','方干','唐','唐诗','tang','','[]','幾年調弄七條絲，元化分功十指知。',64,'全唐诗/poet.tang.36000.json','["幾年調弄七條絲，元化分功十指知。", "泉迸幽音離石底，松含細韻在霜枝。", "窗中顧兔初圓夜，竹上寒蟬盡散時。", "唯有此時心更靜，聲聲可作後人師。"]'),
('d7062bbc-428a-46cc-a9da-a03c3fece818','初歸鏡中寄陳端公','方干','唐','唐诗','tang','','[]','去歲離家今歲歸，孤帆夢向鳥前飛。',64,'全唐诗/poet.tang.36000.json','["去歲離家今歲歸，孤帆夢向鳥前飛。", "必知蘆笋侵沙井，兼被藤花占石磯。", "雲島採茶常失路，雪龕中酒不關扉。", "故交若問逍遙事，玄冕何曾勝葦衣。"]'),
('13933f4a-f8e9-4914-a2af-8f652a6649cb','再題龍泉寺上方','方干','唐','唐诗','tang','','[]','牛斗正齊羣木末，鳥行橫截衆山腰。',64,'全唐诗/poet.tang.36000.json','["牛斗正齊羣木末，鳥行橫截衆山腰。", "路盤砌下兼穿竹，井在巖頭亦統潮。", "海岸四更看日出，石房三月任花燒。", "未能割得繁華去，難向此中甘寂寥。"]'),
('804bd3c9-3828-4e3c-a217-bc1e3995b88b','于秀才小池','方干','唐','唐诗','tang','','[]','一泓瀲灧復澄明，半日功夫斸小庭。',66,'全唐诗/poet.tang.36000.json','["一泓瀲灧復澄明，半日功夫斸小庭。", "占地未過四五尺，浸天唯入兩三星。", "鷁舟草際浮霜葉，[漁]火沙邊駐小螢。", "纔見規模識方寸，知君立意象滄溟。"]'),
('d4bb6bb4-0a1a-4ac0-9103-8e34e6a2347d','敘錢塘異勝','方干','唐','唐诗','tang','','[]','暖景融融寒景清，越臺風送曉鐘聲。',64,'全唐诗/poet.tang.36000.json','["暖景融融寒景清，越臺風送曉鐘聲。", "四郊遠火燒煙月，一道驚波撼郡城。", "夜雪未知東岸綠，春風猶放半江晴。", "謝公吟處依稀在，千古無人繼盛名。"]'),
('ec3bb929-3cb1-47fe-ab85-27f0f9a04359','贈中巖王處士','方干','唐','唐诗','tang','','[]','垂楊褭褭草芊芊，氣象清深似洞天。',64,'全唐诗/poet.tang.36000.json','["垂楊褭褭草芊芊，氣象清深似洞天。", "援筆便成鸚鵡賦，洗花須用桔槔泉。", "商於避世堪同日，渭曲逢時必有年。", "直恐剛腸閑未得，醉吟爭奈被才牽。"]'),
('ecad7cb7-d844-4261-8828-774ea7096f54','初歸故里獻侯郎中','方干','唐','唐诗','tang','','[]','常思舊里欲歸難，已作歸心即自寬。',64,'全唐诗/poet.tang.36000.json','["常思舊里欲歸難，已作歸心即自寬。", "此日早知無爵位，當時便合把漁竿。", "朝昏入閏春將逼，城邑多山夏却寒。", "不是幽愚望榮忝，君侯異禮亦何安。"]'),
('b920e66d-5611-4e4a-9050-b93061ca9d08','歸睦州中路寄侯郎中','方干','唐','唐诗','tang','','[]','顏巷蕭條知命後，膺門感激受恩初。',64,'全唐诗/poet.tang.36000.json','["顏巷蕭條知命後，膺門感激受恩初。", "却容鶴髪還蝸舍，猶夢漁竿從隼旟。", "新定暮雲吞故國，會稽春草入貧居。", "鄉中自古爲儒者，誰得公侯降尺書。"]'),
('cf96d9bb-5f35-4d4a-bf12-3d21e39ea74f','題報恩寺上方','方干','唐','唐诗','tang','','[]','來來先上上方看，眼界無窮世界寬。',64,'全唐诗/poet.tang.36000.json','["來來先上上方看，眼界無窮世界寬。", "巖溜噴空晴似雨，林蘿礙日夏多寒。", "衆山迢遞皆相疊，一路高低不記盤。", "清峭關心惜歸去，他時夢到亦難判。"]'),
('7cd871a4-1f4a-4295-95a2-54080a243a70','送永嘉王令之任二首 一','方干','唐','唐诗','tang','','[]','定擬孜孜化海邊，須判素髪侮流年。',64,'全唐诗/poet.tang.36000.json','["定擬孜孜化海邊，須判素髪侮流年。", "波濤不應雙溪水，分野長如二月天。", "浮客若容開荻地，釣翁應免稅苔田。", "前賢未必全堪學，莫讀當時歸去篇。"]'),
('2c3a79cf-cf6a-4bad-842b-6639ac55b7b1','送永嘉王令之任二首 二','方干','唐','唐诗','tang','','[]','雖展縣圖如到縣，五程猶入縉雲東。',64,'全唐诗/poet.tang.36000.json','["雖展縣圖如到縣，五程猶入縉雲東。", "山間閣道盤巖底，海界孤峰在浪中。", "禮法未聞離漢制，土宜多說似吳風。", "字人若用非常術，唯要旬時便立功。"]'),
('55496726-b913-4685-83ea-b40d4ebf677c','鹽官王長官新創瑞隱亭','方干','唐','唐诗','tang','','[]','指畫便分元化力，周迴秀絕自清機。',64,'全唐诗/poet.tang.36000.json','["指畫便分元化力，周迴秀絕自清機。", "孤雲戀石尋常住，落絮縈風特地飛。", "雛鳥啼花催釀酒，驚魚濺水誤沾衣。", "明年秩滿難將去，何似先教畫取歸。"]'),
('f4f2406a-32f3-4efc-8f56-f827db9647d8','李戶曹小妓天得善擊越器以成曲章','方干','唐','唐诗','tang','','[]','越器敲來曲調成，腕頭勻滑自輕清。',64,'全唐诗/poet.tang.36000.json','["越器敲來曲調成，腕頭勻滑自輕清。", "隨風搖曳有餘韻，測水淺深多泛聲。", "晝漏丁當相續滴，寒蟬計會一時鳴。", "若教進上梨園去，衆樂無由更擅名。"]'),
('421ffaee-2a37-4e56-8383-00732b82ad6c','歲晚言事寄鄉中親友','方干','唐','唐诗','tang','','[]','急景蒼茫晝若昏，夜風乾峭觸前軒。',64,'全唐诗/poet.tang.36000.json','["急景蒼茫晝若昏，夜風乾峭觸前軒。", "寒威半入龍蛇窟，暖氣全歸草樹根。", "蠟燼凝來多碧焰，香醪滴處有冰痕。", "尺書未達年應老，先被新春入故園。"]'),
('25656d38-a8f4-4aee-9f34-f7a41824f626','贈孫百篇','方干','唐','唐诗','tang','','[]','御題百首思縱橫，半日功夫舉世名。',64,'全唐诗/poet.tang.36000.json','["御題百首思縱橫，半日功夫舉世名。", "羽冀便從吟處出，珠璣續向筆頭生。", "莫嫌黃綬官資小，必料青雲道路平。", "才子風流復年少，無愁高臥不公卿。"]'),
('c666b67e-ecb4-4aae-a61d-9f8dd0c7558d','贈夏侯評事','方干','唐','唐诗','tang','','[]','傍窺盛德與高節，緬想應無前後人。',64,'全唐诗/poet.tang.36000.json','["傍窺盛德與高節，緬想應無前後人。", "講論參同深到骨，停騰姹女立成銀。", "棊功過却楊玄寶，易義精於梅子真。", "朱紫侯門猶不見，可知岐路有風塵。"]'),
('20383cfb-ddf1-469f-8393-c419d3902a60','送鄭端公','方干','唐','唐诗','tang','','[]','聖主佇知宣室事，豈容才子滯長沙。',64,'全唐诗/poet.tang.36000.json','["聖主佇知宣室事，豈容才子滯長沙。", "隨珠此去方酬德，趙璧當時誤指瑕。", "驄馬將離江浦月，繡衣却照禁中花。", "應憐寂寞滄洲客，煙漢塵泥相去賒。"]'),
('cb399434-92aa-4bf0-9efa-722fd23e559e','題故人廢宅二首 一','方干','唐','唐诗','tang','','[]','舉目淒涼入破門，鮫人一飯尚知恩。',64,'全唐诗/poet.tang.36000.json','["舉目淒涼入破門，鮫人一飯尚知恩。", "閑花舊識猶含笑，怪石無情更不言。", "樵叟和巢伐桃李，牧童兼草踏蘭蓀。", "壺觴笑詠隨風去，唯有聲聲蜀帝魂。"]'),
('46b62c90-24c9-4802-8ef6-2d0f47142173','題故人廢宅二首 二','方干','唐','唐诗','tang','','[]','寒莎野樹入荒庭，風雨蕭蕭不掩扃。',64,'全唐诗/poet.tang.36000.json','["寒莎野樹入荒庭，風雨蕭蕭不掩扃。", "舊徑已知無孟竹，前溪應不浸荀星。", "精靈消散歸寥廓，功業傳留在誌銘。", "薄暮停車更悽愴，山陽隣笛若爲聽。"]'),
('2afba7f8-a83f-4dc4-9330-1c9351374b8c','寄于少監','方干','唐','唐诗','tang','','[]','修持清苦振佳聲，衆鳥那知一鶚情。',64,'全唐诗/poet.tang.36000.json','["修持清苦振佳聲，衆鳥那知一鶚情。", "躡履三千皆後學，摶風九萬即前程。", "名將日月同時朽，身是山河應數生。", "從此雲泥更懸闊，漁翁不合見公卿。"]'),
('00e4e11e-d07b-4571-be1c-b7c0a9bae513','和剡縣陳明府登縣樓','方干','唐','唐诗','tang','','[]','郭裏人家如掌上，簷前樹木映窗櫺。',64,'全唐诗/poet.tang.36000.json','["郭裏人家如掌上，簷前樹木映窗櫺。", "煙霞若接天台地，分野應侵婺女星。", "驛路古今通北闕，仙溪日夜入東溟。", "綵衣才子多吟嘯，公退時時見畫屏。"]'),
('2a642c7c-869a-461d-94a6-89cb68902bfd','項洙處士畫水墨釣臺','方干','唐','唐诗','tang','','[]','畫石畫松無兩般，猶嫌瀑布畫聲難。',64,'全唐诗/poet.tang.36000.json','["畫石畫松無兩般，猶嫌瀑布畫聲難。", "雖云智惠生靈府，要且功夫在筆端。", "潑處便連陰洞黑，添來先向朽枝乾。", "我家曾寄雙臺下，往往開圖盡日看。"]'),
('30bc1cb8-87e0-45f3-b373-b743251ebcb3','贈天台葉尊師','方干','唐','唐诗','tang','','[]','莫見平明離少室，須知薄暮入天台。',64,'全唐诗/poet.tang.36000.json','["莫見平明離少室，須知薄暮入天台。", "常時愛縮山川去，有夜自攜星月來。", "靈藥不知何代得，古松應是長年栽。", "先生暗笑看棊者，半局棊邊白髮催。"]'),
('f338a4ab-eef7-43a3-b0f0-d19df1d980c5','寄台州孫從事百篇','方干','唐','唐诗','tang','','[]','聖世科名酬志業，仙州秀色助神機。',64,'全唐诗/poet.tang.36000.json','["聖世科名酬志業，仙州秀色助神機。", "梅真入仕提雄筆，阮瑀從軍著綵衣。", "晝寢不知山雪積，春遊應趁夜潮歸。", "相思莫訝音書晚，鳥去猶須疊日飛。"]'),
('79ad1634-1d57-4ab5-a78d-608da7ae60c2','送睦州侯郎中赴闕','方干','唐','唐诗','tang','','[]','昔著政聲聞國外，今留儒術化江東。',64,'全唐诗/poet.tang.36000.json','["昔著政聲聞國外，今留儒術化江東。", "青雲舊路歸仙掖，白鳳新詞入聖聰。", "弦管未知銀燭曉，旌旗已侍錦帆風。", "郡人難議酬恩德，徧在三年禮遇中。"]'),
('2509435c-6904-417d-95b2-84d7e5a3c746','朱秀才庭際薔薇','方干','唐','唐诗','tang','','[]','繡難相似畫難真，明媚鮮妍絕比倫。',64,'全唐诗/poet.tang.36000.json','["繡難相似畫難真，明媚鮮妍絕比倫。", "露壓盤條方到地，風吹豔色欲燒春。", "斷霞轉影侵西壁，濃麝分香入四鄰。", "看取後時歸故里，庭花應讓錦衣新。"]'),
('079f6fcf-4c0e-44f2-a54f-1fed25e11546','登龍瑞觀北巖','方干','唐','唐诗','tang','','[]','縱目下看浮世事，方知峭崿與天通。',64,'全唐诗/poet.tang.36000.json','["縱目下看浮世事，方知峭崿與天通。", "湖邊風力歸帆上，嶺頂雲根在雪中。", "促韻寒鐘催落照，斜行白鳥入遙空。", "前人去後後人至，今古異時登眺同。"]'),
('e5a3986e-b53a-46ac-9775-f3bf5049eec5','送婺州許錄事','方干','唐','唐诗','tang','','[]','之官便是還鄉路，白日堂堂著錦衣。',64,'全唐诗/poet.tang.36000.json','["之官便是還鄉路，白日堂堂著錦衣。", "八詠遺風資逸興，二溪寒色助清威。", "曙星沒盡提綱去，暝角吹殘鏁印歸。", "笑我中年更愚僻，醉醒多在釣漁磯。"]'),
('ae9241dd-b994-4008-a225-f22ffe3df174','題龍泉寺絕頂','方干','唐','唐诗','tang','','[]','未明先見海底日，良久遠雞方報晨。',64,'全唐诗/poet.tang.36000.json','["未明先見海底日，良久遠雞方報晨。", "古樹含風長帶雨，寒巖四月始知春。", "中天氣爽星河近，下界時豐雷雨勻。", "前後登臨思無盡，年年改換去來人。"]'),
('43991de9-0528-495f-b247-88cdee06973d','贈上虞胡少府百篇','方干','唐','唐诗','tang','','[]','求仙不在鍊金丹，輕舉由來別有門。',64,'全唐诗/poet.tang.36000.json','["求仙不在鍊金丹，輕舉由來別有門。", "日晷未移三十刻，風騷已及四千言。", "宏才尚遣居卑位，公道何曾雪至冤。", "歛板塵中無恨色，應緣利祿副晨昏。"]'),
('27a31d0e-4cb3-4640-a12b-2af17e442dcb','上鄭員外','方干','唐','唐诗','tang','','[]','爲郡至公兼至察，古今能有幾多人。',64,'全唐诗/poet.tang.36000.json','["爲郡至公兼至察，古今能有幾多人。", "憂民一似清吟苦，守節還如未達貧。", "利刃從前堪切玉，澄潭到底不容塵。", "潛夫豈合干旌斾，甘棹漁舟下釣綸。"]'),
('28aed5ea-acbe-4f21-b6e3-0b625e92e068','桐廬江閣','方干','唐','唐诗','tang','','[]','風煙百變無定態，緬想畫人虛損心。',64,'全唐诗/poet.tang.36000.json','["風煙百變無定態，緬想畫人虛損心。", "卷箔檻前沙鳥散，垂鉤牀下錦鱗沈。", "白雲野寺凌晨磬，紅樹孤村遙夜砧。", "此地四時拋不得，非唯盛暑事開襟。"]'),
('f2af8215-6ac6-436f-8539-fa1a746b98f0','題澄聖塔院上方','方干','唐','唐诗','tang','','[]','地靈直是饒風雨，杉檜老於雲雨間。',64,'全唐诗/poet.tang.36000.json','["地靈直是饒風雨，杉檜老於雲雨間。", "只訝窗中常見海，方知砌下更多山。", "遠泉勢曲猶須引，野果枝低可要攀。", "若把重門諭玄寂，何妨善閉却無關。"]'),
('a9b64065-51f2-4088-a7fc-51d6a9e4c82c','僧院小泉井','方干','唐','唐诗','tang','','[]','亦恐淺深同禹穴，兼云制度象汙罇。',64,'全唐诗/poet.tang.36000.json','["亦恐淺深同禹穴，兼云制度象汙罇。", "窺尋未見泉來路，緬想應穿石裂痕。", "片段似冰猶可把，澄清如鏡不曾昏。", "欲知到底無塵染，堪與吾師比性源。"]'),
('d3ed1da2-fd4b-4ba9-bb69-baa97b3165fb','過姚監故居','方干','唐','唐诗','tang','','[]','不敢要君徵亦起，致君全得似唐虞。',64,'全唐诗/poet.tang.36000.json','["不敢要君徵亦起，致君全得似唐虞。", "讜言昨歎離天聽，新塚今聞入縣圖。", "琴鎖壞窗風自觸，鶴歸喬木月難呼。", "學書弟子何人在，檢點猶逢諫草無。"]'),
('d78bf863-e246-4cf5-a1a9-d463e9d553ca','陪李郎中夜[宴]','方干','唐','唐诗','tang','','[]','間世星郎夜[宴]時，丁丁寒漏滴聲稀。',66,'全唐诗/poet.tang.36000.json','["間世星郎夜[宴]時，丁丁寒漏滴聲稀。", "琵琶弦促千般語，鸚鵡杯深四散飛。", "遍請玉容歌白雪，高燒紅蠟照朱衣。", "人間有此榮華事，爭遣漁翁戀釣磯。"]'),
('97cfa1a4-cd39-4c9d-a9fa-215d20f64d58','狂寇後上劉尚書','方干','唐','唐诗','tang','','[]','孫武傾心與萬夫，削平妖孽在斯須。',64,'全唐诗/poet.tang.36000.json','["孫武傾心與萬夫，削平妖孽在斯須。", "纔施偃月行軍令，便見台星逼座隅。", "獨柱搘天寰海正，雄名蓋世古今無。", "聖君爭不酬功業，仗下高懸破賊圖。"]'),
('14b6191b-91b8-4eb8-ab63-c0b4efdee1c5','尚書新創敵樓二首 一','方干','唐','唐诗','tang','','[]','下馬政成無一事，應須勝地過朝昏。',64,'全唐诗/poet.tang.36000.json','["下馬政成無一事，應須勝地過朝昏。", "笙歌引出桃花洞，羅繡擁來金谷園。", "十里水雲吞半郭，九秋山月入千門。", "常聞大廈堪棲息，燕雀心知不敢言。"]'),
('fda59d83-9203-463a-b642-10059d281859','尚書新創敵樓二首 二','方干','唐','唐诗','tang','','[]','異境永爲歡樂地，歌鐘夜夜復年年。',64,'全唐诗/poet.tang.36000.json','["異境永爲歡樂地，歌鐘夜夜復年年。", "平明旭日生牀底，薄暮殘霞落酒邊。", "雖向檻前窺下界，不知窗裏是中天。", "直須分付丹青手，畫出旌幢遶謫仙。"]'),
('9358d8d8-b26e-420b-974a-b10553983866','贈李郢端公','方干','唐','唐诗','tang','','[]','非唯孤峭與世絕，吟處斯須能變通。',64,'全唐诗/poet.tang.36000.json','["非唯孤峭與世絕，吟處斯須能變通。", "物外搜羅歸大雅，毫端剪削有餘功。", "山川正氣侵靈府，雪月清輝引思風。", "別得人間上昇術，丹霄路在五言中。"]'),
('e81a2e4c-3f09-41da-b6ab-7c9983984962','送孫百篇遊天台','方干','唐','唐诗','tang','','[]','東南雲路落斜行，入樹穿村見赤城。',64,'全唐诗/poet.tang.36000.json','["東南雲路落斜行，入樹穿村見赤城。", "遠近常時皆藥氣，高低無處不泉聲。", "映巖日向牀頭沒，濕燭雲從柱底生。", "更有仙花與靈鳥，恐君多半未知名。"]'),
('57cfd391-5a1e-4f1d-94c3-71ebbda5b2fd','陸山人畫水','方干','唐','唐诗','tang','','[]','毫末用功成一水，水源山脉固難尋。',64,'全唐诗/poet.tang.36000.json','["毫末用功成一水，水源山脉固難尋。", "逡巡便可見波浪，咫尺不能知淺深。", "但有片雲生海口，終無明月在潭心。", "我來擬學磻溪叟，白首釣璜非陸沈。"]'),
('0a121fdb-d28e-4d93-9aac-1667466c2aea','郭中山居','方干','唐','唐诗','tang','','[]','莫見一瓢離樹上，猶須四壁在林間。',64,'全唐诗/poet.tang.36000.json','["莫見一瓢離樹上，猶須四壁在林間。", "沈吟不寐先聞角，屈曲登高自有山。", "濺石迸泉聽未足，亞窗紅果臥堪攀。", "公卿若便遺名姓，却與禽魚作往還。"]'),
('22771bdf-fd40-465e-8f76-5addfa25ba95','雪中寄李知誨判官','方干','唐','唐诗','tang','','[]','聚散聯翩急復遲，解將華髪兩相欺。',64,'全唐诗/poet.tang.36000.json','["聚散聯翩急復遲，解將華髪兩相欺。", "雖云竹重先藏路，却訝巢傾不損枝。", "入戶便從風起後，照窗翻似月明時。", "此時門巷無行跡，塵滿尊罍誰得知。"]'),
('5d9ec426-8ef2-438a-bde2-72fa9fdbb615','途中言事寄居遠上人','方干','唐','唐诗','tang','','[]','舉目時時似故園，鄉心自動向誰言。',64,'全唐诗/poet.tang.36000.json','["舉目時時似故園，鄉心自動向誰言。", "白雲曉濕寒山寺，紅葉夜飛明月村。", "震澤風帆歸橘岸，錢塘水府抵城根。", "羨師了達無牽束，竹徑生苔掩竹門。"]'),
('cfa7f9e0-9a85-4346-b652-907c8b520ee0','雪中寄薛郎中','方干','唐','唐诗','tang','','[]','野禽未覺巢枝仄，稚子先憂徑竹摧。',64,'全唐诗/poet.tang.36000.json','["野禽未覺巢枝仄，稚子先憂徑竹摧。", "半夜忽明非月午，前庭旋釋被春摧。", "碎花若入樽中去，清氣應歸筆底來。", "深擁紅爐聽仙樂，忍教愁坐畫寒灰。"]'),
('b31b6c47-50de-4e78-ae7d-8320d89688b9','題盛令新亭','方干','唐','唐诗','tang','','[]','舉目豈知新智慧，存思便是小天台。',64,'全唐诗/poet.tang.36000.json','["舉目豈知新智慧，存思便是小天台。", "偶嘗嘉果求枝去，因問名花寄種來。", "春物誘才歸健筆，夜歌牽醉入叢杯。", "此中難遇逍遙事，計日應爲印綬催。"]'),
('1a50192e-1ba5-42dd-81e4-b2c1dd53464f','贈鄭仁規','方干','唐','唐诗','tang','','[]','一石雄才獨占難，應分二斗借人寰。',64,'全唐诗/poet.tang.36000.json','["一石雄才獨占難，應分二斗借人寰。", "澄心不出風騷外，落筆全歸教化間。", "蓮幕未來須更聘，桂枝纔去即先攀。", "可憐麗句能飛動，荀宋精靈亦厚顏。"]'),
('c409a740-82cd-4ef4-90c5-c67a1e8eafae','送縉陵王少府赴舉','方干','唐','唐诗','tang','','[]','相看不忍盡離觴，五兩牽風速去檣。',64,'全唐诗/poet.tang.36000.json','["相看不忍盡離觴，五兩牽風速去檣。", "遠驛新砧應弄月，初程殘角未吹霜。", "越山直下分吳苑，淮水橫流入楚鄉。", "珍重郄家好兄弟，明年祿位在何方。"]'),
('8c91ff71-32c5-4a44-ad8b-854196ce3eee','路入剡中作','方干','唐','唐诗','tang','','[]','截灣衝瀨片帆通，高枕微吟到剡中。',64,'全唐诗/poet.tang.36000.json','["截灣衝瀨片帆通，高枕微吟到剡中。", "掠草並飛憐燕子，停橈獨飲學漁翁。", "波濤漫撼長潭月，楊柳斜牽一岸風。", "便擬乘槎應去得，仙源直恐接星東。"]'),
('52c21623-9b05-4e06-8935-c7a398165efb','東山瀑布','方干','唐','唐诗','tang','','[]','遙夜看來疑月照，平明失去被雲迷。',64,'全唐诗/poet.tang.36000.json','["遙夜看來疑月照，平明失去被雲迷。", "掛巖遠勢穿松島，擊石殘聲注稻畦。", "素色噴成三伏雪，餘波流作萬年溪。", "不緣真宰能開決，應向前山雜淤泥。"]'),
('25bb5111-e17f-4d19-b261-56f76b78714e','水墨松石','方干','唐','唐诗','tang','','[]','三世精能舉世無，筆端狼籍見功夫。',64,'全唐诗/poet.tang.36000.json','["三世精能舉世無，筆端狼籍見功夫。", "添來勢逸陰崖黑，潑處痕輕灌木枯。", "垂地寒雲吞大漠，過江春雨入全吳。", "蘭堂坐久心彌惑，不道山川是畫圖。"]'),
('6781e418-606e-4b83-8d29-211ccc36fc9d','獻浙東王大夫二首 一','方干','唐','唐诗','tang','','[]','出鎮當時移越俗，致君何日不堯年。',64,'全唐诗/poet.tang.36000.json','["出鎮當時移越俗，致君何日不堯年。", "到來唯飲長溪水，歸去應將一箇錢。", "吟處美人擎筆硯，行時飛鳥避旌旃。", "四方皆是分憂寄，獨有東南戴二天。"]'),
('daf469bc-99b3-4c76-b482-3ff3be76eaf5','獻浙東王大夫二首 二','方干','唐','唐诗','tang','','[]','王臣夷夏仰清名，領鎮猶爲失意行。',64,'全唐诗/poet.tang.36000.json','["王臣夷夏仰清名，領鎮猶爲失意行。", "已見玉璜曾上釣，何愁金鼎不和羹。", "譽將星月同時朽，身應山河滿數生。", "泥滓雲霄至懸闊，漁翁不合見公卿。"]'),
('7a8c87d6-dc85-4c20-8cd6-6155a1c5cadb','越州使院竹','方干','唐','唐诗','tang','','[]','莫見凌風飄粉籜，須知礙石作盤根。',64,'全唐诗/poet.tang.36000.json','["莫見凌風飄粉籜，須知礙石作盤根。", "細看枝上蟬吟處，猶是筍時蟲蝕痕。", "月送綠陰斜上砌，露凝寒色濕遮門。", "列仙終日逍遙地，鳥雀潛來不敢喧。"]'),
('f71ae393-d0dc-4627-9ee8-ac96bca1b2be','題贈李校書','方干','唐','唐诗','tang','','[]','名場失手一年年，月桂嘗聞到手邊。',64,'全唐诗/poet.tang.36000.json','["名場失手一年年，月桂嘗聞到手邊。", "誰道高情偏似鶴，自云長嘯不如蟬。", "衆花交豔多成實，深井通潮半雜泉。", "却是偶然行未到，元來有路上寥天。"]'),
('47943bb7-7c60-42ef-bea0-ef8d40d98c88','送王侍郎浙東入朝','方干','唐','唐诗','tang','','[]','自將苦節酬清秩，肯要龐眉一箇錢。',64,'全唐诗/poet.tang.36000.json','["自將苦節酬清秩，肯要龐眉一箇錢。", "恩愛已蘇句踐國，程途却上大羅天。", "魚池菊島還公署，沙鶴松栽入畫船。", "密奏無非經濟術，從容幾刻在爐煙。"]'),
('ac11e601-295a-4b3c-81e9-70baeebccb82','贈黃處士','方干','唐','唐诗','tang','','[]','閉戶先生無是非，竹灣松樹藕苗衣。',64,'全唐诗/poet.tang.36000.json','["閉戶先生無是非，竹灣松樹藕苗衣。", "愁吟密雪思難盡，醉倒殘花扶不歸。", "若出薜蘿迎鶴簡，應拋舴艋別漁磯。", "到頭苦節終何益，空改文星作少微。"]'),
('5b656af9-c728-48b8-861d-8badf693c1c1','獻王大夫二首 一','方干','唐','唐诗','tang','','[]','都緣聲價振皇州，高臥中條不自由。',64,'全唐诗/poet.tang.36000.json','["都緣聲價振皇州，高臥中條不自由。", "早副急徵來鳳沼，常陪內宴醉龍樓。", "鏘金五字能援筆，釣玉三年信直鉤。", "必恐借留終不遂，越人相顧已先愁。"]'),
('fb9f4fa3-6155-408c-9b43-d1e06146bc24','獻王大夫二首 二','方干','唐','唐诗','tang','','[]','功成猶自更行春，塞路旌旗十里塵。',64,'全唐诗/poet.tang.36000.json','["功成猶自更行春，塞路旌旗十里塵。", "只用篇章爲教化，不知夷夏望陶鈞。", "金章照耀浮光動，玉面生獰細步勻。", "歷任聖朝清峻地，至今依是少年身。"]'),
('81e7315e-6bd3-47fe-9476-00949dfe7005','贈五牙山人洗修白','方干','唐','唐诗','tang','','[]','變通唯在片時間，此事全由一粒丹。',64,'全唐诗/poet.tang.36000.json','["變通唯在片時間，此事全由一粒丹。", "若取壽長延至易，如嫌地遠縮何難。", "先生闊別能輕舉，弟子纔來學不飡。", "篋裏生塵是閑藥，外沾猶可救衰殘。"]'),
('d8c32c2f-4e73-4bdb-8006-cfb592495ff3','處州獻盧員外','方干','唐','唐诗','tang','','[]','纔下軺車即歲豐，方知盛德與天通。',64,'全唐诗/poet.tang.36000.json','["纔下軺車即歲豐，方知盛德與天通。", "清聲漸出寰瀛外，喜氣全歸教化中。", "落地遺金終日在，經年滯獄當時空。", "直緣後學無功業，不慮文翁不至公。"]'),
('b2c33488-8414-4cc6-bbad-058da1e31f1a','石門瀑布','方干','唐','唐诗','tang','','[]','奔傾漱石亦噴苔，此是便隨元化來。',64,'全唐诗/poet.tang.36000.json','["奔傾漱石亦噴苔，此是便隨元化來。", "長片掛巖輕似練，遠聲離洞咽於雷。", "氣含松桂千枝潤，勢畫雲霞一道開。", "直是銀河分派落，兼聞碎滴濺天台。"]'),
('135370e8-2d7a-41b6-8305-1ec998217c18','題仙巖瀑布呈陳明府','方干','唐','唐诗','tang','','[]','方知激蹙與噴飛，直恐古今同一時。',64,'全唐诗/poet.tang.36000.json','["方知激蹙與噴飛，直恐古今同一時。", "遠壑流來多石脉，寒空撲碎作凌澌。", "謝公巖上衝雲去，織女星邊落地遲。", "聚向山前更誰測，深沈見底是澄漪。"]'),
('2533784d-65c8-4d14-9d24-41aa4fb5d0ab','贈山陰崔明府','方干','唐','唐诗','tang','','[]','用心何況兩衙間，退食孜孜亦不閑。',64,'全唐诗/poet.tang.36000.json','["用心何況兩衙間，退食孜孜亦不閑。", "壓酒曬書猶檢點，修琴取藥似交關。", "笙歌入夜舟中月，花木知春縣裏山。", "平叔正堪湯餅試，風流不合問年顏。"]'),
('5e83bad8-4fc4-4e9f-9d7b-5be373a9a4f9','山井','方干','唐','唐诗','tang','','[]','灩灩濕光凌竹樹，寥寥清氣襲衣襟。',64,'全唐诗/poet.tang.36000.json','["灩灩濕光凌竹樹，寥寥清氣襲衣襟。", "不知測穴通潮信，却訝輕漣動鏡心。", "夜久即疑星影過，早來猶見石痕深。", "轆轤用智終何益，抱甕遺名亦至今。"]'),
('2b63aee2-eff3-45ff-a1b9-b40464bf0c3c','偶作','方干','唐','唐诗','tang','','[]','直爲篇章非動衆，遂令軒蓋不經過。',64,'全唐诗/poet.tang.36000.json','["直爲篇章非動衆，遂令軒蓋不經過。", "未妨溪上泛漁艇，又爲門前張雀羅。", "夜學事須憑雪照，朝廚爭奈絕煙何。", "若於巖洞求倫類，今古疎愚似我多。"]'),
('d4993e83-70b4-47e9-8541-b25e2d7be8c8','賊退後贈劉將軍','方干','唐','唐诗','tang','','[]','非唯吳起與穰苴，今古推排盡不如。',64,'全唐诗/poet.tang.36000.json','["非唯吳起與穰苴，今古推排盡不如。", "白馬知無髀上肉，黃巾泣向箭頭書。", "二年戰地成桑茗，千里荒榛作比閭。", "功業更多身轉貴，佇看幢節引戎車。"]'),
('14a97b0b-a66b-421a-ab79-6955ebe37729','感時三首 一','方干','唐','唐诗','tang','','[]','不覺年華似箭流，朝看春色暮逢秋。',64,'全唐诗/poet.tang.36000.json','["不覺年華似箭流，朝看春色暮逢秋。", "正嗟新塚垂青草，便見故交梳白頭。", "雖道了然皆是夢，應還達者即無愁。", "破除生死須齊物，誰向穹蒼問事由。"]'),
('d75584fb-20ad-45ff-8bb9-838ff3378ee4','感時三首 二','方干','唐','唐诗','tang','','[]','日烏往返無休息，朝出扶桑暮却迴。',64,'全唐诗/poet.tang.36000.json','["日烏往返無休息，朝出扶桑暮却迴。", "夜雨旋驅殘熱去，江風吹送早寒來。", "纔憐飲處飛花片，又見書邊聚雪堆。", "莫恃少年欺白首，須臾還被老相催。"]'),
('3ee23327-cced-451e-a830-57d6b05074f8','感時三首 三','方干','唐','唐诗','tang','','[]','世途擾擾復憧憧，真恐華夷事亦同。',64,'全唐诗/poet.tang.36000.json','["世途擾擾復憧憧，真恐華夷事亦同。", "歲月自消寒暑內，榮枯盡在是非中。", "今朝猶作青襟子，明日還成白首翁。", "堪笑愚夫足紛競，不知流水去無窮。"]'),
('28fbc11a-a99f-4d75-a8db-fa33eaa8cc7c','牡丹','方干','唐','唐诗','tang','','[]','不逢盛暑不衝寒，種子成叢用法難。',64,'全唐诗/poet.tang.36000.json','["不逢盛暑不衝寒，種子成叢用法難。", "醉眼若爲拋去得，狂心更擬折來看。", "凌霜烈火吹無豔，裛露陰霞曬不乾。", "莫道嬌紅怕風雨，經時猶自未凋殘。"]'),
('42d8f044-8f43-45ea-9e11-0ae1cfbfd29d','贈進士章碣','方干','唐','唐诗','tang','','[]','織錦雖云用舊機，抽梭起樣更新奇。',64,'全唐诗/poet.tang.36000.json','["織錦雖云用舊機，抽梭起樣更新奇。", "何如且破望中葉，未可便攀低處枝。", "藉地落花春半後，打窗斜雪夜深時。", "此時才子吟應苦，吟苦鬼神知不知。"]'),
('6e18cb48-d173-479a-9456-c07e99cccc8a','與桐廬鄭明府','方干','唐','唐诗','tang','','[]','字人心苦達神明，何止重門夜不扃。',64,'全唐诗/poet.tang.36000.json','["字人心苦達神明，何止重門夜不扃。", "莫道耕田全種秫，兼聞退食亦逢星。", "暎林顧兔停琴望，隔水寒猨駐筆聽。", "却恐南山盡無石，南山有石合爲銘。"]'),
('e7e428bf-ccee-4e12-8a28-ddaacfede756','謝王大夫奏表','方干','唐','唐诗','tang','','[]','非唯言下變榮衰，大海可傾山可移。',64,'全唐诗/poet.tang.36000.json','["非唯言下變榮衰，大海可傾山可移。", "如剖夜光歸暗室，似驅春氣入寒枝。", "死灰到底翻騰焰，朽骨隨頭却長肥。", "便殺微躬復何益，生成恩重報無期。"]'),
('837f3760-286c-44d8-b78e-9978ebad20f7','送道人歸舊巖','方干','唐','唐诗','tang','','[]','舊巖終副却歸期，巖下有人應識師。',64,'全唐诗/poet.tang.36000.json','["舊巖終副却歸期，巖下有人應識師。", "目覩嬰孩成老叟，手栽松柏有枯枝。", "前山低校無多地，東海淺於初去時。", "若把古今相比類，姓丁仙鶴亦如斯。"]'),
('a014c5b0-bcea-4487-8d09-07befe112cbf','送錢特卿赴職天台','方干','唐','唐诗','tang','','[]','路入仙溪氣象清，垂鞭樹石罅中行。',64,'全唐诗/poet.tang.36000.json','["路入仙溪氣象清，垂鞭樹石罅中行。", "霧昏不見西陵岸，風急先聞瀑布聲。", "山下縣寮張樂送，海邊津吏棹舟迎。", "詩家弟子無多少，唯只於余別有情。"]'),
('fa7b4e61-d84b-4c84-836f-869cfff353f6','題新竹','方干','唐','唐诗','tang','','[]','青苔斸破植貞堅，細碧竿排鬱眼鮮。',64,'全唐诗/poet.tang.36000.json','["青苔斸破植貞堅，細碧竿排鬱眼鮮。", "小鳳凰聲吹嫩葉，短蛟龍尾褭輕煙。", "節環膩色端勻粉，根拔秋光暗長鞭。", "怪得入門肌骨冷，綴風黏月滿庭前。"]'),
('2c0c764a-86af-48ba-99c1-8732ed9df4d0','哭王大夫','方干','唐','唐诗','tang','','[]','俗人皆嫉謝臨川，果中常情□□□。',64,'全唐诗/poet.tang.36000.json','["俗人皆嫉謝臨川，果中常情□□□。", "爲政舊規方利國，降生直性已歸天。", "峴亭惋咽知無極，渭曲馨香莫計年。", "從此心喪應畢世，忍看墳草讀殘篇。"]'),
('4cd567ae-d63b-4532-b079-d7f6ca0d3cf8','贈乾素上人','方干','唐','唐诗','tang','','[]','苦用貞心傳弟子，即應低眼看公卿。',64,'全唐诗/poet.tang.36000.json','["苦用貞心傳弟子，即應低眼看公卿。", "水中明月無踪跡，風裏浮雲可計程。", "庭際孤松隨鶴立，窗間清磬學蟬鳴。", "料師多刦長如此，豈筭前生與後生。"]'),
('e1df388d-698e-4896-a337-107d0bb06714','題應天寺上方兼呈謙上人','方干','唐','唐诗','tang','','[]','中天坐臥見人寰，峭石垂藤不易攀。',64,'全唐诗/poet.tang.36000.json','["中天坐臥見人寰，峭石垂藤不易攀。", "晴卷風雷歸故壑，夜和猿鳥鎖寒山。", "勢橫綠野蒼茫外，影落平湖瀲灩間。", "師在西巖最高處，路尋之字見禪關。"]'),
('2c431add-bbd2-43f3-83fc-1dd24c527037','題法華寺絕頂禪家壁','方干','唐','唐诗','tang','','[]','蒼翠岧嶤逼窅冥，下方雷雨上方晴。',64,'全唐诗/poet.tang.36000.json','["蒼翠岧嶤逼窅冥，下方雷雨上方晴。", "飛流便向砌邊挂，片月影從窗外行。", "馴鹿不知誰結侶，野禽都是自呼名。", "只應禪者無來去，坐看千山白髮生。"]'),
('63fcdb63-3899-45d8-a774-7db18bd01156','春日','方干','唐','唐诗','tang','','[]','春去春來似有期，日高添睡是歸時。',64,'全唐诗/poet.tang.36000.json','["春去春來似有期，日高添睡是歸時。", "雖將細雨催蘆笋，却用東風染柳絲。", "重霧已應吞海色，輕霜猶自剉花枝。", "此時野客因花醉，醉臥花間應不知。"]'),
('f08bc9e1-6822-4492-8b75-91302a40e3ee','上越州楊嚴中丞','方干','唐','唐诗','tang','','[]','連枝棣萼世無雙，未秉鴻鈞擁大邦。',64,'全唐诗/poet.tang.36000.json','["連枝棣萼世無雙，未秉鴻鈞擁大邦。", "折桂早聞推獨步，分憂暫輟過重江。", "晴尋鳳沼雲中樹，思遶稽山枕上窗。", "試把十年辛苦志，問津求拜碧油幢。"]'),
('29cf0e3c-8138-43a5-9d2a-e42b5591e3c9','月','方干','唐','唐诗','tang','','[]','桂輪秋半出東方，巢鵲驚飛夜未央。',64,'全唐诗/poet.tang.36000.json','["桂輪秋半出東方，巢鵲驚飛夜未央。", "海上風雲搖皓影，空中露氣濕流光。", "斜臨戶牖通宵燭，迴照堦墀到曉霜。", "庾亮恃才高更逸，方聞墨翰已成章。"]'),
('bf019d08-f1c8-4368-8c5e-f924caa36589','早春','方干','唐','唐诗','tang','','[]','運行元化不參差，四極中華共一時。',64,'全唐诗/poet.tang.36000.json','["運行元化不參差，四極中華共一時。", "正氣纔隨灰律變，殘寒便被柳條欺。", "冰融大澤朝陽覺，草綠陳根夜雨知。", "不信風光疾於箭，年來年去變霜髭。"]'),
('f001479c-4b58-402c-a966-d8a6209bc9f6','對花','方干','唐','唐诗','tang','','[]','清曉入花如步障，戀花行步步遲遲。',64,'全唐诗/poet.tang.36000.json','["清曉入花如步障，戀花行步步遲遲。", "含風欲綻中心朵，似火應燒外面枝。", "野客須𢬵終日醉，流鶯自有隔年期。", "使君坐處笙歌合，便是列仙身不知。"]'),
('fde664e8-2d5a-47e4-aa2b-7fd3e07b6780','除夜','方干','唐','唐诗','tang','','[]','玉漏斯須即達晨，四時吹轉任風輪。',64,'全唐诗/poet.tang.36000.json','["玉漏斯須即達晨，四時吹轉任風輪。", "寒燈短燼方燒臘，畫角殘聲已報春。", "明日便爲經歲客，昨朝猶是少年人。", "新正定數隨年減，浮世惟應百遍新。"]'),
('fd31e801-564c-4e56-b29e-29e546344153','題松江驛','方干','唐','唐诗','tang','','[]','便向中流出太陽，兼疑大岸逼浮桑。',64,'全唐诗/poet.tang.36000.json','["便向中流出太陽，兼疑大岸逼浮桑。", "門前白道通丹闕，浪裏青山占幾鄉。", "帆勢落斜依浦溆，鐘聲斷續在滄茫。", "古今悉不知天意，偏把雲霞媚一方。"]'),
('3cdd5f0b-21e1-45fb-b992-6038553b91eb','思桐廬舊居便送鑒上人','方干','唐','唐诗','tang','','[]','莫道東南路不賒，思歸一步是天涯。',64,'全唐诗/poet.tang.36000.json','["莫道東南路不賒，思歸一步是天涯。", "林中夜半雙臺月，洲上春深九里花。", "綠樹遶村含細雨，寒潮背郭卷平沙。", "聞師却到鄉中去，爲我殷勤謝酒家。"]'),
('c55cafae-4be4-43f2-a912-d07559c60add','送僧歸日本','方干','唐','唐诗','tang','','[]','四極雖云共二儀，晦明前後即難知。',64,'全唐诗/poet.tang.36000.json','["四極雖云共二儀，晦明前後即難知。", "西方尚在星辰下，東域已過寅卯時。", "大海浪中分國界，扶桑樹底是天涯。", "滿帆若有歸風便，到岸猶須隔歲期。"]'),
('c7462818-fd04-4963-8a97-10859ebbeefc','寧國寺','方干','唐','唐诗','tang','','[]','深僻孤高無四鄰，白雲明月自相親。',66,'全唐诗/poet.tang.36000.json','["深僻孤高無四鄰，白雲明月自相親。", "海中日出山先曉，世上寒輕谷未春。", "窗逼野溪聞唳鶴，林通村徑見樵人。", "此時惟有雷居士，不厭[籃]輿去住頻。"]'),
('00dca69f-cc9e-4cbe-bcc3-ec039a9728b6','山中寄吳磻十韻','方干','唐','唐诗','tang','','[]','莫問終休否，林中事已成。',120,'全唐诗/poet.tang.36000.json','["莫問終休否，林中事已成。", "盤餐憐火種，歲計付刀耕。", "掬水皆花氣，聽松似雨聲。", "書空翹足臥，避險側身行。", "果傍閑軒落，蒲連濕岸生。", "禪生知見理，妻子笑無名。", "更擬教詩苦，何曾待酒清。", "石溪魚不大，月樹鵲多驚。", "砌下通樵路，窗間見縣城。", "雲山任重疊，難隔故交情。"]'),
('ca4393f5-a5de-45ed-85f7-561572886837','嘉興縣內池閣','方干','唐','唐诗','tang','','[]','指畫應心成，周迴氣象清。',72,'全唐诗/poet.tang.36000.json','["指畫應心成，周迴氣象清。", "牀前沙鳥語，案下錦鱗驚。", "細柳風吹旋，新荷露壓傾。", "微芳緣岸落，迸笋入波生。", "舴艋舟中醉，莓苔徑上行。", "高人莫歸去，此處勝蓬瀛。"]'),
('7900b5e8-5fc0-4896-a1ee-86ec2d0e2721','鏡湖西島言事寄陶校書','方干','唐','唐诗','tang','','[]','樵獵兩三戶，凋疎是近鄰。',72,'全唐诗/poet.tang.36000.json','["樵獵兩三戶，凋疎是近鄰。", "風雷前壑雨，花木後嵒春。", "文字不得力，桑麻難救貧。", "山禽欺稚子，夜犬吠漁人。", "未必聖明代，長將雲水親。", "知音不延薦，何路出泥塵。"]'),
('1c7c0898-c714-43b6-8b60-5731f538bbd6','贈趙崇侍御','方干','唐','唐诗','tang','','[]','貴達合逢明聖日，風流又及少年時。',96,'全唐诗/poet.tang.36000.json','["貴達合逢明聖日，風流又及少年時。", "才因出衆人皆嫉，勢欲摩霄自不知。", "正直早年聞苦節，從容此日見清規。", "却教鸚鵡呼桃葉，便遣嬋娟唱竹枝。", "閑話篇章停燭久，醉迷歌舞出花遲。", "雲鴻別有回翔便，應笑啁啾燕雀卑。"]'),
('c40f8d04-5d8e-4d1e-8176-41c8af345470','敘龍瑞觀勝異寄于尊師','方干','唐','唐诗','tang','','[]','混元融結致功難，山下平湖湖上山。',96,'全唐诗/poet.tang.36000.json','["混元融結致功難，山下平湖湖上山。", "萬傾涵虛寒瀲灩，千尋聳翠秀孱顏。", "芰荷香入琴棊處，雷雨聲離棟牖間。", "但有五雲依鶴嶺，曾無陸路向人寰。", "夜溪漱玉常堪聽，仙樹垂珠可要攀。", "若棄榮名便居此，自然浮濁不相關。"]'),
('98dc34a9-2116-4899-b68b-1ae883ea90df','侯郎中新置西湖','方干','唐','唐诗','tang','','["\u897f\u6e56"]','遠近利民因智力，周迴潤物像心源。',160,'全唐诗/poet.tang.36000.json','["遠近利民因智力，周迴潤物像心源。", "菰蒲縱感生成惠，鱣鮪那占廣大恩。", "瀲灩清輝吞半郭，縈紆別派入遙村。", "砂泉遶石通山脈，岸木黏萍是浪痕。", "已見澄來連鏡底，兼知極處浸雲根。", "波濤不起時方泰，舟檝徐行日易昏。", "煙霧未應藏島嶼，鳧鷖亦解避旌旛。", "雖云桃葉歌還醉，却被荷花笑不言。", "孤鶴必應思鳳詔，凡魚豈合在龍門。", "能將盛事添元化，一夕機謨萬古存。"]'),
('648f33a4-c11c-47f9-a0c1-c78ee40fe788','許員外新陽別業','方干','唐','唐诗','tang','','[]','蘭汀橘島映亭臺，不是經心即手栽。',128,'全唐诗/poet.tang.36000.json','["蘭汀橘島映亭臺，不是經心即手栽。", "滿閣白雲隨雨去，一池寒月逐潮來。", "小松出屋和巢長，新逕通村避笋開。", "柳絮風前欹枕臥，荷花香裏棹舟迴。", "園中認葉封林草，簷下攀枝落野梅。", "莫恣高情求逸思，須防急詔用長材。", "若因螢火終殘卷，便把漁歌送幾杯。", "多謝郢中賢太守，常時談笑許追陪。"]'),
('aaaac947-5d82-401f-8d95-48494cd6fb40','李侍御上虞別業','方干','唐','唐诗','tang','','[]','滿目亭臺嘉木繁，燕蟬吟語不爲喧。',96,'全唐诗/poet.tang.36000.json','["滿目亭臺嘉木繁，燕蟬吟語不爲喧。", "晝潮勢急吞諸島，暑雨聲迴露半村。", "真爲援毫方掩卷，常因按曲便開尊。", "若將明月爲儔侶，應把清風遺子孫。", "繡羽驚弓離果上，紅鱗見餌出蒲根。", "尋君未要先敲竹，且棹漁舟入大門。"]'),
('5ce68366-a582-4fe7-9d07-c350d2a09230','題懸溜巖隱者居','方干','唐','唐诗','tang','','[]','世人如要問生涯，滿架堆牀是五車。',128,'全唐诗/poet.tang.36000.json','["世人如要問生涯，滿架堆牀是五車。", "谷鳥暮蟬聲四散，修篁灌木勢交加。", "蒲葵細織團圓扇，薤葉平鋪合遝花。", "却用水荷苞綠李，兼將寒井浸甘瓜。", "慣緣嶮峭收松粉，常趂芳鮮掇茗芽。", "池上樹陰隨浪動，窗前月影被巢遮。", "坐雲獨酌杯盤濕，穿竹微吟路徑斜。", "見說公卿訪遺逸，逢迎亦是戴烏紗。"]'),
('6f685a00-97a9-4faf-a785-7fab7cb57244','山中言事八韻寄李支使','方干','唐','唐诗','tang','','[]','豈知經史深相悞，兩鬢垂絲百事休。',128,'全唐诗/poet.tang.36000.json','["豈知經史深相悞，兩鬢垂絲百事休。", "受業幾多爲弟子，成名一半作公侯。", "前時射鵠徒拋箭，此日求魚未上鉤。", "竹裏斷雲來枕上，巖邊片月在牀頭。", "過庭急雨和花落，遶舍澄泉帶葉流。", "緬想遠書聆鵲喜，窺尋嘉果覺猿偷。", "舊詩改處空留韻，新醞嘗來不滿篘。", "阮瑀如能問寒餒，風光當日入滄洲。"]'),
('1fa01f08-2686-4fc1-91d8-bcd83e046010','山中言事寄贈蘇判官','方干','唐','唐诗','tang','','[]','寸心似火頻求薦，兩鬢如霜始息機。',96,'全唐诗/poet.tang.36000.json','["寸心似火頻求薦，兩鬢如霜始息機。", "隔岸雞鳴春耨去，鄰家犬吠夜漁歸。", "倚松長嘯成疎拙，拂石欹眠絕是非。", "執爨縱曾炊橡實，紉針曾解補荷衣。", "常憑早月來張燭，亦假清風爲掩扉。", "多是元瑜憐野賤，時迴車馬發光輝。"]'),
('0a643914-95d2-47b9-acfc-6407687869f6','獻王大夫','方干','唐','唐诗','tang','','[]','高情不與俗人知，耻學諸生取桂枝。',128,'全唐诗/poet.tang.36000.json','["高情不與俗人知，耻學諸生取桂枝。", "荀宋五言行世早，巢由三詔出溪遲。", "操心已在精微域，落筆皆成典誥詞。", "一鶚難成燕雀伍，非熊本是帝王師。", "賢臣雖蘊經邦術，明主終無諫獵時。", "莫道百僚憂禮絕，兼聞七郡怕天移。", "直緣材力頭頭贍，專被文星步步隨。", "不信重言通造化，須臾便可變榮衰。"]'),
('159a72c5-31db-4cab-94dd-22f2f7d9cb0d','淺井','方干','唐','唐诗','tang','','[]','夜入明河星似少，曙搖澄碧扇風翻。',32,'全唐诗/poet.tang.36000.json','["夜入明河星似少，曙搖澄碧扇風翻。", "細泉細脈難來到，應覺添瓶耗舊痕。"]'),
('633aee94-6b17-4f5a-a86d-5bdee4a3e2f9','與徐溫話別','方干','唐','唐诗','tang','','[]','去去何時却見君，悠悠煙水似天津。',32,'全唐诗/poet.tang.36000.json','["去去何時却見君，悠悠煙水似天津。", "明年今夜有明月，不是今年看月人。"]'),
